CREATE FUNCTION public.ap_rpvendorsoa(pvendcode character varying DEFAULT ''::character varying, cost1code character varying DEFAULT ''::character varying, cost2code character varying DEFAULT ''::character varying, cost3code character varying DEFAULT ''::character varying, cost4code character varying DEFAULT ''::character varying, fromvend character varying DEFAULT ''::character varying, tovend character varying DEFAULT ''::character varying, vendcat character varying DEFAULT ''::character varying, pfromdate date DEFAULT CURRENT_DATE, ptodate date DEFAULT CURRENT_DATE, transcode character varying DEFAULT ''::character varying, balgthan double precision DEFAULT '-9999999999'::bigint, ballthan double precision DEFAULT 999999999, pengdesc character varying DEFAULT ''::character varying, parbdesc character varying DEFAULT ''::character varying, balnzero boolean DEFAULT false, postflag boolean DEFAULT false, netmovment boolean DEFAULT false, lang boolean DEFAULT false, userid integer DEFAULT 1) RETURNS TABLE(rowno bigint, rowtot numeric, lid integer, vendcode character varying, vendengname character varying, vendarbname character varying, vendcatcode character varying, vendcatengname character varying, vendcatarbname character varying, drobamount numeric, crobamount numeric, obamount numeric, dramount numeric, cramount numeric, amount numeric, drobamountfc numeric, crobamountfc numeric, obamountfc numeric, dramountfc numeric, cramountfc numeric, amountfc numeric, usercode character varying, ttcode character varying, ttengname character varying, ttarbname character varying, arbdesc character varying, engdesc character varying, transdate date, docnumber character varying, tcramount numeric, tcramountfc numeric, tdramount numeric, tdramountfc numeric, curcode character varying, curengname character varying, curarbname character varying, currencyrate numeric, c1code character varying, c2code character varying, c3code character varying, c4code character varying, c1engname character varying, c1arbname character varying, c2engname character varying, c2arbname character varying, c3engname character varying, c3arbname character varying, c4engname character varying, c4arbname character varying, vendortransid integer, vendid integer, vendorjournalid integer, paymentid integer, approveddate date, approvedusercode character varying, approveduserengname character varying, approveduserarbname character varying)
    LANGUAGE plpgsql
    AS $$
Declare VendorID 	Int;
	    UpToDate date ;
	   InCludeUpToDate  int   ;
	
	
	Declare PeriodID int;
	Declare PeriodToDate	date;

Begin

	UpToDate = PFromDate;
	PeriodID=(SELECT * FROM  sy_GetFiscalYearPeriodID( cast(UpToDate as date) ,'gl' ));

	PeriodToDate =(Select   FYp.ToDate  
	from sy_FiscalYears FY
	Inner Join sy_FiscalYearsPeriods FYP On FY.ID = FYP.FiscalYear_ID 
	Inner Join sy_FiscalYearsPeriodsModules FYPM On FYP.ID = FYPM.FiscalYearPeriod_ID 
	Where  FromDate < UpToDate
	And CloseDate is Not  null Order By FromDate Desc limit 1);

	return query

SELECT 
	   ROW_NUMBER() Over(Order by v.TransDate, v.VendorTransID) RowNo  
	   , v.OBAmount + Sum( v.TDrAmount - v.TCrAmount) Over  (Order by v.TransDate, v.VendorTransID) RowTot
    ,* 
FROM(

	Select DisTinCT
	 VendorID
	,vwInfo.VendCode
	,vwInfo.VendEngNAme
	,vwInfo.VendArbName
	,vwInfo.VendCatCode
	,vwInfo.VendCatEngNAme
	,vwInfo.VendCatArbName
	,vwInfo.DrOBAmount,vwInfo.CrOBAmount ,vwInfo.OBAmount
	,vwInfo.DrAmount, vwInfo.CrAmount 
	, vwInfo.Amount
	, vwInfo.DrOBAmountFC, vwInfo.CrOBAmountFC ,vwInfo.OBAmountFC
	, vwInfo.DrAmountFC, vwInfo.CrAmountFC 
	, vwInfo.AmountFC
	, (select username from  users_user U Where U.ID=UserID) as UserCode
	,vwt.TTCode 
	,vwt.TTEngName 
	,vwt.TTArbName 	
	,vwt.ArbDesc  ArbDesc 
	,vwt.EngDesc  EngDesc
	,vwt.TransDate 
	,vwt.DocNumber 
	,vwt.CrAmount		TCrAmount
	,vwt.CrAmountFC		TCrAmountFC
	,vwt.DrAmount 		TDrAmount
	,vwt.DrAmountFC		TDrAmountFC
	,vwt.CurCode 
	,vwt.CurEngName 
	,vwt.CurArbName 
	,vwt.CurrencyRate 
	,vwt.C1Code 
	,vwt.C2Code 
	,vwt.C3Code 
	,vwt.C4Code 
	,vwt.C1EngName 
	,vwt.C1ArbName 
	,vwt.C2EngName 
	,vwt.C2ArbName 
	,vwt.C3EngName 
	,vwt.C3ArbName 
	,vwt.C4EngName 
	,vwt.C4ArbName 

	,vwt.VendorTransID
	,vwt.VendID   
	--,vwt.OperationHeadID 
	,vwt.VendorJour_ID 
	--,vwt.VendorTransID 	 
	,vwt.Payment_ID 
	
	,vwt.ApprovalDate
	,vwt.ApprovedUserCode
	,vwt.ApprovedUserEngName
	,vwt.ApprovedUserArbName

	From 
	(
		Select 
		 L.ID 
		,L.Code VendCode
		,L.EngNAme VendEngNAme
		,L.ArbName VendArbName
		,LC.Code   VendCatCode
		,LC.EngNAme VendCatEngNAme
		,LC.ArbName VendCatArbName
		,Mov.CostCenter1ID Cost1ID
		,Mov.CostCenter2ID Cost2ID
		,Mov.CostCenter3ID Cost3ID
		,Mov.CostCenter4ID Cost4ID

		, SUM(COALESCE(Bal.DrAmount,0)) DrOBAmount, SUM(COALESCE(Bal.CrAmount,0)) CrOBAmount ,SUM(COALESCE(Bal.DrAmount,0) - COALESCE(Bal.CrAmount,0)) OBAmount
		, AVG(COALESCE(Mov.DrAmount,0)) DrAmount, AVG(COALESCE(Mov.CrAmount,0)) CrAmount 
		, SUM(COALESCE(Bal.DrAmount,0) - COALESCE(Bal.CrAmount,0)) + AVG(COALESCE(Mov.DrAmount ,0)- COALESCE(Mov.CrAmount,0)) Amount

		, SUM(COALESCE(Bal.DrAmountFC,0)) DrOBAmountFC, SUM(COALESCE(Bal.CrAmountFC,0)) CrOBAmountFC ,SUM(COALESCE(Bal.DrAmountFC,0) - COALESCE(Bal.CrAmountFC,0)) OBAmountFC
		, AVG(COALESCE(Mov.DrAmountFC,0)) DrAmountFC, AVG(COALESCE(Mov.CrAmountFC,0)) CrAmountFC 
		, SUM(COALESCE(Bal.DrAmountFC,0) - COALESCE(Bal.CrAmountFC,0)) + AVG(COALESCE(Mov.DrAmountFC ,0)- COALESCE(Mov.CrAmountFC,0)) AmountFC

		From
		 ap_Vendors L 
		Left Join 	ap_VendorsCategories LC	On 	LC.ID=L.VendorCategory_ID
		-- Opening Balance Before From Date
		Left Join 
	   (
		Select LCB.Vendor_ID VendorID,COALESCE(CostCenter1_ID,0) CostCenter1ID,COALESCE(CostCenter2_ID,0) CostCenter2ID,COALESCE(CostCenter3_ID,0) CostCenter3ID,COALESCE(CostCenter4_ID,0) CostCenter4ID
		, SUM(COALESCE(LCB.DrAmount,0)) DrAmount , SUM(COALESCE(LCB.CrAmount ,0)) CrAmount 
		,  SUM(COALESCE(LCB.DrAmountFC,0)) DrAmountFC , SUM(COALESCE(LCB.CrAmountFC ,0)) CrAmountFC 
		From ap_VendorCostBalances LCB
		LEFT JOIN gl_CostCenters CC1 ON COALESCE(LCB.CostCenter1_ID,0) = CC1.ID
		LEFT JOIN gl_CostCenters CC2 ON COALESCE(LCB.CostCenter2_ID,0) = CC2.ID
		LEFT JOIN gl_CostCenters CC3 ON COALESCE(LCB.CostCenter3_ID,0) = CC3.ID 
		LEFT JOIN gl_CostCenters CC4 ON COALESCE(LCB.CostCenter4_ID,0) = CC4.ID 		
		Where  
		FiscalYearPeriod = COALESCE(PeriodID,0)
		AND COALESCE(CC1.Code,'') LIKE COALESCE(Cost1Code,'') || '%'
		AND COALESCE(CC2.Code,'') LIKE COALESCE(Cost2Code,'') || '%'
		AND COALESCE(CC3.Code,'') LIKE COALESCE(Cost3Code,'') || '%'
		AND COALESCE(CC4.Code,'') LIKE COALESCE(Cost4Code,'') || '%'
		Group By Vendor_ID,COALESCE(CostCenter1_ID,0),COALESCE(CostCenter2_ID,0),COALESCE(CostCenter3_ID,0),COALESCE(CostCenter4_ID,0)

	   Union All
		Select 
		LT.Vendor_ID VendorID ,COALESCE(CostCenter1_ID,0) CostCenter1ID,COALESCE(CostCenter2_ID,0) CostCenter2ID,COALESCE(CostCenter3_ID,0) CostCenter3ID,COALESCE(CostCenter4_ID,0) CostCenter4ID
		,Sum(COALESCE(Case When LT.Amount   > 0 Then abs(LT.Amount)  Else 0 End,0))
		,Sum(COALESCE(Case When LT.Amount   < 0 Then abs(LT.Amount)  Else 0 End,0))

		,Sum(COALESCE(Case When LT.AmountFC   > 0 Then abs(LT.AmountFC) Else 0 End,0))
		,Sum(COALESCE(Case When LT.AmountFC   < 0 Then abs(LT.AmountFC) Else 0 End,0))
		From ap_VendorsTrans LT
		LEFT JOIN gl_CostCenters CC1 ON COALESCE(LT.CostCenter1_ID,0) = CC1.ID
		LEFT JOIN gl_CostCenters CC2 ON COALESCE(LT.CostCenter2_ID,0) = CC2.ID
		LEFT JOIN gl_CostCenters CC3 ON COALESCE(LT.CostCenter3_ID,0) = CC3.ID 
		LEFT JOIN gl_CostCenters CC4 ON COALESCE(LT.CostCenter4_ID,0) = CC4.ID 
		Where 
		(LT.TransDate > PeriodToDate Or PeriodToDate Is Null)
		And LT.TransDate < UpToDate
		AND COALESCE(CC1.Code,'') LIKE COALESCE(Cost1Code,'') || '%'
		AND COALESCE(CC2.Code,'') LIKE COALESCE(Cost2Code,'') || '%'
		AND COALESCE(CC3.Code,'') LIKE COALESCE(Cost3Code,'') || '%'
		AND COALESCE(CC4.Code,'') LIKE COALESCE(Cost4Code,'') || '%'
		Group By Vendor_ID,COALESCE(CostCenter1_ID,0),COALESCE(CostCenter2_ID,0),COALESCE(CostCenter3_ID,0),COALESCE(CostCenter4_ID,0)
		) Bal ON L.ID = Bal.VendorID

		-- Movement Trans Between Dates
		Left Join
		(
		Select 
		LT.Vendor_ID VendorID ,COALESCE(MAX(CostCenter1_ID),0) CostCenter1ID,COALESCE(MAX(CostCenter2_ID),0) CostCenter2ID,COALESCE(MAX(CostCenter3_ID),0) CostCenter3ID,COALESCE(MAX(CostCenter4_ID),0) CostCenter4ID
		,Sum(COALESCE(Case When LT.Amount   > 0 Then abs(LT.Amount) Else 0 End,0)) As DrAmount 
		,Sum(COALESCE(Case When LT.Amount   < 0 Then abs(LT.Amount) Else 0 End,0)) As CrAmount 

		,Sum(COALESCE(Case When LT.AmountFC   > 0 Then abs(LT.AmountFC) Else 0 End,0)) DrAmountFC 
		,Sum(COALESCE(Case When LT.AmountFC   < 0 Then abs(LT.AmountFC) Else 0 End,0)) CrAmountFC
		From ap_VendorsTrans LT
		LEFT JOIN gl_CostCenters CC1 ON COALESCE(CostCenter1_ID,0) = CC1.ID  
		LEFT JOIN gl_CostCenters CC2 ON COALESCE(CostCenter2_ID,0) = CC2.ID
		LEFT JOIN gl_CostCenters CC3 ON COALESCE(CostCenter3_ID,0) = CC3.ID 
		LEFT JOIN gl_CostCenters CC4 ON COALESCE(CostCenter4_ID,0) = CC4.ID 
		Where 
		LT.TransDate >= PFromDate
		And LT.TransDate <= PToDate
		AND (COALESCE(Cost1Code,'') = '' OR COALESCE(CC1.Code,'') LIKE COALESCE(Cost1Code,'') || '%' )
		AND (COALESCE(CC2.Code,'') LIKE COALESCE(Cost2Code,'') || '%')
		AND COALESCE(CC3.Code,'') LIKE COALESCE(Cost3Code,'') || '%'
		AND COALESCE(CC4.Code,'') LIKE COALESCE(Cost4Code,'') || '%'
		Group By  Vendor_ID--,COALESCE(CostCenter1ID,0),COALESCE(CostCenter2ID,0),COALESCE(CostCenter3ID,0),COALESCE(CostCenter4ID,0)
		)Mov
		On L.ID = Mov.VendorID 
		Where 
			L.Code Like PVendCode || '%'
		And L.Code Between  FromVend || ' ' And ToVend || 'ZZZ'
--		And LC.Code Like VendCat || '%'	
	
		Group By L.ID
				,L.Code
				,L.EngNAme
				,L.ArbName
				,LC.Code   
				,LC.EngNAme 
				,LC.ArbName 
				,Mov.CostCenter1ID,Mov.CostCenter2ID,Mov.CostCenter3ID,Mov.CostCenter4ID
			
		Having 
		(SUM(COALESCE(Bal.DrAmount,0) - COALESCE(Bal.CrAmount,0) + COALESCE(Mov.DrAmount ,0)- COALESCE(Mov.CrAmount,0)) <> (Case 	When  	BalNZero = true 	Then 0 End) 	Or 	BalNZero = false
		Or SUM(COALESCE(Bal.DrAmount,0) - COALESCE(Bal.CrAmount,0)) <>0 )
		
		) vwInfo
		
	  --Details Data For Vendor Trans
		LEFT Join 
		(Select 
			 LT.ID VendorTransID
			,L.ID VendID
			,L.Code 
			,cast(LJ.JournalNumber as varchar(50))  DocNumber
			,Case when LT.ArbDesc = '' then LT.EngDesc  else LT.ArbDesc  end AS ArbDesc 
			,LT.EngDesc 
			,LT.TransDate 
			,LT.Payment_ID 
			,LT.VendorJour_ID 
			--,LT.OperationHeadID 
			
			
			 ,Case When LT.Amount   > 0 Then  abs( LT.Amount - case When NetMovment = true Then   COALESCE(LT.SettleAmount,0) Else 0 End) Else 0 End As DrAmount 
			 ,Case When LT.Amount   < 0 Then  abs( LT.Amount - case When NetMovment = true Then   COALESCE(LT.SettleAmount,0) Else 0 End) Else 0 End As CrAmount 
			

			 ,Case When LT.AmountFC   > 0 Then  abs( LT.AmountFC - case When NetMovment = true Then   COALESCE(SettleAmount,0) Else 0 End) Else 0 End As DrAmountFC 
			 ,Case When LT.AmountFC   < 0 Then  abs( LT.AmountFC - case When NetMovment = true Then   COALESCE(SettleAmount,0) Else 0 End) Else 0 End As CrAmountFC 

			--,COALESCE(Case When LT.Amount   > = 0 Then CONVERT(money, abs(LT.Amount),1) Else 0 End,0) As DrAmount 
			--,COALESCE(Case When LT.Amount   < 0 Then CONVERT(money, abs(LT.Amount),1) Else 0 End,0) As CrAmount 

			--,COALESCE(Case When AmountFC    > = 0 Then CONVERT(money, abs(AmountFC),1) Else 0 End,0) As DrAmountFC 
			--,COALESCE(Case When AmountFC   < 0 Then CONVERT(money, abs(AmountFC),1) Else 0 End,0) As CrAmountFC 

			,Cur.Code	 As CurCode
			,Cur.Name As CurEngName
			,Cur.Name As CurArbName
			,LT.CurrencyRate 
			,C1.ID		C1ID
			,C1.Code	C1Code
			,C1.EngName C1EngName
			,C1.EngName C1ArbName
			
			,C2.ID		C2ID
			,C2.Code	C2Code
			,C2.EngName C2EngName
			,C2.EngName C2ArbName

			,C3.ID		C3ID
			,C3.Code	C3Code
			,C3.EngName C3EngName
			,C3.EngName C3ArbName

			,C4.ID		C4ID
			,C4.Code	C4Code
			,C4.EngName C4EngName
			,C4.EngName C4ArbName
			,TT.Code	TTCode
			,TT.EngName TTEngName
			,TT.ArbName TTArbName 
			
			,cast(LT.ApprovalDate as date) ApprovalDate
			,U.name as ApprovedUserCode
			,U.Name as ApprovedUserEngName
			,U.Name as ApprovedUserArbName
			 
		 From ap_VendorsTrans LT
		 Inner Join gl_TransTypes  TT On TT.ID = LT.TransType_ID 
		 Inner Join ap_Vendors L On L.ID = LT.Vendor_ID
		 Left Join 	ap_VendorsCategories LC	On 	LC.ID=L.VendorCategory_ID
		 LEFT Join crm_Currency Cur On Cur.ID = LT.Currency_ID 
		 Left Join gl_CostCenters C1 On C1.ID = LT.CostCenter1_ID 
		 Left Join gl_CostCenters C2 On C2.ID = LT.CostCenter2_ID 
		 Left Join gl_CostCenters C3 On C3.ID = LT.CostCenter3_ID 
		 Left Join gl_CostCenters C4 On C4.ID = LT.CostCenter4_ID 
		 left join ap_Vendorsjour lj on lj.id = lt.VendorJour_ID
		--left join (select ID,JournalNumber from gl_VendorJour) vt on vt.ID = lj.VendorJournalID
		 Left Join users_user U On U.ID = LT.ApprovalBy_ID 
		 Where 
		 LT.TransDate >= PFromDate
		 And LT.TransDate <= PToDate
		 And COALESCE(LT.EngDesc,'') Like PEngDesc || '%'
		 And COALESCE(LT.ArbDesc,'') Like PArbDesc || '%'
		 And COALESCE(TT.Code,'') Like   TransCode || '%'
		
		)vwT On vwInfo.ID = vwT.VendID  
		AND (COALESCE(Cost1Code,'') = '' OR COALESCE(vwInfo.Cost1ID,0) = COALESCE(vwt.C1ID,0))
		AND (COALESCE(Cost2Code,'') = '' OR COALESCE(vwInfo.Cost2ID,0) = COALESCE(vwt.C2ID,0))
		AND (COALESCE(Cost3Code,'') = '' OR COALESCE(vwInfo.Cost3ID,0) = COALESCE(vwt.C3ID,0))
		AND (COALESCE(Cost4Code,'') = '' OR COALESCE(vwInfo.Cost4ID,0) = COALESCE(vwt.C4ID,0))
		
		Where vwInfo.Amount  >=	BalGThan	
		And vwInfo.Amount  <= BalLThan	
		And ((vwInfo.Amount <> 0 And BalNZero = true ) Or BalNZero = false )	

)V;

End;

$$;


ALTER FUNCTION public.ap_rpvendorsoa(pvendcode character varying, cost1code character varying, cost2code character varying, cost3code character varying, cost4code character varying, fromvend character varying, tovend character varying, vendcat character varying, pfromdate date, ptodate date, transcode character varying, balgthan double precision, ballthan double precision, pengdesc character varying, parbdesc character varying, balnzero boolean, postflag boolean, netmovment boolean, lang boolean, userid integer) OWNER TO postgres;

--
-- Name: ar_collectionapproval(integer, integer); Type: PROCEDURE; Schema: public; Owner: postgres
--

CREATE PROCEDURE public.ar_collectionapproval(collectionid integer DEFAULT 0, loginuserid integer DEFAULT 0)
    LANGUAGE plpgsql
    AS $$
Declare
		statuskeyid	int = 0;
		approvalid int =0;
		varactioncode varchar(20);  ---- (ADD,OUT,CLOSE)
		varactiondate varchar(10);  
		varactiontime varchar(8);  
		
declare myrec record;
Declare 
	varMSGText		varchar(512) = '' ;

begin
	Select COALESCE(Status_ID ,0) as oldStatusID ,statuschangedby_id as oldstatuschangedbyid ,statusdate as oldstatusdate  
		,currency_id,currencyrate, amount ,paymentmethod_id , collector_id
	into myrec  
		From ar_collections Where ID = collectionid ;
		
	Select keyid  from sy_lookup Where id = myrec.oldStatusID into statuskeyid;

	if COALESCE(statuskeyid ,0) > 10002 then
		varMSGText =   'Error Operation Appoved Before';
		SELECT RaiseError(varMSGText);
	else if COALESCE(statuskeyid ,0) < 10002 then
		varMSGText =   'Error Operation Not Submited';
		SELECT RaiseError(varMSGText);

	end if;
	end if;

	
	Select id  from sy_lookup Where keyid = '10003' into approvalid;

	--- Fill collector Drawer 
	varactioncode ='ADD' ;
	varactiondate = cast(current_date as varchar(10));  
	varactiontime = cast(current_time as varchar(8)) ;  

	if myrec.paymentmethod_id in (Select id from sy_paymentsmethods where iscash = false) then
		insert into bnk_banksdocumentsunderprocess (sourcename,sourceid,bankrefno,bankrefdate,isclose,created_date,created_by_id)
		Select 'ar_collections' , collectionid , null , null ,false, now() , loginuserid ;	

	end if;
	

	insert into ar_drawersLog (sourcename, sourcerecid,currency_id,currencyrate,amount,user_id ,salesman_id,paymethod_id
							,actioncode,actiondate,actiontime,created_date,created_by_id)
	Select 'ar_collections' , collectionid , myrec.currency_id,myrec.currencyrate,myrec.amount, loginuserid ,myrec.collector_id,myrec.paymentmethod_id  
							, varactioncode  ,varactiondate,varactiontime,now(), loginuserid;

	insert into sy_StatusLog (tablename, recordid,status_id,statusdate,statuschangedby_id ,created_date)
	Select 'ar_collections' , collectionid , myrec.oldStatusid , myrec.OLDstatusdate,myrec.oldstatuschangedbyid ,now() ;
		

	If statuskeyid In (  10002 ) then
		Update ar_collections Set Status_ID = approvalid , statuschangedby_id = loginuserid ,statusdate = current_date,islocked =true Where ID = collectionid  ;
	End if;

end;
$$;


ALTER PROCEDURE public.ar_collectionapproval(collectionid integer, loginuserid integer) OWNER TO postgres;

--
-- Name: ar_collectioncancel(integer, integer); Type: PROCEDURE; Schema: public; Owner: postgres
--

CREATE PROCEDURE public.ar_collectioncancel(collectionid integer DEFAULT 0, loginuserid integer DEFAULT 0)
    LANGUAGE plpgsql
    AS $$
Declare
		statuskeyid	int = 0;
		rejectid int =0;
		
declare myrec record;
Declare 
	varMSGText		varchar(512) = '' ;

begin
	Select COALESCE(Status_ID ,0) as oldStatusID ,statuschangedby_id as oldstatuschangedbyid ,statusdate as oldstatusdate  
		,currency_id,currencyrate, amount ,paymentmethod_id , collector_id
	into myrec  
		From ar_collections Where ID = collectionid ;
		
	Select keyid  from sy_lookup Where id = myrec.oldStatusID into statuskeyid;

	if COALESCE(statuskeyid ,0) <> 10003 then
		varMSGText =   'Error collection is not Submitted ';
		SELECT RaiseError(varMSGText);
	end if;

	
	Select id  from sy_lookup Where keyid = '10005' into rejectid;

	insert into sy_StatusLog (tablename, recordid,status_id,statusdate,statuschangedby_id ,created_date)
	Select 'ar_collections' , collectionid , myrec.oldStatusid , myrec.OLDstatusdate,myrec.oldstatuschangedbyid ,now() ;
		

	If statuskeyid In (  10003 ) then
		Update ar_collections Set Status_ID = rejectid ,isclose = true , islocked = true , statuschangedby_id = loginuserid ,statusdate = current_date Where ID = collectionid  ;
		update bnk_banksdocumentsunderprocess Set isclose = true where sourcename = 'ar_collections' and sourceid = collectionid ;
	End if;

end;
$$;


ALTER PROCEDURE public.ar_collectioncancel(collectionid integer, loginuserid integer) OWNER TO postgres;

--
-- Name: ar_collectionpost(integer, integer); Type: PROCEDURE; Schema: public; Owner: postgres
--

CREATE PROCEDURE public.ar_collectionpost(collectionid integer DEFAULT 0, loginuserid integer DEFAULT 0)
    LANGUAGE plpgsql
    AS $$
Declare 
		statuskeyid	int = 0;
		Postid int =0;
		varactioncode varchar(20);  ---- (ADD,OUT,CLOSE)
		varactiondate varchar(10);  
		varactiontime varchar(8);  
		
declare transtype record;
declare myrec record;
declare transkindid int;
declare signid int;
declare directionid int;
declare PaymentDate varchar(20);
declare paymentstatusid int;
declare LedgerAccountTypeID int;
declare PaymentID int;
declare AccountLedgerID int;
declare retid	int;
declare FiscalYearPeriodID int;

declare treasuryaccountid int;    ---- (Cashier Ledger Account ID If Payment Cash) OR  (Bank Ledger Account ID If Payment Not Cash ) 
declare EngDesc varchar(100) ='';
declare ArbDesc varchar(100) ='';
declare customerAccountTypeID int;
declare ModuleCode varchar(20) = 'AR';
Declare 
	varMSGText		varchar(512) = '' ;

begin
	Select COALESCE(Status_ID ,0) as oldStatusID ,statuschangedby_id as oldstatuschangedbyid ,statusdate as oldstatusdate  
		,currency_id,currencyrate, amount ,paymentmethod_id , collector_id
	into myrec  
		From ar_collections Where ID = collectionid ;
		
	Select keyid  from sy_lookup Where id = myrec.oldStatusID into statuskeyid;

	if COALESCE(statuskeyid ,0) > 10003 then
		varMSGText =   'Error Collection Appoved Before';
		SELECT RaiseError(varMSGText);
	else if COALESCE(statuskeyid ,0) < 10003 then
		varMSGText =   'Error Collection Not Submited';
		SELECT RaiseError(varMSGText);

	end if;
	end if;

	PaymentDate = TO_CHAR(now(), 'YYYY-MM-DD');

Select id from sy_lookup where keyid =  52 into transkindid ;-- transkind ID  keyname ='TransKind'
Select id from sy_lookup Where keyid = 1002 into signid  ;  ---- positive Sign keyname ='Sign'
Select id from sy_lookup Where keyid = 90005 into directionid ;-- IN keyname ='PaymentDirection'
Select id from sy_lookup Where keyid = 90101  into paymentstatusid;  -- keyname ='PaymentStatus'   -----Initiated Status (After Complete Execution Stored Update to Completed Successfully Status

LedgerAccountTypeID = (Select id from sy_lookup where keyid = 90001 limit 1);
customerAccountTypeID = (Select id from sy_lookup where keyid = 90003 limit 1);

Select tt.id transtypeid, tt.code  transtypecode into transtype
from gl_transtypes tt inner join sy_lookup lu on lu.id = tt.transkind_id
where transkind_id = transkindid and sign_id = signid and paymentdirection_id = directionid limit 1  ;

Select id  from sy_lookup Where keyid = '10004' into Postid;    -----get post staus id 
------===== Insert Payment Head
					
SELECT col.id collectionid
	,amount , col.currency_id, col.currencyrate
	, col.customer_id, paymentmethod_id
	,cc.arledger_id
	,pm.iscash ,pm.ischeck ,pm.iscreditcard , pm.isremittance
	, "number"
	
	, chequenumber, chequebankname,   duedate ,bankchequedestination_id
	, beneficiaryname, remittanceno, fromaccountno, frombankname
	, remittancedate, creditcardnumber, cvnumber, expiredate, bankrefno
	, bankrefdate, isclose, remarks, bankdestination_id, bankdocunderprocess_id
	, collector_id, costcenter1_id, costcenter2_id, costcenter3_id, costcenter4_id
	, creditcardtype_id
	,col.status_id oldStatusid
	,col.statusdate oldStatusdate
	,col.statuschangedby_id oldstatuschangedbyid

	into myrec	
	from			
	ar_collections col
	inner join ar_customers c on c.id = customer_id
	inner join ar_customersclasses cc on cc.id = C.customerclass_id
	inner join sy_paymentsmethods pm on pm.id = col.paymentmethod_id
	where col.id = collectionid
	limit 1 
	;

	RAISE NOTICE '[%]', myrec.iscash;

	----- get ledger Account ID
	if myrec.iscash =  True then
		Select ledger_id from ar_salesmans s
		inner join gl_treasuries t on t.id = s.treasurylink_id
		inner Join gl_treasuriesaccounts ta on ta.treasury_id = t.id
		where s.user_id = loginuserid and ((isbank = false and myrec.iscash = true) ) into treasuryaccountid ;
	
	else if myrec.ischeck =  True or  myrec.isremittance =  True  then
		if coalesce(myrec.bankrefno ,'') = '' or myrec.bankrefdate is null   then
			RAISE NOTICE '[%]','You have to check payment in your bank Then insert Bank reference and bank Date' ;	
			SELECT RaiseError(varMSGText);

		end if;

		if myrec.isremittance =  true then
			Select l.id 
			from bnk_banks b
			inner join gl_ledger l on b.bankledger_id = l.id
			inner join 
				(Select ledger_id from ar_salesmans s
					inner join gl_treasuries t on t.id = s.treasurylink_id
					inner Join gl_treasuriesaccounts ta on ta.treasury_id = t.id
					where s.user_id = loginuserid and isbank = true and myrec.iscash = false ) Treled on l.id = Treled.ledger_id
			where b.id = myrec.bankdestination_id into treasuryaccountid ;
		else
			Select l.id 
			from bnk_banks b
			inner join gl_ledger l on b.bankledger_id = l.id
			inner join 
				(Select ledger_id from ar_salesmans s
					inner join gl_treasuries t on t.id = s.treasurylink_id
					inner Join gl_treasuriesaccounts ta on ta.treasury_id = t.id
					where s.user_id = loginuserid and isbank = true and myrec.iscash = false ) Treled on l.id = Treled.ledger_id
			where b.id = myrec.bankchequedestination_id into treasuryaccountid ;
		
		end if ;
	end if ;
	end if ;
	RAISE NOTICE '[%]', treasuryaccountid;

	if coalesce(myrec.arledger_id,0)= 0 then
		RAISE NOTICE '[%]','Please check Ledger Account Receivable In Customer Classes (Channels)' ;	
		SELECT RaiseError(varMSGText);

	end if;

	if coalesce(treasuryaccountid,0) = 0  then
		RAISE NOTICE '[%]','Check Treasury Ledger Permission' ;	
		SELECT RaiseError(varMSGText);
	end if;

	--if coalesce(bankchhqledgerid,0) = 0 and myrec.iscash =  false then
	--	RAISE NOTICE '[%]','Check Treasury Ledger Or Check Bank Ledger Or Treasry Have no Permission' ;	
	--end if;

	FiscalYearPeriodID=(SELECT * FROM  sy_GetFiscalYearPeriodID( cast(PaymentDate as date) ,ModuleCode ) limit 1);
	if FiscalYearPeriodID =0 then
		RAISE NOTICE '[%]','Fiscal Period Not valid Check Payment Date =' || cast(PaymentDate as date) || ' - FYP = ' || FiscalYearPeriodID || ' - Module =' || ModuleCode;	
		SELECT RaiseError(varMSGText);
	end if ;

---==============================
------ Start Create Payment 
---==============================

		RAISE NOTICE '[%]', treasuryaccountid;
	if coalesce(treasuryaccountid ,0) <> 0  then

		Insert Into ar_customersPayments 
		(TransType_ID			,Number		,PaymentDate	,Remarks	,customer_ID		
		,CostCenter1_ID		,CostCenter2_ID		,CostCenter3_ID		,CostCenter4_ID		,FiscalYearPeriod ,created_by_ID 
		,TreasuryOrder_ID , collection_id
		,Amount ,Currency_ID ,CurrencyRate ,Status_ID ,PaymentDirection_ID ,paymentmethod_ID ,isposted 

		,chequenumber 
		,chequebankname 
		,duedate 
		,beneficiaryname 

		,remittanceno 
		,fromaccountno 
		,frombankname 
		,remittancedate 
		,bankdestination_id 

		,creditcardtype_id  
		,creditcardnumber 
