---==============================
------ Start Create Ledger Trans
---==============================

		insert into gl_ledgertrans (
			TransType_ID,Ledger_ID,CostCenter1_ID,CostCenter2_ID,CostCenter3_ID,CostCenter4_ID,TransDate,DocNumber
			,customerJour,EngDesc,ArbDesc,Amount,AmountFC
			,Currency_ID,CurrencyRate,DueDate,ApprovalBy_ID,ApprovalDate
			,created_by_id,Remarks,FiscalYearPeriod
		)

		Select 
			TransType_ID,Ledger_ID,CostCenter1_ID,CostCenter2_ID,CostCenter3_ID,CostCenter4_ID,JournalDate,JournalNumber
			,cj.ID,cjl.EngDesc,cjl.ArbDesc,Amount,0 AmountFC
			,cj.Currency_ID,cj.CurrencyRate,null DueDate,null ApprovalBy_ID, null ApprovalDate
			,created_by_id,cj.Remarks,FiscalYearPeriod
		from ar_customersjour cj
		inner join ar_customersjourline cjl On cj.id = cjl.customerjour_id
		where cj.id= retid;

---==============================
------ End Create Ledger Trans
---==============================

---==============================
------ Start Update Status All Related Tables
---==============================

		Update ar_customersPayments Set Status_ID =(Select ID from sy_LookUp Where keyid = 90106  limit 1)  ----- Completed Successfully
		Where ID =   PaymentID;

		

		insert into sy_StatusLog (tablename, recordid,status_id,statusdate,statuschangedby_id ,created_date)
		Select 'ar_collections' , collectionid , myrec.oldStatusid , myrec.OLDstatusdate,myrec.oldstatuschangedbyid ,now() ;

		If statuskeyid In (  10003 ) then    --  "Approved"	"موافق عليه"
			Update ar_collections Set Status_ID = Postid, isclose = true , statuschangedby_id = loginuserid ,statusdate = current_date,islocked =true Where ID = collectionid  ;
		End if;

		update ar_customerspaymentsschedule Set paidamount = abs(coalesce(paidamount,0)) +  colpaidamount 
			,isclose = case when dueamount - (abs(coalesce(paidamount,0)) +  colpaidamount) = 0  then true else false end
		from
		(
		Select abs(cp.paidamount) colpaidamount   , ps.id
		from ar_collectionsduepayments cp
		inner join ar_customerspaymentsschedule ps on ps.id= cp.customerpaymentschedule_id
			Where cp.collection_id = collectionid
		) ps
		where ar_customerspaymentsschedule.id = ps.id;

---==============================
------ Start Update Status All Related Tables
---==============================
	else
		RAISE NOTICE '[%]','Please check Ledger treasuryaccountid' ;	
		
	end if;

end;
$$;


ALTER PROCEDURE public.ar_collectionpost(collectionid integer, loginuserid integer) OWNER TO postgres;

--
-- Name: ar_collectionreject(integer, integer); Type: PROCEDURE; Schema: public; Owner: postgres
--

CREATE PROCEDURE public.ar_collectionreject(collectionid integer DEFAULT 0, loginuserid integer DEFAULT 0)
    LANGUAGE plpgsql
    AS $$
Declare 
		statuskeyid	int = 0;
		rejectid int =0;
		
declare myrec record;
Declare 
	varMSGText		varchar(512) = '' ;

begin
	Select COALESCE(Status_ID ,0) as oldStatusID ,statuschangedby_id as oldstatuschangedbyid ,statusdate as oldstatusdate  
		,currency_id,currencyrate, amount ,paymentmethod_id , collector_id
	into myrec  
		From ar_collections Where ID = collectionid ;
		
	Select keyid  from sy_lookup Where id = myrec.oldStatusID into statuskeyid;

	if COALESCE(statuskeyid ,0) <> 10002 then
		varMSGText =   'Error collection is not Submitted ';
		SELECT RaiseError(varMSGText);
	end if;

	
	Select id  from sy_lookup Where keyid = '10007' into rejectid;

	insert into sy_StatusLog (tablename, recordid,status_id,statusdate,statuschangedby_id ,created_date)
	Select 'ar_collections' , collectionid , myrec.oldStatusid , myrec.OLDstatusdate,myrec.oldstatuschangedbyid ,now() ;
		

	If statuskeyid In (  10002 ) then
		Update ar_collections Set Status_ID = rejectid ,isclose = true , islocked = true , statuschangedby_id = loginuserid ,statusdate = current_date Where ID = collectionid  ;
	End if;

end;
$$;


ALTER PROCEDURE public.ar_collectionreject(collectionid integer, loginuserid integer) OWNER TO postgres;

--
-- Name: ar_collectionsubmit(integer, integer); Type: PROCEDURE; Schema: public; Owner: postgres
--

CREATE PROCEDURE public.ar_collectionsubmit(collectionid integer DEFAULT 0, loginuserid integer DEFAULT 0)
    LANGUAGE plpgsql
    AS $$
Declare 
		statuskeyid	int = 0;
		statussubmitid int =0;
declare myrec record;
Declare 
	varMSGText		varchar(512) = '' ;

begin
	Select COALESCE(Status_ID ,0) as oldStatusID ,statuschangedby_id as oldstatuschangedbyid ,statusdate as oldstatusdate  into myrec  
		From ar_collections Where ID = collectionid ;
		
	Select keyid  from sy_lookup Where id = myrec.oldStatusID into statuskeyid;
	if COALESCE(statuskeyid ,0) > 10001 then
		varMSGText =   'Error Collection Submited Or Approved Before';
		SELECT RaiseError(varMSGText);
	end if;

	
	Select id  from sy_lookup Where keyid = '10002' into statussubmitid;

	insert into sy_StatusLog (tablename, recordid,status_id,statusdate,statuschangedby_id ,created_date)
	Select 'ar_collections' , collectionid , myrec.oldStatusid , myrec.OLDstatusdate,myrec.oldstatuschangedbyid ,now() ;
		

	If statuskeyid In ( 0 , 10001 ) then
		Update ar_collections Set Status_ID = statussubmitid , statuschangedby_id = loginuserid ,statusdate = current_date Where ID = collectionid  ;
	End if;

end;
$$;


ALTER PROCEDURE public.ar_collectionsubmit(collectionid integer, loginuserid integer) OWNER TO postgres;

--
-- Name: ar_dashcollection(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.ar_dashcollection() RETURNS TABLE(t_duemonth text, t_noofinvoice bigint, t_agedays double precision, t_duedays double precision, t_dueamount numeric, t_paidamount numeric, t_pendingamount numeric, t_duecount bigint, t_isclose boolean)
    LANGUAGE plpgsql
    AS $$
declare myrec	record;

	BEGIN

return query 

	Select 
	 EXTRACT(year FROM duedate)  || '-' || EXTRACT(MONTH FROM duedate) duemonth
	 ,COUNT(DISTINCT operation_id)  Noofinvoice 
	,DATE_PART('day', current_date::timestamp - operationdate::timestamp) agedays
	,DATE_PART('day', duedate::timestamp - operationdate::timestamp) duedays
	, sum(dueamount ) dueamount, sum(paidamount) paidamount,  sum(dueamount )- sum( coalesce(paidamount,0))  pendingamount , count(*) duecount ,isclose
	From ar_customerspaymentsschedule cps
	inner join vw_customersInfo custinfo on custinfo.custid = cps.customer_id
	where isclose <> True
	group by  EXTRACT(year FROM duedate)  || '-' || EXTRACT(MONTH FROM duedate) ,isclose
	,DATE_PART('day', current_date::timestamp - operationdate::timestamp)
	,DATE_PART('day', duedate::timestamp - operationdate::timestamp) ;
													  

end;
$$;


ALTER FUNCTION public.ar_dashcollection() OWNER TO postgres;

--
-- Name: ar_rpcustomersoa(character varying, character varying, character varying, character varying, character varying, character varying, character varying, character varying, date, date, character varying, double precision, double precision, character varying, character varying, boolean, boolean, boolean, boolean, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.ar_rpcustomersoa(pcustcode character varying DEFAULT ''::character varying, cost1code character varying DEFAULT ''::character varying, cost2code character varying DEFAULT ''::character varying, cost3code character varying DEFAULT ''::character varying, cost4code character varying DEFAULT ''::character varying, fromcust character varying DEFAULT ''::character varying, tocust character varying DEFAULT ''::character varying, custcat character varying DEFAULT ''::character varying, pfromdate date DEFAULT CURRENT_DATE, ptodate date DEFAULT CURRENT_DATE, transcode character varying DEFAULT ''::character varying, balgthan double precision DEFAULT '-9999999999'::bigint, ballthan double precision DEFAULT 999999999, pengdesc character varying DEFAULT ''::character varying, parbdesc character varying DEFAULT ''::character varying, balnzero boolean DEFAULT false, postflag boolean DEFAULT false, netmovment boolean DEFAULT false, lang boolean DEFAULT false, userid integer DEFAULT 1) RETURNS TABLE(rowno bigint, rowtot numeric, lid integer, custcode character varying, custengname character varying, custarbname character varying, custcatcode character varying, custcatengname character varying, custcatarbname character varying, drobamount numeric, crobamount numeric, obamount numeric, dramount numeric, cramount numeric, amount numeric, drobamountfc numeric, crobamountfc numeric, obamountfc numeric, dramountfc numeric, cramountfc numeric, amountfc numeric, usercode character varying, ttcode character varying, ttengname character varying, ttarbname character varying, arbdesc character varying, engdesc character varying, transdate date, docnumber character varying, tcramount numeric, tcramountfc numeric, tdramount numeric, tdramountfc numeric, curcode character varying, curengname character varying, curarbname character varying, currencyrate numeric, c1code character varying, c2code character varying, c3code character varying, c4code character varying, c1engname character varying, c1arbname character varying, c2engname character varying, c2arbname character varying, c3engname character varying, c3arbname character varying, c4engname character varying, c4arbname character varying, customertransid integer, custid integer, customerjournalid integer, paymentid integer, approveddate date, approvedusercode character varying, approveduserengname character varying, approveduserarbname character varying)
    LANGUAGE plpgsql
    AS $$
Declare CustomerID 	Int;
	    UpToDate date ;
	   InCludeUpToDate  int   ;
	
	
	Declare PeriodID int;
	Declare PeriodToDate	date;

Begin

	UpToDate = PFromDate;
	PeriodID=(SELECT * FROM  sy_GetFiscalYearPeriodID( cast(UpToDate as date) ,'gl' ));

	PeriodToDate =(Select   FYp.ToDate  
	from sy_FiscalYears FY
	Inner Join sy_FiscalYearsPeriods FYP On FY.ID = FYP.FiscalYear_ID 
	Inner Join sy_FiscalYearsPeriodsModules FYPM On FYP.ID = FYPM.FiscalYearPeriod_ID 
	Where  FromDate < UpToDate
	And CloseDate is Not  null Order By FromDate Desc limit 1);

	return query

SELECT 
	   ROW_NUMBER() Over(Order by v.TransDate, v.CustomerTransID) RowNo  
	   , v.OBAmount + Sum( v.TDrAmount - v.TCrAmount) Over  (Order by v.TransDate, v.CustomerTransID) RowTot
    ,* 
FROM(

	Select DisTinCT
	 CustomerID
	,vwInfo.CustCode
	,vwInfo.CustEngNAme
	,vwInfo.CustArbName
	,vwInfo.CustCatCode
	,vwInfo.CustCatEngNAme
	,vwInfo.CustCatArbName
	,vwInfo.DrOBAmount,vwInfo.CrOBAmount ,vwInfo.OBAmount
	,vwInfo.DrAmount, vwInfo.CrAmount 
	, vwInfo.Amount
	, vwInfo.DrOBAmountFC, vwInfo.CrOBAmountFC ,vwInfo.OBAmountFC
	, vwInfo.DrAmountFC, vwInfo.CrAmountFC 
	, vwInfo.AmountFC
	, (select username from  users_user U Where U.ID=UserID) as UserCode
	,vwt.TTCode 
	,vwt.TTEngName 
	,vwt.TTArbName 	
	,vwt.ArbDesc  ArbDesc 
	,vwt.EngDesc  EngDesc
	,vwt.TransDate 
	,vwt.DocNumber 
	,vwt.CrAmount		TCrAmount
	,vwt.CrAmountFC		TCrAmountFC
	,vwt.DrAmount 		TDrAmount
	,vwt.DrAmountFC		TDrAmountFC
	,vwt.CurCode 
	,vwt.CurEngName 
	,vwt.CurArbName 
	,vwt.CurrencyRate 
	,vwt.C1Code 
	,vwt.C2Code 
	,vwt.C3Code 
	,vwt.C4Code 
	,vwt.C1EngName 
	,vwt.C1ArbName 
	,vwt.C2EngName 
	,vwt.C2ArbName 
	,vwt.C3EngName 
	,vwt.C3ArbName 
	,vwt.C4EngName 
	,vwt.C4ArbName 

	,vwt.CustomerTransID
	,vwt.CustID   
	--,vwt.OperationHeadID 
	,vwt.customerJour_ID 
	--,vwt.CustomerTransID 	 
	,vwt.Payment_ID 
	
	,vwt.ApprovalDate
	,vwt.ApprovedUserCode
	,vwt.ApprovedUserEngName
	,vwt.ApprovedUserArbName

	From 
	(
		Select 
		 L.ID 
		,L.Code CustCode
		,L.EngNAme CustEngNAme
		,L.ArbName CustArbName
		,LC.Code   CustCatCode
		,LC.EngNAme CustCatEngNAme
		,LC.ArbName CustCatArbName
		,Mov.CostCenter1ID Cost1ID
		,Mov.CostCenter2ID Cost2ID
		,Mov.CostCenter3ID Cost3ID
		,Mov.CostCenter4ID Cost4ID

		, SUM(COALESCE(Bal.DrAmount,0)) DrOBAmount, SUM(COALESCE(Bal.CrAmount,0)) CrOBAmount ,SUM(COALESCE(Bal.DrAmount,0) - COALESCE(Bal.CrAmount,0)) OBAmount
		, AVG(COALESCE(Mov.DrAmount,0)) DrAmount, AVG(COALESCE(Mov.CrAmount,0)) CrAmount 
		, SUM(COALESCE(Bal.DrAmount,0) - COALESCE(Bal.CrAmount,0)) + AVG(COALESCE(Mov.DrAmount ,0)- COALESCE(Mov.CrAmount,0)) Amount

		, SUM(COALESCE(Bal.DrAmountFC,0)) DrOBAmountFC, SUM(COALESCE(Bal.CrAmountFC,0)) CrOBAmountFC ,SUM(COALESCE(Bal.DrAmountFC,0) - COALESCE(Bal.CrAmountFC,0)) OBAmountFC
		, AVG(COALESCE(Mov.DrAmountFC,0)) DrAmountFC, AVG(COALESCE(Mov.CrAmountFC,0)) CrAmountFC 
		, SUM(COALESCE(Bal.DrAmountFC,0) - COALESCE(Bal.CrAmountFC,0)) + AVG(COALESCE(Mov.DrAmountFC ,0)- COALESCE(Mov.CrAmountFC,0)) AmountFC

		From
		 ar_Customers L 
		Left Join 	ar_CustomersCategories LC	On 	LC.ID=L.CustomerCategory_ID
		-- Opening Balance Before From Date
		Left Join 
	   (
		Select LCB.Customer_ID CustomerID,COALESCE(CostCenter1_ID,0) CostCenter1ID,COALESCE(CostCenter2_ID,0) CostCenter2ID,COALESCE(CostCenter3_ID,0) CostCenter3ID,COALESCE(CostCenter4_ID,0) CostCenter4ID
		, SUM(COALESCE(LCB.DrAmount,0)) DrAmount , SUM(COALESCE(LCB.CrAmount ,0)) CrAmount 
		,  SUM(COALESCE(LCB.DrAmountFC,0)) DrAmountFC , SUM(COALESCE(LCB.CrAmountFC ,0)) CrAmountFC 
		From ar_CustomerCostBalances LCB
		LEFT JOIN gl_CostCenters CC1 ON COALESCE(LCB.CostCenter1_ID,0) = CC1.ID
		LEFT JOIN gl_CostCenters CC2 ON COALESCE(LCB.CostCenter2_ID,0) = CC2.ID
		LEFT JOIN gl_CostCenters CC3 ON COALESCE(LCB.CostCenter3_ID,0) = CC3.ID 
		LEFT JOIN gl_CostCenters CC4 ON COALESCE(LCB.CostCenter4_ID,0) = CC4.ID 		
		Where  
		--FiscalYearPeriod = COALESCE(PeriodID,0)
		--AND 
		
		COALESCE(CC1.Code,'') LIKE COALESCE(Cost1Code,'') || '%'
		AND COALESCE(CC2.Code,'') LIKE COALESCE(Cost2Code,'') || '%'
		AND COALESCE(CC3.Code,'') LIKE COALESCE(Cost3Code,'') || '%'
		AND COALESCE(CC4.Code,'') LIKE COALESCE(Cost4Code,'') || '%'
		Group By Customer_ID,COALESCE(CostCenter1_ID,0),COALESCE(CostCenter2_ID,0),COALESCE(CostCenter3_ID,0),COALESCE(CostCenter4_ID,0)

	   Union All
		Select 
		LT.Customer_ID CustomerID ,COALESCE(CostCenter1_ID,0) CostCenter1ID,COALESCE(CostCenter2_ID,0) CostCenter2ID,COALESCE(CostCenter3_ID,0) CostCenter3ID,COALESCE(CostCenter4_ID,0) CostCenter4ID
		,Sum(COALESCE(Case When LT.Amount   > 0 Then abs(LT.Amount)  Else 0 End,0))
		,Sum(COALESCE(Case When LT.Amount   < 0 Then abs(LT.Amount)  Else 0 End,0))

		,Sum(COALESCE(Case When LT.AmountFC   > 0 Then abs(LT.AmountFC) Else 0 End,0))
		,Sum(COALESCE(Case When LT.AmountFC   < 0 Then abs(LT.AmountFC) Else 0 End,0))
		From ar_CustomersTrans LT
		LEFT JOIN gl_CostCenters CC1 ON COALESCE(LT.CostCenter1_ID,0) = CC1.ID
		LEFT JOIN gl_CostCenters CC2 ON COALESCE(LT.CostCenter2_ID,0) = CC2.ID
		LEFT JOIN gl_CostCenters CC3 ON COALESCE(LT.CostCenter3_ID,0) = CC3.ID 
		LEFT JOIN gl_CostCenters CC4 ON COALESCE(LT.CostCenter4_ID,0) = CC4.ID 
		Where 
		(LT.TransDate > PeriodToDate Or PeriodToDate Is Null)
		And LT.TransDate < UpToDate
		AND COALESCE(CC1.Code,'') LIKE COALESCE(Cost1Code,'') || '%'
		AND COALESCE(CC2.Code,'') LIKE COALESCE(Cost2Code,'') || '%'
		AND COALESCE(CC3.Code,'') LIKE COALESCE(Cost3Code,'') || '%'
		AND COALESCE(CC4.Code,'') LIKE COALESCE(Cost4Code,'') || '%'
		Group By Customer_ID,COALESCE(CostCenter1_ID,0),COALESCE(CostCenter2_ID,0),COALESCE(CostCenter3_ID,0),COALESCE(CostCenter4_ID,0)
		) Bal ON L.ID = Bal.CustomerID

		-- Movement Trans Between Dates
		Left Join
		(
		Select 
		LT.Customer_ID CustomerID ,COALESCE(MAX(CostCenter1_ID),0) CostCenter1ID,COALESCE(MAX(CostCenter2_ID),0) CostCenter2ID,COALESCE(MAX(CostCenter3_ID),0) CostCenter3ID,COALESCE(MAX(CostCenter4_ID),0) CostCenter4ID
		,Sum(COALESCE(Case When LT.Amount   > 0 Then abs(LT.Amount) Else 0 End,0)) As DrAmount 
		,Sum(COALESCE(Case When LT.Amount   < 0 Then abs(LT.Amount) Else 0 End,0)) As CrAmount 

		,Sum(COALESCE(Case When LT.AmountFC   > 0 Then abs(LT.AmountFC) Else 0 End,0)) DrAmountFC 
		,Sum(COALESCE(Case When LT.AmountFC   < 0 Then abs(LT.AmountFC) Else 0 End,0)) CrAmountFC
		From ar_CustomersTrans LT
		LEFT JOIN gl_CostCenters CC1 ON COALESCE(CostCenter1_ID,0) = CC1.ID  
		LEFT JOIN gl_CostCenters CC2 ON COALESCE(CostCenter2_ID,0) = CC2.ID
		LEFT JOIN gl_CostCenters CC3 ON COALESCE(CostCenter3_ID,0) = CC3.ID 
		LEFT JOIN gl_CostCenters CC4 ON COALESCE(CostCenter4_ID,0) = CC4.ID 
		Where 
		LT.TransDate >= PFromDate
		And LT.TransDate <= PToDate
		AND (COALESCE(Cost1Code,'') = '' OR COALESCE(CC1.Code,'') LIKE COALESCE(Cost1Code,'') || '%' )
		AND (COALESCE(CC2.Code,'') LIKE COALESCE(Cost2Code,'') || '%')
		AND COALESCE(CC3.Code,'') LIKE COALESCE(Cost3Code,'') || '%'
		AND COALESCE(CC4.Code,'') LIKE COALESCE(Cost4Code,'') || '%'
		Group By  Customer_ID--,COALESCE(CostCenter1ID,0),COALESCE(CostCenter2ID,0),COALESCE(CostCenter3ID,0),COALESCE(CostCenter4ID,0)
		)Mov
		On L.ID = Mov.CustomerID 
		Where 
			L.Code Like PCustCode || '%'
		And L.Code Between  FromCust || ' ' And ToCust || 'ZZZ'
--		And LC.Code Like CustCat || '%'	
	
		Group By L.ID
				,L.Code
				,L.EngNAme
				,L.ArbName
				,LC.Code   
				,LC.EngNAme 
				,LC.ArbName 
				,Mov.CostCenter1ID,Mov.CostCenter2ID,Mov.CostCenter3ID,Mov.CostCenter4ID
			
		Having 
		(SUM(COALESCE(Bal.DrAmount,0) - COALESCE(Bal.CrAmount,0) + COALESCE(Mov.DrAmount ,0)- COALESCE(Mov.CrAmount,0)) <> (Case 	When  	BalNZero = true 	Then 0 End) 	Or 	BalNZero = false
		Or SUM(COALESCE(Bal.DrAmount,0) - COALESCE(Bal.CrAmount,0)) <>0 )
		
		) vwInfo
		
	  --Details Data For Customer Trans
		LEFT Join 
		(Select 
			 LT.ID CustomerTransID
			,L.ID CustID
			,L.Code 
			,cast(LJ.JournalNumber as varchar(50))  DocNumber
			,Case when LT.ArbDesc = '' then LT.EngDesc  else LT.ArbDesc  end AS ArbDesc 
			,LT.EngDesc 
			,LT.TransDate 
			,LT.Payment_ID 
			,LT.customerJour_ID 
			--,LT.OperationHeadID 
			
			
			 ,Case When LT.Amount   > 0 Then  abs( LT.Amount - case When NetMovment = true Then   COALESCE(LT.SettleAmount,0) Else 0 End) Else 0 End As DrAmount 
			 ,Case When LT.Amount   < 0 Then  abs( LT.Amount - case When NetMovment = true Then   COALESCE(LT.SettleAmount,0) Else 0 End) Else 0 End As CrAmount 
			

			 ,Case When LT.AmountFC   > 0 Then  abs( LT.AmountFC - case When NetMovment = true Then   COALESCE(SettleAmount,0) Else 0 End) Else 0 End As DrAmountFC 
			 ,Case When LT.AmountFC   < 0 Then  abs( LT.AmountFC - case When NetMovment = true Then   COALESCE(SettleAmount,0) Else 0 End) Else 0 End As CrAmountFC 

			--,COALESCE(Case When LT.Amount   > = 0 Then CONVERT(money, abs(LT.Amount),1) Else 0 End,0) As DrAmount 
			--,COALESCE(Case When LT.Amount   < 0 Then CONVERT(money, abs(LT.Amount),1) Else 0 End,0) As CrAmount 

			--,COALESCE(Case When AmountFC    > = 0 Then CONVERT(money, abs(AmountFC),1) Else 0 End,0) As DrAmountFC 
			--,COALESCE(Case When AmountFC   < 0 Then CONVERT(money, abs(AmountFC),1) Else 0 End,0) As CrAmountFC 

			,Cur.Code	 As CurCode
			,Cur.Name As CurEngName
			,Cur.Name As CurArbName
			,LT.CurrencyRate 
			,C1.ID		C1ID
			,C1.Code	C1Code
			,C1.EngName C1EngName
			,C1.EngName C1ArbName
			
			,C2.ID		C2ID
			,C2.Code	C2Code
			,C2.EngName C2EngName
			,C2.EngName C2ArbName

			,C3.ID		C3ID
			,C3.Code	C3Code
			,C3.EngName C3EngName
			,C3.EngName C3ArbName

			,C4.ID		C4ID
			,C4.Code	C4Code
			,C4.EngName C4EngName
			,C4.EngName C4ArbName
			,TT.Code	TTCode
			,TT.EngName TTEngName
			,TT.ArbName TTArbName 
			
			,cast(LT.ApprovalDate as date) ApprovalDate
			,U.name as ApprovedUserCode
			,U.Name as ApprovedUserEngName
			,U.Name as ApprovedUserArbName
			 
		 From ar_CustomersTrans LT
		 Inner Join gl_TransTypes  TT On TT.ID = LT.TransType_ID 
		 Inner Join ar_Customers L On L.ID = LT.Customer_ID
		 Left Join 	ar_CustomersCategories LC	On 	LC.ID=L.CustomerCategory_ID
		 LEFT Join crm_Currency Cur On Cur.ID = LT.Currency_ID 
		 Left Join gl_CostCenters C1 On C1.ID = LT.CostCenter1_ID 
		 Left Join gl_CostCenters C2 On C2.ID = LT.CostCenter2_ID 
		 Left Join gl_CostCenters C3 On C3.ID = LT.CostCenter3_ID 
		 Left Join gl_CostCenters C4 On C4.ID = LT.CostCenter4_ID 
		 left join ar_Customersjour lj on lj.id = lt.customerJour_ID
		--left join (select ID,JournalNumber from gl_VendorJour) vt on vt.ID = lj.VendorJournalID
		 Left Join users_user U On U.ID = LT.ApprovalBy_ID 
		 Where 
		 LT.TransDate >= PFromDate
		 And LT.TransDate <= PToDate
		 And COALESCE(LT.EngDesc,'') Like PEngDesc || '%'
		 And COALESCE(LT.ArbDesc,'') Like PArbDesc || '%'
		 And COALESCE(TT.Code,'') Like   TransCode || '%'
		
		)vwT On vwInfo.ID = vwT.CustID  
		AND (COALESCE(Cost1Code,'') = '' OR COALESCE(vwInfo.Cost1ID,0) = COALESCE(vwt.C1ID,0))
		AND (COALESCE(Cost2Code,'') = '' OR COALESCE(vwInfo.Cost2ID,0) = COALESCE(vwt.C2ID,0))
		AND (COALESCE(Cost3Code,'') = '' OR COALESCE(vwInfo.Cost3ID,0) = COALESCE(vwt.C3ID,0))
		AND (COALESCE(Cost4Code,'') = '' OR COALESCE(vwInfo.Cost4ID,0) = COALESCE(vwt.C4ID,0))
		
		Where vwInfo.Amount  >=	BalGThan	
		And vwInfo.Amount  <= BalLThan	
		And ((vwInfo.Amount <> 0 And BalNZero = true ) Or BalNZero = false )	

)V;

End;

$$;


ALTER FUNCTION public.ar_rpcustomersoa(pcustcode character varying, cost1code character varying, cost2code character varying, cost3code character varying, cost4code character varying, fromcust character varying, tocust character varying, custcat character varying, pfromdate date, ptodate date, transcode character varying, balgthan double precision, ballthan double precision, pengdesc character varying, parbdesc character varying, balnzero boolean, postflag boolean, netmovment boolean, lang boolean, userid integer) OWNER TO postgres;

--
-- Name: bnk_banksdocumentsunderprocesspost(integer, integer); Type: PROCEDURE; Schema: public; Owner: postgres
--

CREATE PROCEDURE public.bnk_banksdocumentsunderprocesspost(bankdocid integer DEFAULT 0, loginuserid integer DEFAULT 0)
    LANGUAGE plpgsql
    AS $$
Declare 
		statuskeyid	int = 0;
		approvalid int =0;
		varactioncode varchar(20);  ---- (ADD,OUT,CLOSE)
		varactiondate varchar(10);  
		varactiontime varchar(8);  
		
declare myrec record;
declare reccol record;
Declare 
	varMSGText		varchar(512) = '' ;
declare postid int;
declare rejectid int;

begin
	Select * 
	into myrec  
	From bnk_banksdocumentsunderprocess
	Where ID = bankdocid ;

	if COALESCE(myrec.bankrefno,'') ='' or myrec.bankrefdate is null then
		varMSGText =   'Error Insert Ref. Bank Number And Bank Ref. Date';
		SELECT RaiseError(varMSGText);
	end if;

	Select id  from sy_lookup Where keyid = '10004' into postid;
	Select id  from sy_lookup Where keyid = '10007' into rejectid;

	if myrec.sourcename = 'ar_collections' then
		if exists(Select * from ar_collections Where id = myrec.sourceid) then
			Select  Status_id , statusdate,statuschangedby_id ,lu.keyid statuskeyid  into reccol from ar_collections c 
			inner join sy_lookup lu on lu.id = c.status_id
			Where c.id = myrec.sourceid ;

			If reccol.statuskeyid In (  10003 ) then
				Update ar_collections Set bankrefno = myrec.bankrefno , bankrefdate = myrec.bankrefdate 
					  Where ID = myrec.sourceid  ;
			End if;

			call  public.ar_CollectionPost (myrec.sourceid ,loginuserid ) ;

			
			If reccol.statuskeyid In (  10003 ) then
				Update ar_collections Set  Status_ID = postid , statuschangedby_id = loginuserid ,statusdate = current_date ,isclose = true  
					Where ID = myrec.sourceid  ;
			End if;

			update bnk_banksdocumentsunderprocess Set isclose = true
			Where ID = bankdocid ;

			insert into sy_StatusLog (tablename, recordid,status_id,statusdate,statuschangedby_id ,created_date)
			Select 'ar_collections' ,  myrec.sourceid , reccol.Status_id , reccol.statusdate,reccol.statuschangedby_id ,now() ;
		

		else
			varMSGText =   'Error The Source Record ID not Avalaiable ';
			SELECT RaiseError(varMSGText);
		end if ;
	else
		varMSGText =   'Error The Source Name not Avalaiable ';
		SELECT RaiseError(varMSGText);
	

	end if;

end;
$$;


ALTER PROCEDURE public.bnk_banksdocumentsunderprocesspost(bankdocid integer, loginuserid integer) OWNER TO postgres;

--
-- Name: getaccountbalance(integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.getaccountbalance(accounttypeid integer, accountid integer) RETURNS TABLE(t_balance numeric)
    LANGUAGE plpgsql
    AS $$
declare acctypekeyid int;
Begin
	
	acctypekeyid = (select keyid from sy_lookup Where id = accounttypeid limit 1 ) ;
	raise notice '%', acctypekeyid;
	
	if acctypekeyid = 90001 then
		CREATE TEMP TABLE temp_Accountbalance AS
		Select Sum(bal) balance from
		(
		Select sum(dramount - cramount) bal from gl_ledgercostbalances 
			where ledger_id = accountid
		union all
		Select sum(amount) balance 
			from gl_ledgerTrans  Where ledger_id = accountid
		)aa ;

	elseif  acctypekeyid = 90002 then
		CREATE TEMP TABLE temp_Accountbalance AS
		Select Sum(bal) balance from
		(
		Select sum(dramount - cramount) bal from ap_vendorcostbalances 
			where vendor_id = accountid
		union all
		Select sum(amount) balance 
			from ap_vendorstrans  Where vendor_id = accountid
		)aa ;

	elseif  acctypekeyid = 90003 then
		CREATE TEMP TABLE temp_Accountbalance AS
		Select Sum(bal) balance from
		(
		Select sum(dramount - cramount) bal from ar_customercostbalances 
			where customer_id = accountid
		union all
		Select sum(amount) balance 
			from ar_customerstrans  Where customer_id = accountid
		)aa ;
	
	end if ;

	return query
	Select balance from temp_Accountbalance ;
	

	drop table temp_Accountbalance;

end;
$$;


ALTER FUNCTION public.getaccountbalance(accounttypeid integer, accountid integer) OWNER TO postgres;

--
-- Name: gl_postpayment(integer, integer, integer); Type: PROCEDURE; Schema: public; Owner: postgres
--

CREATE PROCEDURE public.gl_postpayment(accounttype integer DEFAULT 0, paymentid integer DEFAULT 0, loginuserid integer DEFAULT 0)
    LANGUAGE plpgsql
    AS $$
Declare myrec Record;
Declare JourStatusID int;
declare retid int;
declare FiscalYearPeriodID int;
declare ModuleCode varchar(20);
begin
		
	IF AccountType = 90001 then
		 ModuleCode = 'GL';
	elseIF AccountType = 90002 then
		 ModuleCode = 'AP';
	elseIF AccountType = 90003 then
		 ModuleCode = 'AR';
	end if;
	
	JourStatusID = (Select ID From sy_lookup Where keyid = 10004 limit 1) ; -- Record Status Id Posted
------Ledger
		
		IF AccountType = 90001 then

			Select lp.* ,pm.iscash,pm.ischeck , pm.iscredit,pm.iscreditcard , TO_CHAR(PaymentDate, 'YYYY-MM-DD') paydate into myrec
			from  gl_Ledgerpayments	lp
			inner join sy_paymentsmethods pm on lp.paymentmethod_id = pm.id
			Inner Join sy_lookup lu on lu.keyid = 90101    --- initiated
			Where lp.id= PaymentID;
			
			FiscalYearPeriodID=(SELECT * FROM  sy_GetFiscalYearPeriodID( cast(myrec.paydate as date) ,ModuleCode ) limit 1);
			if FiscalYearPeriodID =0 then
				RAISE NOTICE '[%]','Fiscal Period Not valid Check Payment Date =' || PaymentDate || ' - FYP = ' || FiscalYearPeriodID || ' - Module =' || ModuleCode;	
			end if ;
			
			if myrec.iscash =  True then
					
					Insert Into gl_ledgerJour  (  
						TransType_ID,JournalNumber,JournalDate,FiscalYearPeriod
						,Reference,ConfirmDate                 ,PostDate     ,created_by_id 
						,Remarks,IsLocked,PaymentID,Status_ID 
						,TotalAmount,Currency_ID,CurrencyRate
						)
				
					Select TransType_ID,Number ,PaymentDate ,FiscalYearPeriod 
						, Cast(TreasuryOrder_ID As varchar(20))  Reference , Null  ConfirmDate ,current_date PostDate ,LoginUserid
						,Remarks, True IsLocked ,  ID PaymentID  ,JourStatusID 
						,Amount,Currency_ID,CurrencyRate
					from gl_LedgerPayments 
					Where ID = PaymentID 
					And Status_ID = (Select id From sy_lookup where  keyid= 90101 limit 1 )  returning id into retid; -----  Initiated Status Only

			raise notice '[%]' , retid;

					Insert into gl_LedgerJourLine (
						ledgerjour_ID,Rank,ledger_ID,CostCenter1_ID,CostCenter2_ID,CostCenter3_ID,CostCenter4_ID,EngDesc,ArbDesc
						,DebitAmount ,CreditAmount  ,Amount,Qty,Currency_ID,CurrencyRate,reverse,Remarks
						
						) 
			
					Select 
						retid  ,Rank,LP.ledger_id , LPL.CostCenter1_ID,LPL.CostCenter2_ID,LPL.CostCenter3_ID,LPL.CostCenter4_ID ,COALESCE(EngDesc,' '),ArbDesc
						,Case When LPL.Amount > 0 then LPL.Amount Else 0 End,Case When LPL.Amount < 0 then LPL.Amount Else 0 End ,LPL.Amount, 0 Qty 
						,LP.Currency_ID,lp.CurrencyRate ,1 Reverse ,LP.Remarks   
				
						From  gl_LedgerPayments LP
						Inner join gl_LedgerPaymentsLine LPL On LP.ID = LPL.ledgerPayment_ID 
						Where LP.ID = PaymentID 
					    And Status_ID = (Select id From sy_lookup where  keyid= 90101 limit 1 );  -----  Processing Status Only
			 

				

					 Insert Into gl_LedgerTrans (
						TransType_ID,Ledger_ID,CostCenter1_ID,CostCenter2_ID,CostCenter3_ID,CostCenter4_ID,TransDate,DocNumber
						,Payment_ID,LedgerJour_ID,EngDesc,ArbDesc,Amount,AmountFC
						,Currency_ID,CurrencyRate,DueDate,ApprovalBy_ID,ApprovalDate
						,created_by_id,Remarks,FiscalYearPeriod
						
						)

					Select 
						 LP.TransType_ID ,LPL.ledger_ID  ,LPL.CostCenter1_ID,LPL.CostCenter2_ID,LPL.CostCenter3_ID,LPL.CostCenter4_ID , LP.PaymentDate ,LP.Number 
						 ,PaymentID,retid ,COALESCE(EngDesc,' ')  , ArbDesc ,lpl.Amount,lpl.AmountFC 
						 ,lp.Currency_ID,lp.CurrencyRate ,Null DueDate , LoginUserid  ApprovedBy_ID , current_date  ApprovedDate
						 ,LoginUserid ,lp.Remarks  ,FiscalYearPeriod
						From  gl_LedgerPayments LP
						Inner join gl_LedgerPaymentsLine LPL On LP.ID = LPL.LedgerPayment_ID 
						Where LP.ID = PaymentID 
						And Status_ID = (Select id From sy_lookup where  keyid= 90101 limit 1 ) ; -----  Processing Status Only

					Update gl_ledgerPayments Set Status_ID =(Select ID from sy_LookUp Where keyid = 90105 limit 1 )  ----- Completed Successfully
					Where ID =   PaymentID;

					Update gl_TreasuriesOrders  Set RefPaymentID  = PaymentID ,IsFinish = True , FinishDate = current_Date
					Where  ID =    (Select TreasuryOrder_ID from gl_ledgerPayments  Where ID = PaymentID limit 1 );
					 
					 
					--=====  Update Cheque Status to 
			elseif myrec.ischeck =  True  then
					--------90507	ChequesStatus	3	Delivered	تم التسليم
					
--					Update bnk_BanksCheques Set ChequeStatus = 90507 Where id = @IsSelectedChq
--					Update BNK_ChequesTrans  Set ChequeStatus  = 90507 Where id = @IsSelectedChq

			elseif myrec.iscredit =  True  then
			elseif myrec.iscreditcard =  True  then
			end if;
			
		
		----- Vendor
		elseIF AccountType = 90002 then
		
		------- Customer
		elseif AccountType = 90003 then

			Select lp.* ,pm.iscash,pm.ischeck , pm.iscredit,pm.iscreditcard , TO_CHAR(PaymentDate, 'YYYY-MM-DD') paydate into myrec
			from  ar_customerspayments	lp
			inner join sy_paymentsmethods pm on lp.paymentmethod_id = pm.id
			Inner Join sy_lookup lu on lu.keyid = 90101    --- initiated
			Where lp.id= PaymentID;
			
			FiscalYearPeriodID=(SELECT * FROM  sy_GetFiscalYearPeriodID( cast(myrec.paydate as date) ,ModuleCode ) limit 1);
			if FiscalYearPeriodID =0 then
				RAISE NOTICE '[%]','Fiscal Period Not valid Check Payment Date =' || PaymentDate || ' - FYP = ' || FiscalYearPeriodID || ' - Module =' || ModuleCode;	
			end if ;
			
			if myrec.iscash =  True then
					
					Insert Into ar_customersJour  (  
						TransType_ID,JournalNumber,JournalDate,FiscalYearPeriod
						,Reference,ConfirmDate                 ,PostDate     ,created_by_id 
						,Remarks,IsLocked,PaymentID,Status_ID 
						,TotalAmount,Currency_ID,CurrencyRate
						)
				
					Select TransType_ID,Number ,PaymentDate ,FiscalYearPeriod 
						, Cast(TreasuryOrder_ID As varchar(20))  Reference , Null  ConfirmDate ,current_date PostDate ,LoginUserid
						,Remarks, True IsLocked ,  ID PaymentID  ,JourStatusID 
						,Amount,Currency_ID,CurrencyRate
					from ar_customersPayments 
					Where ID = PaymentID 
					And Status_ID = (Select id From sy_lookup where  keyid= 90101  limit 1  )  returning id into retid; -----  Initiated Status Only

			raise notice '[%]' , retid;
			

					Insert into ar_customersJourLine (
						customerjour_ID
						,Rank,accounttype_id,ledger_ID,customer_id,CostCenter1_ID,CostCenter2_ID,CostCenter3_ID,CostCenter4_ID,EngDesc,ArbDesc
						,DebitAmount ,CreditAmount  ,Amount,Qty,Currency_ID,CurrencyRate,reverse,Remarks
						
						) 
			
					Select 
						retid  ,Rank,LPL.accounttype_id,LPL.ledger_id , LPL.customer_id ,LPL.CostCenter1_ID,LPL.CostCenter2_ID,LPL.CostCenter3_ID,LPL.CostCenter4_ID ,COALESCE(EngDesc,' '),ArbDesc
						,Case When LPL.Amount > 0 then LPL.Amount Else 0 End,Case When LPL.Amount < 0 then LPL.Amount Else 0 End ,LPL.Amount, 0 Qty 
						,LP.Currency_ID,lp.CurrencyRate ,1 Reverse ,LP.Remarks   
				
						From  ar_customersPayments LP
						Inner join ar_customersPaymentsLine LPL On LP.ID = LPL.customerPayment_ID 
						Where LP.ID = PaymentID 
					    And Status_ID = (Select id From sy_lookup where  keyid= 90101 limit 1 ) ;  -----  Processing Status Only
			 

				

					 Insert Into ar_customersTrans (
						TransType_ID,customer_ID,CostCenter1_ID,CostCenter2_ID,CostCenter3_ID,CostCenter4_ID,TransDate,DocNumber
						,Payment_ID,customerJour_ID,EngDesc,ArbDesc,Amount,AmountFC
						,Currency_ID,CurrencyRate,DueDate,ApprovalBy_ID,ApprovalDate
						,created_by_id,Remarks,FiscalYearPeriod
						
						)

					Select 
						 LP.TransType_ID ,LPL.customer_ID  ,LPL.CostCenter1_ID,LPL.CostCenter2_ID,LPL.CostCenter3_ID,LPL.CostCenter4_ID , LP.PaymentDate ,LP.Number 
						 ,PaymentID,retid ,COALESCE(EngDesc,' ')  , ArbDesc ,lpl.Amount,lpl.AmountFC 
						 ,lp.Currency_ID,lp.CurrencyRate ,Null DueDate , LoginUserid  ApprovedBy_ID , current_date  ApprovedDate
						 ,LoginUserid ,lp.Remarks  ,FiscalYearPeriod
						From  ar_customersPayments LP
						Inner join ar_customersPaymentsLine LPL On LP.ID = LPL.customerPayment_ID 
						Where LP.ID = PaymentID 
						And Status_ID = (Select id From sy_lookup where  keyid= 90101 limit 1 ) ; -----  Processing Status Only

			----- check if we need Add in Ledger Jour

insert into gl_ledgertrans (
		TransType_ID,Ledger_ID,CostCenter1_ID,CostCenter2_ID,CostCenter3_ID,CostCenter4_ID,TransDate,DocNumber
		,customerJour,EngDesc,ArbDesc,Amount,AmountFC
		,Currency_ID,CurrencyRate,DueDate,ApprovalBy_ID,ApprovalDate
		,created_by_id,Remarks,FiscalYearPeriod

						)

Select 
	TransType_ID,Ledger_ID,CostCenter1_ID,CostCenter2_ID,CostCenter3_ID,CostCenter4_ID,JournalDate,JournalNumber
	,cj.ID,EngDesc,ArbDesc,Amount,0 AmountFC
	,cj.Currency_ID,cj.CurrencyRate,null DueDate,null ApprovalBy_ID, null ApprovalDate
	,created_by_id,cj.Remarks,FiscalYearPeriod
from ar_customersjour cj
inner join ar_customersjourline cjl On cj.id = cjl.customerjour_id
where cj.id= retid;

					Update ar_customersPayments Set Status_ID =(Select ID from sy_LookUp Where keyid = 90105  limit 1)  ----- Completed Successfully
					Where ID =   PaymentID;

					Update gl_TreasuriesOrders  Set RefPaymentID  = PaymentID ,IsFinish = True , FinishDate = current_Date
					Where  ID =    (Select TreasuryOrder_ID from ar_customersPayments  Where ID = PaymentID limit 1);
					 
					 
					--=====  Update Cheque Status to 
			elseif myrec.ischeck =  True  then
					--------90507	ChequesStatus	3	Delivered	تم التسليم
					
--					Update bnk_BanksCheques Set ChequeStatus = 90507 Where id = @IsSelectedChq
--					Update BNK_ChequesTrans  Set ChequeStatus  = 90507 Where id = @IsSelectedChq

			elseif myrec.iscredit =  True  then
			elseif myrec.iscreditcard =  True  then
			end if;

		
		end if;
		
		 
end;
$$;


ALTER PROCEDURE public.gl_postpayment(accounttype integer, paymentid integer, loginuserid integer) OWNER TO postgres;

--
-- Name: gl_rpledgerjournal(character varying, character varying, character varying, date, date, character varying, character varying); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.gl_rpledgerjournal(ledgercode character varying DEFAULT ''::character varying, fromledger character varying DEFAULT ''::character varying, toledger character varying DEFAULT ''::character varying, fromdate date DEFAULT '2018-05-01'::date, todate date DEFAULT '2018-11-22'::date, transtypecode character varying DEFAULT ''::character varying, transdesc character varying DEFAULT ''::character varying) RETURNS TABLE(ljid integer, journalnumber character varying, transdate date, ttcode character varying, ttengname character varying, ttarbname character varying, lcode character varying, lengname character varying, larbname character varying, lid integer, ljlengdesc character varying, ljlarbname character varying, debitamount numeric, creditamount numeric, amount numeric, amountfc numeric, debitamountfc numeric, creditamountfc numeric, currencyid integer, currencyrate numeric, rank integer)
    LANGUAGE plpgsql
    AS $$
Declare 

Begin

    CREATE TEMP TABLE AllowedTrans AS
	Select unnest(string_to_array(TransTypeCode, '|')) TransCode ;
	--SELECT value as TransCode  FROM dbo.fn_Split(TransTypeCode,',');
	
	return query 
	
SELECT
     LT.ID LJID
    ,LT.DocNumber 	    JournalNumber
    ,LT.TransDate	    TransDate
    ,TT.Code		    TTCode
    ,TT.EngName	    TTEngName
    ,TT.ArbName	    TTArbName
    ,L.Code		    LCode 
    ,L.EngName		    LEngName
    ,L.ArbName		    LArbName
    ,L.ID			    LID
    ,LT.EngDesc	    LJLEngDesc
    ,LT.ArbDesc	    LJLArbDesc
    ,Case When COALESCE(LT.Amount,0)  >=0 Then  LT.Amount Else 0 End  Debitamount 
    ,Case When COALESCE(LT.Amount,0)  <0 Then  ABS(LT.Amount) Else 0 End  Creditamount 
    ,LT.Amount 
    ,LT.AmountFC 
    ,Case When COALESCE(LT.AmountFC,0) >= 0 Then ABS(LT.AmountFC) Else 0 End As DebitFC
    ,Case When COALESCE(LT.AmountFC,0) < 0 Then ABS(LT.AmountFC) Else 0 End As CreditFC
    ,LT.Currency_ID
    ,LT.CurrencyRate 
    ,LT.ID Rank
FROM 
gl_LedgerTrans LT
INNER JOIN gl_TransTypes TT ON LT.TransType_ID = TT.ID
INNER JOIN gl_Ledger L ON L.ID = LT.Ledger_ID

WHERE LT.ID IS NOT NULL
AND (COALESCE(TransTypeCode,'') = '' OR upper(TT.Code) IN (SELECT upper(TransCode) FROM AllowedTrans))
AND (COALESCE(LedgerCode,'') = '' OR L.Code Like LedgerCode || '%')
AND (COALESCE(FromLedger,'') = '' OR L.Code >= FromLedger)
AND (COALESCE(ToLedger,'') = '' OR L.Code <= ToLedger)
AND (COALESCE(FromDate,'01/01/1900') = '01/01/1900' OR LT.TransDate  >= FromDate)
AND (COALESCE(ToDate,'01/01/1900') = '01/01/1900' OR LT.TransDate <= ToDate)
And ( COALESCE(LT.EngDesc,'') || COALESCE(LT.EngDesc,'')  Like  '%' || COALESCE(TransDesc,'') || '%')
order by LT.TransDate,LT.ID
;
	
drop TABLE AllowedTrans;

End;
$$;


ALTER FUNCTION public.gl_rpledgerjournal(ledgercode character varying, fromledger character varying, toledger character varying, fromdate date, todate date, transtypecode character varying, transdesc character varying) OWNER TO postgres;

--
-- Name: gl_rpledgersoa(character varying, character varying, character varying, character varying, character varying, character varying, character varying, character varying, date, date, character varying, double precision, double precision, character varying, character varying, boolean, boolean, boolean, boolean, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.gl_rpledgersoa(pledcode character varying DEFAULT ''::character varying, cost1code character varying DEFAULT ''::character varying, cost2code character varying DEFAULT ''::character varying, cost3code character varying DEFAULT ''::character varying, cost4code character varying DEFAULT ''::character varying, fromled character varying DEFAULT ''::character varying, toled character varying DEFAULT ''::character varying, ledcat character varying DEFAULT ''::character varying, pfromdate date DEFAULT CURRENT_DATE, ptodate date DEFAULT CURRENT_DATE, transcode character varying DEFAULT ''::character varying, balgthan double precision DEFAULT '-9999999999'::bigint, ballthan double precision DEFAULT 999999999, pengdesc character varying DEFAULT ''::character varying, parbdesc character varying DEFAULT ''::character varying, balnzero boolean DEFAULT false, postflag boolean DEFAULT false, netmovment boolean DEFAULT false, lang boolean DEFAULT false, userid integer DEFAULT 1) RETURNS TABLE(rowno bigint, rowtot numeric, lid integer, ledcode character varying, ledengname character varying, ledarbname character varying, ledcatcode character varying, ledcatengname character varying, ledcatarbname character varying, drobamount numeric, crobamount numeric, obamount numeric, dramount numeric, cramount numeric, amount numeric, drobamountfc numeric, crobamountfc numeric, obamountfc numeric, dramountfc numeric, cramountfc numeric, amountfc numeric, usercode character varying, ttcode character varying, ttengname character varying, ttarbname character varying, arbdesc character varying, engdesc character varying, transdate date, docnumber character varying, tcramount numeric, tcramountfc numeric, tdramount numeric, tdramountfc numeric, curcode character varying, curengname character varying, curarbname character varying, currencyrate numeric, c1code character varying, c2code character varying, c3code character varying, c4code character varying, c1engname character varying, c1arbname character varying, c2engname character varying, c2arbname character varying, c3engname character varying, c3arbname character varying, c4engname character varying, c4arbname character varying, ledgertransid integer, ledid integer, ledgerjournalid integer, paymentid integer, approveddate date, approvedusercode character varying, approveduserengname character varying, approveduserarbname character varying)
    LANGUAGE plpgsql
    AS $$
Declare LedgerID 	Int;
	    UpToDate date ;
	   InCludeUpToDate  int   ;
	
	
	Declare PeriodID int;
	Declare PeriodToDate	date;

Begin

	UpToDate = PFromDate;
	PeriodID=(SELECT * FROM  sy_GetFiscalYearPeriodID( cast(UpToDate as date) ,'gl' ));

	PeriodToDate =(Select   FYp.ToDate  
	from sy_FiscalYears FY
	Inner Join sy_FiscalYearsPeriods FYP On FY.ID = FYP.FiscalYear_ID 
	Inner Join sy_FiscalYearsPeriodsModules FYPM On FYP.ID = FYPM.FiscalYearPeriod_ID 
	Where  FromDate < UpToDate
	And CloseDate is Not  null Order By FromDate Desc limit 1);

	return query

SELECT 
	   ROW_NUMBER() Over(Order by v.TransDate, v.LedgerTransID) RowNo  
	   , v.OBAmount + Sum( v.TDrAmount - v.TCrAmount) Over  (Order by v.TransDate, v.LedgerTransID) RowTot
    ,* 
FROM(

	Select DisTinCT
	 LedgerID
	,vwInfo.LedCode
	,vwInfo.LedEngNAme
	,vwInfo.LedArbName
	,vwInfo.LedCatCode
	,vwInfo.LedCatEngNAme
	,vwInfo.LedCatArbName
	,vwInfo.DrOBAmount,vwInfo.CrOBAmount ,vwInfo.OBAmount
	,vwInfo.DrAmount, vwInfo.CrAmount 
	, vwInfo.Amount
	, vwInfo.DrOBAmountFC, vwInfo.CrOBAmountFC ,vwInfo.OBAmountFC
	, vwInfo.DrAmountFC, vwInfo.CrAmountFC 
	, vwInfo.AmountFC
	, (select username from  users_user U Where U.ID=UserID) as UserCode
	,vwt.TTCode 
	,vwt.TTEngName 
	,vwt.TTArbName 	
	,vwt.ArbDesc  ArbDesc 
	,vwt.EngDesc  EngDesc
	,vwt.TransDate 
	,vwt.DocNumber 
	,vwt.CrAmount		TCrAmount
	,vwt.CrAmountFC		TCrAmountFC
	,vwt.DrAmount 		TDrAmount
	,vwt.DrAmountFC		TDrAmountFC
	,vwt.CurCode 
	,vwt.CurEngName 
	,vwt.CurArbName 
	,vwt.CurrencyRate 
	,vwt.C1Code 
	,vwt.C2Code 
	,vwt.C3Code 
	,vwt.C4Code 
	,vwt.C1EngName 
	,vwt.C1ArbName 
	,vwt.C2EngName 
	,vwt.C2ArbName 
	,vwt.C3EngName 
	,vwt.C3ArbName 
	,vwt.C4EngName 
	,vwt.C4ArbName 

	,vwt.LedgerTransID
	,vwt.LedID   
	--,vwt.OperationHeadID 
	,vwt.LedgerJour_ID 
	--,vwt.LedgerTransID 	 
	,vwt.Payment_ID 
	
	,vwt.ApprovalDate
	,vwt.ApprovedUserCode
	,vwt.ApprovedUserEngName
	,vwt.ApprovedUserArbName

	From 
	(
		Select 
		 L.ID 
		,L.Code LedCode
		,L.EngNAme LedEngNAme
		,L.ArbName LedArbName
		,LC.Code   LedCatCode
		,LC.EngNAme LedCatEngNAme
		,LC.ArbName LedCatArbName
		,Mov.CostCenter1ID Cost1ID
		,Mov.CostCenter2ID Cost2ID
		,Mov.CostCenter3ID Cost3ID
		,Mov.CostCenter4ID Cost4ID

		, SUM(COALESCE(Bal.DrAmount,0)) DrOBAmount, SUM(COALESCE(Bal.CrAmount,0)) CrOBAmount ,SUM(COALESCE(Bal.DrAmount,0) - COALESCE(Bal.CrAmount,0)) OBAmount
		, AVG(COALESCE(Mov.DrAmount,0)) DrAmount, AVG(COALESCE(Mov.CrAmount,0)) CrAmount 
		, SUM(COALESCE(Bal.DrAmount,0) - COALESCE(Bal.CrAmount,0)) + AVG(COALESCE(Mov.DrAmount ,0)- COALESCE(Mov.CrAmount,0)) Amount

		, SUM(COALESCE(Bal.DrAmountFC,0)) DrOBAmountFC, SUM(COALESCE(Bal.CrAmountFC,0)) CrOBAmountFC ,SUM(COALESCE(Bal.DrAmountFC,0) - COALESCE(Bal.CrAmountFC,0)) OBAmountFC
		, AVG(COALESCE(Mov.DrAmountFC,0)) DrAmountFC, AVG(COALESCE(Mov.CrAmountFC,0)) CrAmountFC 
		, SUM(COALESCE(Bal.DrAmountFC,0) - COALESCE(Bal.CrAmountFC,0)) + AVG(COALESCE(Mov.DrAmountFC ,0)- COALESCE(Mov.CrAmountFC,0)) AmountFC

		From
		 gl_Ledger L 
		Left Join 	gl_LedgersCategories LC	On 	LC.ID=L.LedgerCategory_ID
		-- Opening Balance Before From Date
		Left Join 
	   (
		Select LCB.Ledger_ID LedgerID,COALESCE(CostCenter1_ID,0) CostCenter1ID,COALESCE(CostCenter2_ID,0) CostCenter2ID,COALESCE(CostCenter3_ID,0) CostCenter3ID,COALESCE(CostCenter4_ID,0) CostCenter4ID
		, SUM(COALESCE(LCB.DrAmount,0)) DrAmount , SUM(COALESCE(LCB.CrAmount ,0)) CrAmount 
		,  SUM(COALESCE(LCB.DrAmountFC,0)) DrAmountFC , SUM(COALESCE(LCB.CrAmountFC ,0)) CrAmountFC 
		From gl_LedgerCostBalances LCB
		LEFT JOIN gl_CostCenters CC1 ON COALESCE(LCB.CostCenter1_ID,0) = CC1.ID
		LEFT JOIN gl_CostCenters CC2 ON COALESCE(LCB.CostCenter2_ID,0) = CC2.ID
		LEFT JOIN gl_CostCenters CC3 ON COALESCE(LCB.CostCenter3_ID,0) = CC3.ID 
		LEFT JOIN gl_CostCenters CC4 ON COALESCE(LCB.CostCenter4_ID,0) = CC4.ID 		
		Where  
		--FiscalYearPeriod = COALESCE(PeriodID,0)
		0 = 0
		AND COALESCE(CC1.Code,'') LIKE COALESCE(Cost1Code,'') || '%'
		AND COALESCE(CC2.Code,'') LIKE COALESCE(Cost2Code,'') || '%'
		AND COALESCE(CC3.Code,'') LIKE COALESCE(Cost3Code,'') || '%'
		AND COALESCE(CC4.Code,'') LIKE COALESCE(Cost4Code,'') || '%'
		Group By Ledger_ID,COALESCE(CostCenter1_ID,0),COALESCE(CostCenter2_ID,0),COALESCE(CostCenter3_ID,0),COALESCE(CostCenter4_ID,0)

	   Union All
		Select 
		LT.Ledger_ID LedgerID ,COALESCE(CostCenter1_ID,0) CostCenter1ID,COALESCE(CostCenter2_ID,0) CostCenter2ID,COALESCE(CostCenter3_ID,0) CostCenter3ID,COALESCE(CostCenter4_ID,0) CostCenter4ID
		,Sum(COALESCE(Case When LT.Amount   > 0 Then abs(LT.Amount)  Else 0 End,0))
		,Sum(COALESCE(Case When LT.Amount   < 0 Then abs(LT.Amount)  Else 0 End,0))

		,Sum(COALESCE(Case When LT.AmountFC   > 0 Then abs(LT.AmountFC) Else 0 End,0))
		,Sum(COALESCE(Case When LT.AmountFC   < 0 Then abs(LT.AmountFC) Else 0 End,0))
		From gl_LedgerTrans LT
		LEFT JOIN gl_CostCenters CC1 ON COALESCE(LT.CostCenter1_ID,0) = CC1.ID
		LEFT JOIN gl_CostCenters CC2 ON COALESCE(LT.CostCenter2_ID,0) = CC2.ID
		LEFT JOIN gl_CostCenters CC3 ON COALESCE(LT.CostCenter3_ID,0) = CC3.ID 
		LEFT JOIN gl_CostCenters CC4 ON COALESCE(LT.CostCenter4_ID,0) = CC4.ID 
		Where 
		(LT.TransDate > PeriodToDate Or PeriodToDate Is Null)
		And LT.TransDate < UpToDate
		AND COALESCE(CC1.Code,'') LIKE COALESCE(Cost1Code,'') || '%'
		AND COALESCE(CC2.Code,'') LIKE COALESCE(Cost2Code,'') || '%'
		AND COALESCE(CC3.Code,'') LIKE COALESCE(Cost3Code,'') || '%'
		AND COALESCE(CC4.Code,'') LIKE COALESCE(Cost4Code,'') || '%'
		Group By Ledger_ID,COALESCE(CostCenter1_ID,0),COALESCE(CostCenter2_ID,0),COALESCE(CostCenter3_ID,0),COALESCE(CostCenter4_ID,0)
		) Bal ON L.ID = Bal.LedgerID

		-- Movement Trans Between Dates
		Left Join
		(
		Select 
		LT.Ledger_ID LedgerID ,COALESCE(MAX(CostCenter1_ID),0) CostCenter1ID,COALESCE(MAX(CostCenter2_ID),0) CostCenter2ID,COALESCE(MAX(CostCenter3_ID),0) CostCenter3ID,COALESCE(MAX(CostCenter4_ID),0) CostCenter4ID
		,Sum(COALESCE(Case When LT.Amount   > 0 Then abs(LT.Amount) Else 0 End,0)) As DrAmount 
		,Sum(COALESCE(Case When LT.Amount   < 0 Then abs(LT.Amount) Else 0 End,0)) As CrAmount 

		,Sum(COALESCE(Case When LT.AmountFC   > 0 Then abs(LT.AmountFC) Else 0 End,0)) DrAmountFC 
		,Sum(COALESCE(Case When LT.AmountFC   < 0 Then abs(LT.AmountFC) Else 0 End,0)) CrAmountFC
		From gl_LedgerTrans LT
		LEFT JOIN gl_CostCenters CC1 ON COALESCE(CostCenter1_ID,0) = CC1.ID  
		LEFT JOIN gl_CostCenters CC2 ON COALESCE(CostCenter2_ID,0) = CC2.ID
		LEFT JOIN gl_CostCenters CC3 ON COALESCE(CostCenter3_ID,0) = CC3.ID 
		LEFT JOIN gl_CostCenters CC4 ON COALESCE(CostCenter4_ID,0) = CC4.ID 
		Where 
		LT.TransDate >= PFromDate
		And LT.TransDate <= PToDate
		AND (COALESCE(Cost1Code,'') = '' OR COALESCE(CC1.Code,'') LIKE COALESCE(Cost1Code,'') || '%' )
		AND (COALESCE(CC2.Code,'') LIKE COALESCE(Cost2Code,'') || '%')
		AND COALESCE(CC3.Code,'') LIKE COALESCE(Cost3Code,'') || '%'
		AND COALESCE(CC4.Code,'') LIKE COALESCE(Cost4Code,'') || '%'
		Group By  Ledger_ID--,COALESCE(CostCenter1ID,0),COALESCE(CostCenter2ID,0),COALESCE(CostCenter3ID,0),COALESCE(CostCenter4ID,0)
		)Mov
		On L.ID = Mov.LedgerID 
		Where 
			L.Code Like PLedCode || '%'
		And L.Code Between  FromLed || ' ' And ToLed || 'ZZZ'
		And LC.Code Like LedCat || '%'	
	
		Group By L.ID
				,L.Code
				,L.EngNAme
				,L.ArbName
				,LC.Code   
				,LC.EngNAme 
				,LC.ArbName 
				,Mov.CostCenter1ID,Mov.CostCenter2ID,Mov.CostCenter3ID,Mov.CostCenter4ID
			
		Having 
		(SUM(COALESCE(Bal.DrAmount,0) - COALESCE(Bal.CrAmount,0) + COALESCE(Mov.DrAmount ,0)- COALESCE(Mov.CrAmount,0)) <> (Case 	When  	BalNZero = true 	Then 0 End) 	Or 	BalNZero = false
		Or SUM(COALESCE(Bal.DrAmount,0) - COALESCE(Bal.CrAmount,0)) <>0 )
		
		) vwInfo
		
	  --Details Data For Ledger Trans
		LEFT Join 
		(Select 
			 LT.ID LedgerTransID
			,L.ID LedID
			,L.Code 
			,cast(LJ.JournalNumber as varchar(50))  DocNumber
			,Case when LT.ArbDesc = '' then LT.EngDesc  else LT.ArbDesc  end AS ArbDesc 
			,LT.EngDesc 
			,LT.TransDate 
			,LT.Payment_ID 
			,LT.LedgerJour_ID 
			--,LT.OperationHeadID 
			
			
			 ,Case When LT.Amount   > 0 Then  abs( LT.Amount - case When NetMovment = true Then   COALESCE(LT.SettleAmount,0) Else 0 End) Else 0 End As DrAmount 
			 ,Case When LT.Amount   < 0 Then  abs( LT.Amount - case When NetMovment = true Then   COALESCE(LT.SettleAmount,0) Else 0 End) Else 0 End As CrAmount 
			

			 ,Case When LT.AmountFC   > 0 Then  abs( LT.AmountFC - case When NetMovment = true Then   COALESCE(SettleAmount,0) Else 0 End) Else 0 End As DrAmountFC 
			 ,Case When LT.AmountFC   < 0 Then  abs( LT.AmountFC - case When NetMovment = true Then   COALESCE(SettleAmount,0) Else 0 End) Else 0 End As CrAmountFC 

			--,COALESCE(Case When LT.Amount   > = 0 Then CONVERT(money, abs(LT.Amount),1) Else 0 End,0) As DrAmount 
			--,COALESCE(Case When LT.Amount   < 0 Then CONVERT(money, abs(LT.Amount),1) Else 0 End,0) As CrAmount 

			--,COALESCE(Case When AmountFC    > = 0 Then CONVERT(money, abs(AmountFC),1) Else 0 End,0) As DrAmountFC 
			--,COALESCE(Case When AmountFC   < 0 Then CONVERT(money, abs(AmountFC),1) Else 0 End,0) As CrAmountFC 

			,Cur.Code	 As CurCode
			,Cur.Name As CurEngName
			,Cur.Name As CurArbName
			,LT.CurrencyRate 
			,C1.ID		C1ID
			,C1.Code	C1Code
			,C1.EngName C1EngName
			,C1.EngName C1ArbName
			
			,C2.ID		C2ID
			,C2.Code	C2Code
			,C2.EngName C2EngName
			,C2.EngName C2ArbName

			,C3.ID		C3ID
			,C3.Code	C3Code
			,C3.EngName C3EngName
			,C3.EngName C3ArbName

			,C4.ID		C4ID
			,C4.Code	C4Code
			,C4.EngName C4EngName
			,C4.EngName C4ArbName
			,TT.Code	TTCode
			,TT.EngName TTEngName
			,TT.ArbName TTArbName 
			
			,cast(LT.ApprovalDate as date) ApprovalDate
			,U.name as ApprovedUserCode
			,U.Name as ApprovedUserEngName
			,U.Name as ApprovedUserArbName
			 
		 From gl_LedgerTrans LT
		 Inner Join gl_TransTypes  TT On TT.ID = LT.TransType_ID 
		 Inner Join gl_Ledger L On L.ID = LT.Ledger_ID
		 Left Join 	gl_LedgersCategories LC	On 	LC.ID=L.LedgerCategory_ID
		 LEFT Join crm_Currency Cur On Cur.ID = LT.Currency_ID 
		 Left Join gl_CostCenters C1 On C1.ID = LT.CostCenter1_ID 
		 Left Join gl_CostCenters C2 On C2.ID = LT.CostCenter2_ID 
		 Left Join gl_CostCenters C3 On C3.ID = LT.CostCenter3_ID 
		 Left Join gl_CostCenters C4 On C4.ID = LT.CostCenter4_ID 
		 left join gl_ledgerjour lj on lj.id = lt.LedgerJour_ID
		--left join (select ID,JournalNumber from gl_VendorJour) vt on vt.ID = lj.VendorJournalID
		 Left Join users_user U On U.ID = LT.ApprovalBy_ID 
		 Where 
		 LT.TransDate >= PFromDate
		 And LT.TransDate <= PToDate
		 And COALESCE(LT.EngDesc,'') Like PEngDesc || '%'
		 And COALESCE(LT.ArbDesc,'') Like PArbDesc || '%'
		 And COALESCE(TT.Code,'') Like   TransCode || '%'
		
		)vwT On vwInfo.ID = vwT.LedID  
		AND (COALESCE(Cost1Code,'') = '' OR COALESCE(vwInfo.Cost1ID,0) = COALESCE(vwt.C1ID,0))
		AND (COALESCE(Cost2Code,'') = '' OR COALESCE(vwInfo.Cost2ID,0) = COALESCE(vwt.C2ID,0))
		AND (COALESCE(Cost3Code,'') = '' OR COALESCE(vwInfo.Cost3ID,0) = COALESCE(vwt.C3ID,0))
		AND (COALESCE(Cost4Code,'') = '' OR COALESCE(vwInfo.Cost4ID,0) = COALESCE(vwt.C4ID,0))
		
		Where vwInfo.Amount  >=	BalGThan	
		And vwInfo.Amount  <= BalLThan	
		And ((vwInfo.Amount <> 0 And BalNZero = true ) Or BalNZero = false )	

)V;

End;

$$;


ALTER FUNCTION public.gl_rpledgersoa(pledcode character varying, cost1code character varying, cost2code character varying, cost3code character varying, cost4code character varying, fromled character varying, toled character varying, ledcat character varying, pfromdate date, ptodate date, transcode character varying, balgthan double precision, ballthan double precision, pengdesc character varying, parbdesc character varying, balnzero boolean, postflag boolean, netmovment boolean, lang boolean, userid integer) OWNER TO postgres;

--
-- Name: gl_rpledgertrialbalance(character varying, character varying, character varying, character varying, character varying, character varying, character varying, character varying, date, date, character varying, double precision, double precision, boolean, boolean, boolean, integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.gl_rpledgertrialbalance(pledcode character varying DEFAULT ''::character varying, fromled character varying DEFAULT ''::character varying, toled character varying DEFAULT ''::character varying, cost1code character varying DEFAULT ''::character varying, cost2code character varying DEFAULT ''::character varying, cost3code character varying DEFAULT ''::character varying, cost4code character varying DEFAULT ''::character varying, ledcat character varying DEFAULT ''::character varying, pfromdate date DEFAULT CURRENT_DATE, ptodate date DEFAULT CURRENT_DATE, transcode character varying DEFAULT ''::character varying, balgthan double precision DEFAULT '-9999999999'::bigint, ballthan double precision DEFAULT 999999999, balnzero boolean DEFAULT false, postflag boolean DEFAULT false, lang boolean DEFAULT false, userid integer DEFAULT 1, glen integer DEFAULT 1) RETURNS TABLE(lid integer, ledcode character varying, ledengname character varying, ledarbname character varying, ledcatcode character varying, ledcatengname character varying, ledcatarbname character varying, drobamount numeric, crobamount numeric, obamount numeric, dramount numeric, cramount numeric, amount numeric, drobamountfc numeric, crobamountfc numeric, obamountfc numeric, dramountfc numeric, cramountfc numeric, amountfc numeric)
    LANGUAGE plpgsql
    AS $$
Declare 
	LedgerID 	Int;
	UpToDate date ;
	InCludeUpToDate  int   ;
	
	PeriodID int;
	PeriodToDate	date;

    MaxLen int = 0 ;

Begin

	UpToDate = PFromDate;
	PeriodID=(SELECT * FROM  sy_GetFiscalYearPeriodID( cast(UpToDate as date) ,'gl' ));

	PeriodToDate =(Select   FYp.ToDate  
	from sy_FiscalYears FY
	Inner Join sy_FiscalYearsPeriods FYP On FY.ID = FYP.FiscalYear_ID 
	Inner Join sy_FiscalYearsPeriodsModules FYPM On FYP.ID = FYPM.FiscalYearPeriod_ID 
	Where  FromDate < UpToDate
	And CloseDate is Not  null Order By FromDate Desc limit 1);

CREATE TEMP TABLE TB AS
Select 
    
     L.ID 
    ,L.Code LedCode
    ,L.EngNAme LedEngNAme
    ,L.ArbName LedArbName
    ,LC.Code   LedCatCode
    ,LC.EngNAme LedCatEngNAme
    ,LC.ArbName LedCatArbName
    
    , SUM(COALESCE(Bal.DrAmount,0)) DrOBAmount, SUM(COALESCE(Bal.CrAmount,0)) CrOBAmount ,SUM(COALESCE(Bal.DrAmount,0) - COALESCE(Bal.CrAmount,0)) OBAmount
    , SUM(COALESCE(Mov.DrAmount,0)) DrAmount, SUM(COALESCE(Mov.CrAmount,0)) CrAmount 
    , SUM(COALESCE(Bal.DrAmount,0) - COALESCE(Bal.CrAmount,0) + COALESCE(Mov.DrAmount ,0)- COALESCE(Mov.CrAmount,0)) Amount

    , SUM(COALESCE(Bal.DrAmountFC,0)) DrOBAmountFC, SUM(COALESCE(Bal.CrAmountFC,0)) CrOBAmountFC ,SUM(COALESCE(Bal.DrAmountFC,0) - COALESCE(Bal.CrAmountFC,0)) OBAmountFC
    , SUM(COALESCE(Mov.DrAmountFC,0)) DrAmountFC, SUM(COALESCE(Mov.CrAmountFC,0)) CrAmountFC 
    , SUM(COALESCE(Bal.DrAmountFC,0) - COALESCE(Bal.CrAmountFC,0) + COALESCE(Mov.DrAmountFC ,0)- COALESCE(Mov.CrAmountFC,0)) AmountFC

    
    From
        gl_Ledger L 
        Left Join     gl_LedgersCategories LC    On     LC.ID=L.LedgerCategory_ID
        -- Opening Balance Before From Date
        Left Join 
       (SELECT B1.LedgerID,SUM(B1.DrAmount) DrAmount,SUM(B1.CrAmount) CrAmount,SUM(B1.DrAmountFC) DrAmountFC,SUM(B1.CrAmountFC) CrAmountFC FROM
       (
			Select Ledger_ID LedgerID
				, SUM(COALESCE(LCB.DrAmount,0)) DrAmount , SUM(COALESCE(LCB.CrAmount ,0)) CrAmount 
				,  SUM(COALESCE(LCB.DrAmountFC,0)) DrAmountFC , SUM(COALESCE(LCB.CrAmountFC ,0)) CrAmountFC 
				From gl_LedgerCostBalances LCB
				LEFT JOIN gl_CostCenters CC1 ON COALESCE(LCB.CostCenter1_ID,0) = CC1.ID
				LEFT JOIN gl_CostCenters CC2 ON COALESCE(LCB.CostCenter2_ID,0) = CC2.ID
				LEFT JOIN gl_CostCenters CC3 ON COALESCE(LCB.CostCenter3_ID,0) = CC3.ID 
				LEFT JOIN gl_CostCenters CC4 ON COALESCE(LCB.CostCenter4_ID,0) = CC4.ID         
			Where  
				fiscalyearperiod = COALESCE(PeriodID,0)
		   		AND COALESCE(CC1.Code,'') LIKE COALESCE(Cost1Code,'') || '%'
				AND COALESCE(CC2.Code,'') LIKE COALESCE(Cost2Code,'') || '%'
				AND COALESCE(CC3.Code,'') LIKE COALESCE(Cost3Code,'') || '%'
				AND COALESCE(CC4.Code,'') LIKE COALESCE(Cost4Code,'') || '%'
			Group By Ledger_ID--,COALESCE(CostCenter1ID,0),COALESCE(CostCenter2ID,0),COALESCE(CostCenter3ID,0),COALESCE(CostCenter4ID,0)

		   	Union All

            Select 
                Ledger_ID --,COALESCE(MAX(CostCenter1ID),0) CostCenter1ID,COALESCE(MAX(CostCenter2ID),0) CostCenter2ID,COALESCE(MAX(CostCenter3ID),0) CostCenter3ID,COALESCE(MAX(CostCenter4ID),0) CostCenter4ID
                ,Sum(COALESCE(Case When lt.Amount   > 0 Then abs(lt.Amount) Else 0 End,0))
                ,Sum(COALESCE(Case When lt.Amount   < 0 Then abs(lt.Amount) Else 0 End,0))

                ,Sum(COALESCE(Case When lt.AmountFC   > 0 Then lt.AmountFC Else 0 End,0))
                ,Sum(COALESCE(Case When lt.AmountFC   < 0 Then lt.AmountFC Else 0 End,0))
            From gl_LedgerTrans LT
            LEFT JOIN gl_CostCenters CC1 ON COALESCE(LT.CostCenter1_ID,0) = CC1.ID
            LEFT JOIN gl_CostCenters CC2 ON COALESCE(LT.CostCenter2_ID,0) = CC2.ID
            LEFT JOIN gl_CostCenters CC3 ON COALESCE(LT.CostCenter3_ID,0) = CC3.ID 
            LEFT JOIN gl_CostCenters CC4 ON COALESCE(LT.CostCenter4_ID,0) = CC4.ID 
            Where 
				(lt.TransDate > PeriodToDate Or PeriodToDate Is Null)
				And lt.TransDate < UpToDate
				AND COALESCE(CC1.Code,'') LIKE COALESCE(Cost1Code,'') || '%'
				AND COALESCE(CC2.Code,'') LIKE COALESCE(Cost2Code,'') || '%'
				AND COALESCE(CC3.Code,'') LIKE COALESCE(Cost3Code,'') || '%'
				AND COALESCE(CC4.Code,'') LIKE COALESCE(Cost4Code,'') || '%'
            Group By Ledger_ID--,COALESCE(CostCenter1ID,0),COALESCE(CostCenter2ID,0),COALESCE(CostCenter3ID,0),COALESCE(CostCenter4ID,0)
        )B1 
		Group By B1.LedgerID) Bal
        On L.ID = Bal.LedgerID

        -- Movement Trans Between Dates
        Left Join
        (

			Select 
                Ledger_ID ,COALESCE(MAX(CostCenter1_ID),0) CostCenter1ID,COALESCE(MAX(CostCenter2_ID),0) CostCenter2ID,COALESCE(MAX(CostCenter3_ID),0) CostCenter3ID,COALESCE(MAX(CostCenter4_ID),0) CostCenter4ID
                ,Sum(COALESCE(Case When lt.Amount   > 0 Then lt.Amount Else 0 End,0)) As DrAmount 
                ,Sum(COALESCE(Case When lt.Amount   < 0 Then abs(lt.Amount) Else 0 End,0)) As CrAmount 

                ,Sum(COALESCE(Case When lt.AmountFC   > 0 Then lt.AmountFC Else 0 End,0)) DrAmountFC 
                ,Sum(COALESCE(Case When lt.AmountFC   < 0 Then abs(lt.AmountFC) Else 0 End,0)) CrAmountFC
            From gl_LedgerTrans lt
			LEFT JOIN gl_CostCenters CC1 ON COALESCE(CostCenter1_ID,0) = CC1.ID  
			LEFT JOIN gl_CostCenters CC2 ON COALESCE(CostCenter2_ID,0) = CC2.ID
			LEFT JOIN gl_CostCenters CC3 ON COALESCE(CostCenter3_ID,0) = CC3.ID 
			LEFT JOIN gl_CostCenters CC4 ON COALESCE(CostCenter4_ID,0) = CC4.ID 
            Where 
				lt.TransDate >= pFromDate
				And lt.TransDate <  pToDate + 1  * INTERVAL '1 day'  
                AND (COALESCE(Cost1Code,'') = '' OR COALESCE(CC1.Code,'') LIKE COALESCE(Cost1Code,'') || '%' )
				AND (COALESCE(CC2.Code,'') LIKE COALESCE(Cost2Code,'') || '%')
				AND COALESCE(CC3.Code,'') LIKE COALESCE(Cost3Code,'') || '%'
				AND COALESCE(CC4.Code,'') LIKE COALESCE(Cost4Code,'') || '%'
            Group By  Ledger_ID--,COALESCE(CostCenter1ID,0),COALESCE(CostCenter2ID,0),COALESCE(CostCenter3ID,0),COALESCE(CostCenter4ID,0)
        )Mov
        On L.ID = Mov.Ledger_ID 
        
        Where 
            L.Code Like pLedCode || '%'
        And L.Code Between  FromLed || ' ' And ToLed || 'ZZZ'
        And LC.Code Like LedCat || '%'    
        Group By L.ID
                ,L.Code
                ,L.EngNAme
                ,L.ArbName
                ,LC.Code   
                ,LC.EngNAme 
                ,LC.ArbName 
                ,Mov.CostCenter1ID,Mov.CostCenter2ID,Mov.CostCenter3ID,Mov.CostCenter4ID
            
        Having 
        (SUM(COALESCE(Bal.DrAmount,0) - COALESCE(Bal.CrAmount,0) + COALESCE(Mov.DrAmount ,0)- COALESCE(Mov.CrAmount,0)) <> (Case     When      BalNZero = true     Then 0 End)     Or     BalNZero = false
        Or SUM(COALESCE(Bal.DrAmount,0) - COALESCE(Bal.CrAmount,0)) <>0 )
        
        Order by L.Code;
        
        

	MaxLen = (Select Max(length(tb.LedCode)) From TB tb) ;
--Select @MaxLen
	

if GLen > MaxLen  Or GLen < 1 Or GLen Is Null then
	return query 
    Select * from TB ;
Else 
	if GLen > MaxLen  Or GLen < 1 Or GLen Is Null then
		GLen = MaxLen ;
		RAISE NOTICE '[%]', MaxLen;
	end if;

	CREATE TEMP TABLE Names AS
	Select *
	from 
	(
	Select Left(   Left( SS.LedCode || repeat('@',MaxLen) ,MaxLen ) ,GLen)  GrpCode
	 ,ss.LedEngName,ss.LedArbName 
	,  ROW_NUMBER() OVER(PARTITION BY Left( Left( ss.LedCode || repeat('@',MaxLen) ,MaxLen ) ,GLen) ORDER BY ss.LedCode Asc) AS RowNumber  

	 From TB SS 
	 )AA
	 Where RowNumber = 1 ;

	return query 
	Select 0 As ID ,cast(Replace(CodeGrp ,'@','') as character varying )  LedCode    
		   ,NN.LedEngNAme ,NN.LedArbName 

		   , cast(Max(AA.LedCatCode) as character varying ) LedCatCode,cast( Max(AA.LedCatEngName ) as character varying ) LedCatEngName
		   , cast(Max(AA.LedCatArbName ) as character varying ) LedCatArbName
		   ,Sum( AA.DrOBAmount) DrOBAmount , Sum(AA.CrOBAmount ) CrOBAmount 
		   ,Sum( AA.OBAmount) OBAmount 

		   ,Sum( AA.DrAmount) DrAmount, Sum(AA.CrAmount ) CrAmount 
		   ,Sum( AA.Amount) Amount 

		   ,Sum( AA.DrOBAmountFC) DrOBAmountFC , Sum(AA.CrOBAmountFC ) CrOBAmountFC 
		   ,Sum( AA.OBAmountFC) OBAmountFC 

		   ,Sum( AA.DrAmountFC) DrAmountFC , Sum(AA.CrAmountFC ) CrAmountFC 
		   ,Sum( AA.AmountFC) AmountFC 

	From 
	(
		Select  Left( Left( SS.LedCode || repeat('@',MaxLen) ,MaxLen ) ,GLen) CodeGrp
			   , SS.LedCatCode , SS.LedCatEngName ,SS.LedCatArbName 
			   ,( SS.DrOBAmount) DrOBAmount , (SS.CrOBAmount ) CrOBAmount 
			   ,( ss.OBAmount) OBAmount 
			   ,( SS.DrAmount) DrAmount , (SS.CrAmount ) CrAmount 
			   ,( SS.Amount) Amount 
			   ,( SS.DrOBAmountFC) DrOBAmountFC , (SS.CrOBAmountFC ) CrOBAmountFC 
			   ,( ss.OBAmountFC) OBAmountFC 
			   ,( SS.DrAmountFC) DrAmountFC , (SS.CrAmountFC ) CrAmountFC 
			   ,( ss.AmountFC) AmountFC 

		from TB SS
	)AA
	Inner Join Names NN On NN.GrpCode  = AA.CodeGrp  
	Group by CodeGrp
		   --, LedCatCode , LedCatEngName ,LedCatArbName
		   ,NN.LedEngNAme ,NN.LedArbName 
	Order by CodeGrp ;

	Drop table Names ;

End if ;

Drop table TB ;

        

End;
$$;


ALTER FUNCTION public.gl_rpledgertrialbalance(pledcode character varying, fromled character varying, toled character varying, cost1code character varying, cost2code character varying, cost3code character varying, cost4code character varying, ledcat character varying, pfromdate date, ptodate date, transcode character varying, balgthan double precision, ballthan double precision, balnzero boolean, postflag boolean, lang boolean, userid integer, glen integer) OWNER TO postgres;

--
-- Name: gl_treasuriesordersapproval(integer, integer); Type: PROCEDURE; Schema: public; Owner: postgres
--

CREATE PROCEDURE public.gl_treasuriesordersapproval(treasuryorderid integer DEFAULT 0, loginuserid integer DEFAULT 0)
    LANGUAGE plpgsql
    AS $$
 Declare PaymentID			int = 0 ;
 Declare AccountLedgerID			int = 0 ;
 Declare LedgerAccountTypeID			int = 0 ;

 Declare 
	ParmID	int;
	ParmTreasuryID	int ;
	ParmTreasuryAccountID	int;
	ParmTreasuryCostCenter1ID	int;
	ParmTreasuryCostCenter2ID	int;
	ParmTreasuryCostCenter3ID	int;
	ParmTreasuryCostCenter4ID	int;
	ParmPaymentDirectionID	int;
	ParmDefaultPayMethodID	int;
	ParmRefSourceRecID	int;
	ParmRefSourceObjectName	varchar(100);
	ParmOrderDate	date ;
	ParmAmount	numeric;
	ParmCurrencyID	int;
	ParmEngDesc	varchar(100);
	ParmArbDesc	varchar(100);
	ParmAccountType	int;
	ParmTransTypeID	int;
	ParmAccountID	int;
	ParmFiscalYearPeriodID	int;
	ParmCostCenter1ID	int;
	ParmCostCenter2ID	int;
	ParmCostCenter3ID	int;
	ParmCostCenter4ID	int;
	ParmApprovalDate	date;
	ParmApprovalByID	int;
	ParmReceiptID	int;
	ParmFinishDate	date;
	ParmIsFinish	bit;
	ParmRefPaymentID	int;
	ParmCompanyID	int;
	ParmRemarks	varchar(1024);
	ParmRegUserID	int;
	ParmPayCode	varchar(100);
	ParmPayEngDesc	varchar(100);
	ParmPayArbDesc	varchar(100);
	ParmIsCash	bit;
	ParmIsCheck	bit;
	ParmIsCreditCard	bit;
	ParmIsCredit	bit;

Declare PaymentStatusID int = (Select id from sy_lookup where keyid= 90101); ---- Read From sys_LookUp Table
------======  Next Part to Get Payment Date And Fiscal Period According date 
Declare 
	PaymentDate			date  = CURRENT_DATE ;
	FiscalYearPeriodID	int = 0 ;
	ModuleCode			varchar(20) = '';

Declare  
	EngDesc varchar(200) = '';
	ArbDesc varchar(200) = '';

Declare 
	SignTreasuryAccount int = 0;

Declare TranCreateLPayment VARCHAR(20);  
Declare BankID int = 0	;
declare myrec record;
declare retid int = 0;
begin

	Select   
	TrsO.ID as ParmID
	,Treasury_ID as ParmTreasuryID
--	,TreasuryLedger_ID as ParmTreasuryAccountID
	,case when COALESCE(TreasuryLedger_ID,0)=0 then (Select ledger_ID From gl_treasuriesaccounts Where treasury_id = Treasury_ID ) Else TreasuryLedger_ID end  as ParmTreasuryAccountID

	,TreasuryCenter1_ID as ParmTreasuryCostCenter1ID
	,TreasuryCenter2_ID as ParmTreasuryCostCenter2ID
	,TreasuryCenter3_ID as ParmTreasuryCostCenter3ID
	,TreasuryCenter4_ID as ParmTreasuryCostCenter4ID
	,luPD.id as ParmPaymentDirectionActID
	,luPD.keyid as ParmPaymentDirectionID
	,PM.id as ParmDefaultPayMethodID
	--,DefaultPayMethod_ID as ParmDefaultPayMethodID
	--,RefSourceRecID as ParmRefSourceRecID
	--,RefSourceObjectName as ParmRefSourceObjectName
	,OrderDate as ParmOrderDate
	,ABS(Amount) as ParmAmount
	,TrsO.Currency_ID as ParmCurrencyID
	,TrsO.EngDesc as ParmEngDesc
	,TrsO.ArbDesc as ParmArbDesc
	,Lu.ID as ParmAccountTypeAct
	,Lu.keyID as ParmAccountType
	,trso.TransType_ID as ParmTransTypeID
	,Account as ParmAccountID
	--,FiscalYearPeriodID as ParmFiscalYearPeriodID
	,CostCenter1_ID as ParmCostCenter1ID
	,CostCenter2_ID as ParmCostCenter2ID
	,CostCenter3_ID as ParmCostCenter3ID
	,CostCenter4_ID as ParmCostCenter4ID
	,ApprovalDate as ParmApprovalDate
	,ApprovalBy_ID as ParmApprovalByID
	--,ReceiptID as ParmReceiptID
	,FinishDate as ParmFinishDate
	,IsFinish as ParmIsFinish
	--,RefPaymentID as ParmRefPaymentID
	--,TrsO.CompanyID as ParmCompanyID
	--,TrsO.Remarks as ParmRemarks
	--,Trso.RegUserID  as ParmRegUserID
	--,PM.Code as ParmPayCode
	,COALESCE(PM.Engname ,'') as ParmPayEngDesc	
	,COALESCE(PM.ArbName,'') as ParmPayArbDesc	
	,COALESCE(PM.IsCash,false) as ParmIsCash	
	,COALESCE(PM.IsCheck,false) as ParmIsCheck	
	,COALESCE(PM.IsCreditCard,false) as ParmIsCreditCard	
	,COALESCE(PM.ISCredit,false) as ParmIsCredit	
	into myrec
 From gl_TreasuriesOrders  as TrsO
 left Join gl_Ledger L on L.ID = TrsO.TreasuryLedger_ID 
 inner join gl_TransTypes TT On TT.ID = TrsO.Transtype_ID
 inner Join sy_PaymentsMethods PM On PM.ID = TT.PaymentMethod_ID 
 inner Join sy_lookup lu on lu.id = trsO.AccountType_ID
 inner Join sy_lookup luPD on luPD.id = TT.PaymentDirection_ID

 Where TrsO.ID = TreasuryOrderID
 And COALESCE(ApprovalBy_ID ,0) = 0
 And ApprovalDate is null
 And COALESCE(RefPaymentID ,0)=0 
limit 1;

	PaymentDate= myrec.ParmOrderDate;

	IF myrec.ParmAccountType = 90001 then
		 ModuleCode = 'GL';
	elseIF myrec.ParmAccountType = 90002 then
		ModuleCode = 'AP';
	elseIF myrec.ParmAccountType = 90003 then
		ModuleCode = 'AR';
	end if;
	
	
	FiscalYearPeriodID=(SELECT * FROM  sy_GetFiscalYearPeriodID( PaymentDate ,ModuleCode));
	if FiscalYearPeriodID =0 then
		RAISE NOTICE '[%]','Fiscal Period Not valid Check Payment Date =' || PaymentDate || ' - FYP = ' || FiscalYearPeriodID || ' - Module =' || ModuleCode;	
	end if ;

	LedgerAccountTypeID=(Select id from sy_lookup where keyid = 90001 limit 1);
	
	ParmRegUserID = LoginUserid;-- (select usesysid from pg_user where usename = CURRENT_USER);
	if COALESCE(myrec.ParmPaymentDirectionID,0) = 90004 then
		SignTreasuryAccount = -1;
		EngDesc = ' Payment Voucher ';
		ArbDesc = ' سند صرف ';
		--Select  ID into BankID from bnk_Banks Where PayOutLedgerID = myrec.ParmTreasuryAccountID ;
	elseif COALESCE(myrec.ParmPaymentDirectionID,0) = 90005 then
		SignTreasuryAccount = 1;
		EngDesc = ' Receipt Voucher ';
		ArbDesc = ' سند قبض ';
		--Select  ID into BankID from bnk_Banks Where CollectInLedgerID  = myrec.ParmTreasuryAccountID ;
	else
		SignTreasuryAccount = 0;
		EngDesc = '';
		ArbDesc = '';
		BankID= 0;
	end if;
	--Select EngDesc || ' ' ||   ParmPayEngDesc || ' ' || ' Ref Order = ' || Cast(TreasuryOrderID As varchar(30)) || ' ' || ParmEngDesc into EngDesc;
	--Select  ArbDesc || ' ' ||   ParmPayArbDesc || ' ' || ' مرجع  = ' || Cast(TreasuryOrderID As varchar(30)) || ' ' || ParmArbDesc into ArbDesc;
	EngDesc =  EngDesc || ' ' ||   ParmPayEngDesc || ' ' || ' Ref Order = ' || Cast(TreasuryOrderID As varchar(30)) || ' ' || ParmEngDesc ;
	ArbDesc = ArbDesc || ' ' ||   ParmPayArbDesc || ' ' || ' مرجع  = ' || Cast(TreasuryOrderID As varchar(30)) || ' ' || ParmArbDesc ;
------Ledger
		
		IF myrec.ParmAccountType = 90001 then

			AccountLedgerID = (Select  COALESCE(LC.glLedger ,0)    As glLedgerID 
			from gl_Ledger L
			Inner join gl_LedgersClasses LC On LC.ID = L.LedgerClass_ID 
			Where  L.ID = myrec.ParmAccountID) ;

			

			
			IF COALESCE(SignTreasuryAccount,0) <> 0 And  COALESCE(myrec.ParmTreasuryAccountID,0) <> 0  And COALESCE(AccountLedgerID,0) <> 0  And FiscalYearPeriodID <> 0 then
				--start TRANSACTION ;  
					
------===== Insert Payment Head
					
					Insert Into gl_ledgerPayments 
					(TransType_ID			,Number		,PaymentDate	,Remarks	,Ledger_ID		
					,CostCenter1_ID		,CostCenter2_ID		,CostCenter3_ID		,CostCenter4_ID		,FiscalYearPeriod ,created_by_ID ,TreasuryOrder_ID
					,Amount ,Currency_ID ,CurrencyRate ,Status_ID ,PaymentDirection_ID ,paymentmethod_ID ,isposted 
					) 

					Select myrec.ParmTransTypeID , nextval(pg_get_serial_sequence('gl_ledgerpayments', 'id')) Number ,PaymentDate  ,'' Remarks	,myrec.ParmAccountID 
					,myrec.ParmCostCenter1ID ,myrec.ParmCostCenter2ID	,myrec.ParmCostCenter3ID ,myrec.ParmCostCenter4ID ,FiscalYearPeriodID ,ParmRegUserID ,TreasuryOrderID 
					,myrec.ParmAmount , myrec.ParmCurrencyID , 1 CurrencyRate ,PaymentStatusID ,myrec.ParmPaymentDirectionActID , myrec.ParmDefaultPayMethodID, False returning id into retid;
					
					RAISE NOTICE '[%]', retid;

					----- First Side
					Insert Into gl_ledgerPaymentsLine 
					(ledgerPayment_ID , ledger_id, CostCenter1_ID , CostCenter2_ID ,CostCenter3_ID ,CostCenter4_ID 
					, Amount , AmountFC  
					, Rank , EngDesc ,ArbDesc   ,AccountType_id ,Account_ID )
					Select 
					retid , myrec.ParmTreasuryAccountID,	myrec.ParmCostCenter1ID ,myrec.ParmCostCenter2ID	,myrec.ParmCostCenter3ID ,myrec.ParmCostCenter4ID 
					,myrec.ParmAmount  * SignTreasuryAccount As Amount  ,myrec.ParmAmount  * SignTreasuryAccount As AmountFC   
					,Case When SignTreasuryAccount > 0  Then 1 Else 2 End  Rank , EngDesc , ArbDesc   , myrec.ParmAccountTypeAct As AccountType , myrec.ParmTreasuryAccountID;

					----- Second Side
					Insert Into gl_LedgerPaymentsLine 
					(ledgerPayment_ID ,ledger_id , CostCenter1_ID , CostCenter2_ID ,CostCenter3_ID ,CostCenter4_ID 
					, Amount , AmountFC  
					, Rank , EngDesc ,ArbDesc   ,AccountType_id ,Account_ID )
					Select 
					retid  , myrec.ParmAccountID,myrec.ParmCostCenter1ID ,myrec.ParmCostCenter2ID	,myrec.ParmCostCenter3ID ,myrec.ParmCostCenter4ID 
					,myrec.ParmAmount  * SignTreasuryAccount * -1 As Amount ,myrec.ParmAmount  * SignTreasuryAccount * -1 As AmountFC 
					,Case When (SignTreasuryAccount * -1 ) > 0  Then 1 Else 2 End  Rank , EngDesc , ArbDesc   , myrec.ParmAccountTypeAct As AccountType , AccountLedgerID;

--					IF myrec.ParmIsCash = true Then
--						Begin
--							Insert into gl_LedgerPaymentHeadCash 
--								(ledgerPaymentID ,CurrencyID ,CurrencyRate ,Amount ,AmountFC )
--							Select 
--								PaymentID ,ParmCurrencyID , 1 As Rate
--								,ParmAmount  * SignTreasuryAccount * -1 As Amount ,ParmAmount  * SignTreasuryAccount * -1 As AmountFC ;
--						End;
--					end if;
					IF myrec.ParmIsCheck = true then
						if COALESCE(BankID ,0) = 0 then
							RAISE notice 'Error Check Bank Account Setting' ;  
						End if;

						Insert into gl_LedgerPaymentHeadCheck 
							(ledgerPaymentID, BankID, CheckDate, CheckNumber ,Description ,CurrencyID  ,CurrencyRate ,Amount ,AmountFC )
						Select 
							PaymentID , BankID BankID , Null CheckDate ,'' CheckNumber , EngDesc,  ParmCurrencyID , 1 As Rate
							,ParmAmount  * SignTreasuryAccount * -1 As Amount ,ParmAmount  * SignTreasuryAccount * -1 As AmountFC ;
					End if;

					IF myrec.ParmIsCreditCard = true then
						Insert into gl_LedgerPaymentHeadCreditCard 
							(ledgerPaymentID, HolderName , Number ,ExpireDate  ,ApprovalNumber ,CreditCardType ,CurrencyID   ,ExchangeRate  ,Amount ,AmountFC )
						Select 
							PaymentID  ,'' HolderName ,'' Number ,Null ExpireDate  ,'' ApprovalNumber ,0 CreditCardType  ,  ParmCurrencyID , 1 As Rate
							,ParmAmount  * SignTreasuryAccount * -1 As Amount ,ParmAmount  * SignTreasuryAccount * -1 As AmountFC ;
					End if;

					Update gl_TreasuriesOrders  Set ApprovalDate = current_date , ApprovalBy_id = ParmRegUserID ,RefPaymentID = PaymentID  Where ID = 	TreasuryOrderID;

					--COMMIT;
					
			End if;
		----- Vendor
		elseIF myrec.ParmAccountType = 90002 then
			Select Case When COALESCE(V.APLedgerID,0) = 0 Then COALESCE(VC.ApLedgerID ,0) Else V.APLedgerID End   As APLedgerID into AccountLedgerID
			from gl_Vendors V
			Inner join gl_VendorsClasses VC On VC.ID = V.VendorClassID 
			Where  V.ID = ParmAccountID ;
				
			IF COALESCE(SignTreasuryAccount,0) <> 0 And  COALESCE(ParmTreasuryAccountID,0) <> 0  And COALESCE(AccountLedgerID,0) <> 0  And FiscalYearPeriodID <> 0 then
			Begin
				start TRANSACTION ;  
					------===== Insert Payment Head

					Insert Into gl_vendorPayments 
					(TransType_ID			,Number		,PaymentDate	,Remarks	,Vendor_ID		
					,CostCenter1_ID		,CostCenter2_ID		,CostCenter3_ID		,CostCenter4_ID		,FiscalYearPeriod ,created_by_ID ,TreasuryOrder_ID
					,Amount ,Currency_ID ,CurrencyRate ,Status_ID ,PaymentDirection_ID ,paymentmethod_ID ,isposted 
					) 

					Select ParmTransTypeID , 0 Number ,PaymentDate  ,Year(ParmOrderDate)	,'' Remarks	,ParmAccountID 
					,ParmCostCenter1ID ,ParmCostCenter2ID	,ParmCostCenter3ID ,ParmCostCenter4ID ,FiscalYearPeriodID ,ParmRegUserID ,TreasuryOrderID 
					,ParmAmount , ParmCurrencyID , 1 CurrencyRate ,PaymentStatusID ,ParmPaymentDirectionID , myrec.ParmDefaultPayMethodID,False;
						

					----- First Side
					Insert Into gl_ledgerPaymentsLine 
					(ledgerPaymentID  , CostCenter1ID , CostCenter2ID ,CostCenter3ID ,CostCenter4ID 
					, Amount , AmountFC  
					, Rank , EngDesc ,ArbDesc ,Remarks ,AccountType ,AccountID )
					Select 
					PaymentID  ,ParmCostCenter1ID ,ParmCostCenter2ID	,ParmCostCenter3ID ,ParmCostCenter4ID 
					,ParmAmount  * SignTreasuryAccount As Amount  ,ParmAmount  * SignTreasuryAccount As AmountFC   
					,Case When SignTreasuryAccount > 0  Then 1 Else 2 End  Rank , EngDesc , ArbDesc  , '' Remarks  , 90001 As AccountType , ParmTreasuryAccountID;

					----- Second Side
					Insert Into gl_LedgerPaymentsLine 
					(ledgerPaymentID  , CostCenter1ID , CostCenter2ID ,CostCenter3ID ,CostCenter4ID 
					, Amount , AmountFC  
					, Rank , EngDesc ,ArbDesc ,Remarks ,AccountType ,AccountID )
					Select 
					PaymentID  ,ParmCostCenter1ID ,ParmCostCenter2ID	,ParmCostCenter3ID ,ParmCostCenter4ID 
					,ParmAmount  * SignTreasuryAccount * -1 As Amount ,ParmAmount  * SignTreasuryAccount * -1 As AmountFC 
					,Case When (SignTreasuryAccount * -1 ) > 0  Then 1 Else 2 End  Rank , EngDesc , ArbDesc  , '' Remarks , 90001 As AccountType , AccountLedgerID;

					IF ParmIsCash = 1 Then
						Begin
							Insert into gl_LedgerPaymentHeadCash 
								(ledgerPaymentID ,CurrencyID ,CurrencyRate ,Amount ,AmountFC )
							Select 
								PaymentID ,ParmCurrencyID , 1 As Rate
								,ParmAmount  * SignTreasuryAccount * -1 As Amount ,ParmAmount  * SignTreasuryAccount * -1 As AmountFC ;
						End;
					end if;
					IF ParmIsCheck = 1 then
						if COALESCE(BankID ,0) = 0 then
							RAISE notice 'Error Check Bank Account Setting' ;  
						End if;

						Insert into gl_LedgerPaymentHeadCheck 
							(ledgerPaymentID, BankID, CheckDate, CheckNumber ,Description ,CurrencyID  ,CurrencyRate ,Amount ,AmountFC )
						Select 
							PaymentID , BankID BankID , Null CheckDate ,'' CheckNumber , EngDesc,  ParmCurrencyID , 1 As Rate
							,ParmAmount  * SignTreasuryAccount * -1 As Amount ,ParmAmount  * SignTreasuryAccount * -1 As AmountFC ;
					End if;

					IF ParmIsCreditCard = 1 then
						Insert into gl_LedgerPaymentHeadCreditCard 
							(ledgerPaymentID, HolderName , Number ,ExpireDate  ,ApprovalNumber ,CreditCardType ,CurrencyID   ,ExchangeRate  ,Amount ,AmountFC )
						Select 
							PaymentID  ,'' HolderName ,'' Number ,Null ExpireDate  ,'' ApprovalNumber ,0 CreditCardType  ,  ParmCurrencyID , 1 As Rate
							,ParmAmount  * SignTreasuryAccount * -1 As Amount ,ParmAmount  * SignTreasuryAccount * -1 As AmountFC ;
					End if;

					Update gl_TreasuriesOrders  Set ApprovalDate = Getdate() , ApprovalByID = ParmRegUserID ,RefPaymentID = PaymentID  Where ID = 	TreasuryOrderID;

					COMMIT;

				EXCEPTION WHEN OTHERS THEN

					Rollback ;
					SELECT  
						ERROR_NUMBER() AS ErrorNumber  
						,ERROR_SEVERITY() AS ErrorSeverity  
						,ERROR_STATE() AS ErrorState  
						,ERROR_PROCEDURE() AS ErrorProcedure  
						,ERROR_LINE() AS ErrorLine  
						,ERROR_MESSAGE() AS ErrorMessage;  
						raise;					
				end;
			End if;
		
		------- Customer
			
		elseIF myrec.ParmAccountType = 90003 then
			
			AccountLedgerID = (Select  COALESCE(CC.arLedger_id ,0)    As arLedgerID 
			from ar_Customers C
			Inner join ar_CustomersClasses CC On CC.ID = C.customerclass_ID 
			Where  C.ID = myrec.ParmAccountID); 

			IF COALESCE(SignTreasuryAccount,0) <> 0 And  COALESCE(myrec.ParmTreasuryAccountID,0) <> 0  And COALESCE(AccountLedgerID,0) <> 0  And FiscalYearPeriodID <> 0 then
				--start TRANSACTION ;  
				RAISE NOTICE '[%]', 'ffff';		
------===== Insert Payment Head
					
					Insert Into ar_customersPayments 
					(TransType_ID			,Number		,PaymentDate	,Remarks	,customer_ID		
					,CostCenter1_ID		,CostCenter2_ID		,CostCenter3_ID		,CostCenter4_ID		,FiscalYearPeriod ,created_by_ID ,TreasuryOrder_ID
					,Amount ,Currency_ID ,CurrencyRate ,Status_ID ,PaymentDirection_ID ,paymentmethod_ID ,isposted 
					) 

					Select myrec.ParmTransTypeID , nextval(pg_get_serial_sequence('ar_customerspayments', 'id')) Number ,PaymentDate  ,'' Remarks	,myrec.ParmAccountID 
					,myrec.ParmCostCenter1ID ,myrec.ParmCostCenter2ID	,myrec.ParmCostCenter3ID ,myrec.ParmCostCenter4ID ,FiscalYearPeriodID ,ParmRegUserID ,TreasuryOrderID 
					,myrec.ParmAmount , myrec.ParmCurrencyID , 1 CurrencyRate ,PaymentStatusID ,myrec.ParmPaymentDirectionActID , myrec.ParmDefaultPayMethodID, False returning id into retid;
					
					RAISE NOTICE '[%]', retid;

					----- First Side
					Insert Into ar_customersPaymentsLine 
					(customerPayment_ID ,accountType_id ,ledger_ID --, customer_id
					 , CostCenter1_ID , CostCenter2_ID ,CostCenter3_ID ,CostCenter4_ID 
					, Amount , AmountFC  , Rank , EngDesc ,ArbDesc    )
					Select 
					retid, ledgerAccountTypeid As AccountType , myrec.ParmTreasuryAccountID --, myrec.ParmTreasuryAccountID
					,myrec.ParmCostCenter1ID ,myrec.ParmCostCenter2ID	,myrec.ParmCostCenter3ID ,myrec.ParmCostCenter4ID 
					,myrec.ParmAmount  * SignTreasuryAccount As Amount  ,myrec.ParmAmount  * SignTreasuryAccount As AmountFC   
					,Case When SignTreasuryAccount > 0  Then 1 Else 2 End  Rank , EngDesc , ArbDesc   
					;

					----- Second Side
					Insert Into ar_customersPaymentsLine 
					(customerPayment_ID ,accountType_id ,ledger_ID,customer_id 
					 , CostCenter1_ID , CostCenter2_ID ,CostCenter3_ID ,CostCenter4_ID 
					, Amount , AmountFC  
					, Rank , EngDesc ,ArbDesc    )
					Select 
					retid , myrec.ParmAccountTypeAct As AccountType , AccountLedgerID , myrec.ParmAccountID
					,myrec.ParmCostCenter1ID ,myrec.ParmCostCenter2ID	,myrec.ParmCostCenter3ID ,myrec.ParmCostCenter4ID 
					,myrec.ParmAmount  * SignTreasuryAccount * -1 As Amount ,myrec.ParmAmount  * SignTreasuryAccount * -1 As AmountFC 
					,Case When (SignTreasuryAccount * -1 ) > 0  Then 1 Else 2 End  Rank , EngDesc , ArbDesc   
					;

--					IF myrec.ParmIsCash = true Then
--						Begin
--							Insert into gl_LedgerPaymentHeadCash 
--								(ledgerPaymentID ,CurrencyID ,CurrencyRate ,Amount ,AmountFC )
--							Select 
--								PaymentID ,ParmCurrencyID , 1 As Rate
--								,ParmAmount  * SignTreasuryAccount * -1 As Amount ,ParmAmount  * SignTreasuryAccount * -1 As AmountFC ;
--						End;
--					end if;
					IF myrec.ParmIsCheck = true then
						if COALESCE(BankID ,0) = 0 then
							RAISE notice 'Error Check Bank Account Setting' ;  
						End if;

						Insert into gl_LedgerPaymentHeadCheck 
							(ledgerPaymentID, BankID, CheckDate, CheckNumber ,Description ,CurrencyID  ,CurrencyRate ,Amount ,AmountFC )
						Select 
							PaymentID , BankID BankID , Null CheckDate ,'' CheckNumber , EngDesc,  ParmCurrencyID , 1 As Rate
							,ParmAmount  * SignTreasuryAccount * -1 As Amount ,ParmAmount  * SignTreasuryAccount * -1 As AmountFC ;
					End if;

					IF myrec.ParmIsCreditCard = true then
						Insert into gl_LedgerPaymentHeadCreditCard 
							(ledgerPaymentID, HolderName , Number ,ExpireDate  ,ApprovalNumber ,CreditCardType ,CurrencyID   ,ExchangeRate  ,Amount ,AmountFC )
						Select 
							PaymentID  ,'' HolderName ,'' Number ,Null ExpireDate  ,'' ApprovalNumber ,0 CreditCardType  ,  ParmCurrencyID , 1 As Rate
							,ParmAmount  * SignTreasuryAccount * -1 As Amount ,ParmAmount  * SignTreasuryAccount * -1 As AmountFC ;
					End if;

					Update gl_TreasuriesOrders  Set ApprovalDate = current_date , ApprovalBy_id = ParmRegUserID ,RefPaymentID = PaymentID  Where ID = 	TreasuryOrderID;

					--COMMIT;
					
			End if;

		end if;
		 
end;
$$;


ALTER PROCEDURE public.gl_treasuriesordersapproval(treasuryorderid integer, loginuserid integer) OWNER TO postgres;

--
-- Name: in_createoperationsjour(integer, integer); Type: PROCEDURE; Schema: public; Owner: postgres
--

CREATE PROCEDURE public.in_createoperationsjour(paramoperationid integer, loginuserid integer DEFAULT 0)
    LANGUAGE plpgsql
    AS $$
--Select  varDecimalFraction = Cur.DecimalFraction   From in_Operations OH
	--inner join sys_Currencies Cur on Cur.id = OH.CurrencyID 
	--Where OH.ID = paramOperationID

Declare 
	varMSGText		varchar(512) = '' ;
   	varDecimalFraction	  int = 2;
	   
	varEngDesc	  varchar(4000)='';
	varArbDesc	  varchar(4000)='';

	varJourDate			date ;
	FiscalYearPeriodID	int= 0 ;
	ModuleCode			varchar(20) = '';

	varJourID		int = 0;
    StockCountPostOptionsID	 int = 0 ;

	varOldInventoryLedgerValue	   money = 0 ;
	varStckCountValueValue	   money = 0 ;

	newfcsTransTypeID integer;
	varTaxTransTypeID  integer;
	taxDueDate			date ;

	MainLedger4Account integer;
	CurrentAccountID integer;
	LedgerAccountTypeKeyID integer;
	CurrentAccountTypeID integer;
	CurrentAccountTypeKeyID integer;

	op_rec		record;
	locInfo_Rec record;

	invoice_AccTypeKeyID_debit			int = 0;
	invoice_AccTypeKeyID_credit			int = 0;
	invoice_debitacc		int = 0;
	invoice_creditacc		int = 0;
	Invoice_DebitAmount		numeric(30,12);
	Invoice_CreditAmount		numeric(30,12);
	Invoice_MainLedger4AccountDebit		integer;
	Invoice_MainLedger4AccountCredit	integer;

	disc1_AccTypeKeyID_debit			int = 0;
	disc1_AccTypeKeyID_credit			int = 0;
	disc1_debitacc		int = 0;
	disc1_creditacc		int = 0;
	disc1_DebitAmount		numeric(30,12);
	disc1_CreditAmount		numeric(30,12);
	disc1_MainLedger4AccountDebit		integer;
	disc1_MainLedger4AccountCredit	integer;

	disc2_AccTypeKeyID_debit			int = 0;
	disc2_AccTypeKeyID_credit			int = 0;
	disc2_debitacc		int = 0;
	disc2_creditacc		int = 0;
	disc2_DebitAmount		numeric(30,12);
	disc2_CreditAmount		numeric(30,12);
	disc2_MainLedger4AccountDebit		integer;
	disc2_MainLedger4AccountCredit	integer;

	disc3_AccTypeKeyID_debit			int = 0;
	disc3_AccTypeKeyID_credit			int = 0;
	disc3_debitacc		int = 0;
	disc3_creditacc		int = 0;
	disc3_DebitAmount		numeric(30,12);
	disc3_CreditAmount		numeric(30,12);
	disc3_MainLedger4AccountDebit		integer;
	disc3_MainLedger4AccountCredit	integer;

	tax_AccTypeKeyID_debit			int = 0;
	tax_AccTypeKeyID_credit			int = 0;
	tax_debitacc		int = 0;
	tax_creditacc		int = 0;
	tax_amount		numeric(30,12);

	expense_AccTypeKeyID_debit			int = 0;
	expense_AccTypeKeyID_credit			int = 0;
	expense_debitacc		int = 0;
	expense_creditacc		int = 0;
	expense_amount		numeric(30,12);
	signamount			int =1;

	diffamount	numeric(30,12);

Begin

	Select 
		 COALESCE(Customer_ID ,0) CustomerID 
		,COALESCE(Vendor_ID ,0) VendorID 
		,ot.code otcode
		,LU.keyID  OperationKindID
		,cast( COALESCE( LU.Value,'0') as int) OperationSign --, ITT.Sign ItemTransTypeSign 
		,LU.code kindcode
		,LU.engname kindengname
		,LU.arbname kindarbname
		,COALESCE(	TransType_id,0) fcsTransTypeID
		,COALESCE(OT.ID,0)	OperationTypeID
		,COALESCE(Status_ID ,0) OPCurrStatusID
		,COALESCE(OH.invLocation_ID,0) CurLocationID
		,COALESCE(destinationinvlocation_ID ,0) DstLocationID
		,COALESCE(GrossAmount ,0) GrossAmount
		,COALESCE(NetAmount ,0) NetAmount
		,COALESCE(TaxAmount  ,0) TotalTaxAmount
		,COALESCE(discamt1  ,0) Disc1Amount
		,COALESCE(discamt2 ,0) Disc2Amount
		,COALESCE(discamt3 ,0) Disc3Amount
		,Case When COALESCE((Select APLedger_ID from ap_vendors Where ID = Vendor_ID ),0) = 0 Then  COALESCE((Select APLedger_ID from ap_VendorsClasses Where ID = (Select VendorClass_ID From ap_Vendors Where ID = Vendor_ID)),0) Else COALESCE((Select APLedger_ID from ap_vendors Where ID = Vendor_ID ),0) End LedAPID
		,Case When COALESCE((Select ARLedger_ID from ar_Customers Where ID = Customer_ID ),0) = 0 Then  COALESCE((Select ARLedger_ID from ar_CustomersClasses Where ID = (Select CustomerClass_ID From ar_Customers Where ID = Customer_ID)),0) Else COALESCE((Select ARLedger_ID from ar_Customers Where ID = Customer_ID ),0)  End LedARID
		,OH.Number  OperationNumber
		,OperationDate  OperationDate
 		,loginuserid  RegUserID
		,Current_date RegDate
		--,ITH.ID ItemTransHeadID
		,0 ItemTransHeadID

		,OH.Currency_ID  CurrencyID
		,1 CurrencyRate--,COALESCE(OH.CurrencyExchange ,1) CurrencyRate
		,COALESCE(OT.ledgerdisc1_id,0) Disc1LedgerID
		,COALESCE(OT.ledgerdisc2_id,0) Disc2LedgerID
		,COALESCE(OT.ledgerdisc3_id,0) Disc3LedgerID
		--,COALESCE(TaxTransTypeID ,0) TaxTransTypeID
		--,COALESCE(StockCountPrepareRefID ,0) StockCountPrepareRefID
		--,COALESCE(OH.RefObjectName ,'') RefObjectName
		--,COALESCE(OH.RefRecordID ,0) RefRecordID
		,COALESCE(ledgergoodsonway_id ,0) ledgergoodsonwayid
		into op_rec
		from inv_Operations OH
		Inner join inv_OperationsTypes OT On OT.ID = OH.OperationType_ID
		--Inner join inv_ItemsTrans ITH On ITH.Operation_id = OH.ID
		Inner Join sy_LookUp LU On LU.ID = OT.OperationKind_id 
		Where OH.ID = paramOperationID;

	If  op_rec.CurLocationID = 0 Then ----- No Location 		  
		varMSGText =   'Error Please Check Location You have to Select Location Before Post Or Operation Not inserted Into Inventory Trans' ;
		SELECT RaiseError(varMSGText);
	End if ;

	--create Tax Trans In GL 
	if not exists(Select * from gl_transtypes Where istaxtrans = true ) then
		insert into gl_transtypes (code , Engname , arbname , alloweditdate,alloweditnumber ,ismanual,transkind_id,remarks 
		,isreceipt,iscash,ischeck,iscreditcard,iscollectorneeded,iscashdisc,useref1,useref2,istaxtrans,isautoposttogl )
		values( 'AUTO-TAX'  ,'Tax Trans','حركة الضريبة' ,false ,false,false,(select id from sy_lookup where keyid =53 limit 1),'This is Trans Created automatic from Operation' 
		,false,false,false,false,false,false,false,false,True,false	)
 		returning id  into varTaxTransTypeID; 
		
	else
		Select id into varTaxTransTypeID from gl_transtypes Where istaxtrans = true ;
	end if;

	varJourDate = current_Date ;
	RAISE NOTICE 'value of a : %',  op_rec.OperationKindID;
	
------======  Next Part to Get Payment Date And Fiscal Period According date 
	IF op_rec.OperationKindID = 0 Then
		ModuleCode = '';
	ElseIF op_rec.OperationKindID In (3206 , 3207 ,3208 ,3209 )  then ----  Purchase	مشتريات   
		ModuleCode = 'AP';
	ElseIF op_rec.OperationKindID In (3202 , 3203 ,3204 ,3205  )  then ----  Sales	مبيعات   
		ModuleCode = 'AR';
	ElseIF op_rec.OperationKindID In (3210 , 3211 ,3212 ,3213 ,3214 ,3215 ,3216 ,3217 )  Then ----  Inventory	مخزون   
		ModuleCode = 'MMS';
	Else
		ModuleCode = '';
	End If ;	    

	If ModuleCode = '' Then
		varMSGText =   'Error Please Check Operation Kind Related to Current Operation Type Or Unkown Kind';
		SELECT RaiseError(varMSGText);
	End if ;

	Select fyp.id 
	from sy_fiscalyears fy 
	inner join sy_fiscalyearsperiods fyp on fy.id = fiscalyear_id
	inner join sy_fiscalyearsperiodsmodules fypm on fypm.fiscalyearperiod_id = fyp.id
	inner join sy_modules m on m.id= fypm.module_id
	where m.code = ModuleCode
	and varJourDate between fyp.fromdate and fyp.todate  into FiscalYearPeriodID	;		

------======  End Next Part to Get Payment Date And Fiscal Period According date 

	Create  TEMPORARY Table TempOJL 
	(
		ID	SERIAL NOT null,  PartName  varchar(100),  PartRank	int	   ,  Rank	int	   ,  AccountType	int	   ,  AccountID	int   ,  LedgerID	int   
		,  CostCenter1ID	int	   ,  CostCenter2ID	int	   ,  CostCenter3ID	int	   ,  CostCenter4ID	int	   ,  EngDesc	varchar(512)	   ,  ArbDesc	varchar(512)	   ,  Amount	money	   
		,  AmountFC	money	   ,  Qty	real	   ,  DebitAmount	money   ,  CreditAmount	money   ,  Reverse	int   ,  CurrencyID	int   ,  CurrencyRate	real	   ,  IsReverse	boolean
	);

	Select  COALESCE(InvLedger_ID,0)  varInventoryLedgerID , COALESCE(CostSalesLedger_ID ,0)  varCostOfSalesLedgerID
		, COALESCE(slsLedger_ID,0) varslsLedgerID , COALESCE(rslsLedger_ID,0) varrslsLedgerID 
		, COALESCE(PurLedger_ID,0) varPurchasesLedgerID ,COALESCE(SettleLedger_ID,0) InventorySettlementLedgerID
		, COALESCE(RPurLedger_ID ,0) varRefundPurchasesLedgerID, COALESCE(CostCenter1_ID,0) varCostCenter1ID,COALESCE(CostCenter2_ID,0) varCostCenter2ID
		, COALESCE(CostCenter3_ID ,0)  varCostCenter3ID, COALESCE(CostCenter4_ID ,0) varCostCenter4ID
	into locInfo_Rec
	From inv_inventorieslocations 
	Where ID = op_rec.CurLocationID;
		

	LedgerAccountTypeKeyID = 90001 ;

	IF op_rec.OperationKindID = 3202  then  ---- cash sales
		MainLedger4Account = op_rec.LedARID ;
		CurrentAccountID = op_rec.CustomerID ;
		IF Exists( Select * from ar_CustomersJour Where Operation_id = paramOperationID ) Then
			varMSGText =   'Error The Operation it was Posted Before ';
			SELECT RaiseError(varMSGText);
		End if;

	   	If  op_rec.OPCurrStatusID <> (Select ID from sy_LookUp Where  keyid = 10003) then ------ Approved	موافق عليه   keyname = 'RecordStatus' 
			varMSGText =   'Error The Operation Not Approved You Have Make Approve Before Post ';
			SELECT RaiseError(varMSGText);
		End if;

		If MainLedger4Account = 0  then
			varMSGText =   'Error No Customer Selected please Select Account Receivable From Ledger Account';
			SELECT RaiseError(varMSGText);
		End if;
		CurrentAccountTypeKeyID = 90003 ;
		CurrentAccountTypeID = (Select ID From sy_LookUp where keyid = CurrentAccountTypeKeyID);

		varEngDesc	    = op_rec.kindengname  || ' - ' ||  ' Invoice Ref = ' || op_rec.OperationNumber ;
		varArbDesc	    = op_rec.kindarbname  || ' - ' ||  ' Invoice Ref = ' || op_rec.OperationNumber ;

		invoice_AccTypeKeyID_debit	= 90003 ;
		invoice_AccTypeKeyID_credit	= 90001;
		invoice_debitacc  = CurrentAccountID;
		invoice_creditacc = locInfo_Rec.varslsLedgerID ;
		Invoice_DebitAmount	=  ABS(op_rec.GrossAmount) ;
		Invoice_CreditAmount = ABS(op_rec.GrossAmount) * - 1 ;
		Invoice_MainLedger4AccountDebit	= op_rec.LedARID ;
		Invoice_MainLedger4AccountCredit = locInfo_Rec.varslsLedgerID	;

		disc1_AccTypeKeyID_debit	= 90001 ;
		disc1_AccTypeKeyID_credit	= 90003;
		disc1_debitacc	= op_rec.Disc1LedgerID;
		disc1_creditacc		= CurrentAccountID;
		disc1_DebitAmount	=  ABS(op_rec.Disc1Amount) ;
		disc1_CreditAmount = ABS(op_rec.Disc1Amount) * - 1 ;
		disc1_MainLedger4AccountDebit	= op_rec.LedARID ;
		disc1_MainLedger4AccountCredit = locInfo_Rec.varslsLedgerID	;

		disc2_AccTypeKeyID_debit	= 90001 ;
		disc2_AccTypeKeyID_credit	= 90003;
		disc2_debitacc	= op_rec.Disc2LedgerID;
		disc2_creditacc	 = CurrentAccountID;
		disc2_MainLedger4AccountDebit	= op_rec.LedARID ;
		disc2_MainLedger4AccountCredit = locInfo_Rec.varslsLedgerID	;
		

		disc3_AccTypeKeyID_debit	= 90001 ;
		disc3_AccTypeKeyID_credit	= 90003;
		disc3_debitacc	= op_rec.Disc3LedgerID;
		disc3_creditacc	 = CurrentAccountID;
		disc3_MainLedger4AccountDebit	= op_rec.LedARID ;
		disc3_MainLedger4AccountCredit = locInfo_Rec.varslsLedgerID	;
		

		--tax_AccTypeKeyID_debit	= 90003 ;
		--tax_AccTypeKeyID_credit	= 90001;
		--tax_debitacc	= op_rec.Disc3LedgerID;
		--tax_creditacc		int = CurrentAccountID;
		--tax_amount	= op_rec.Disc3Amount;

		--expense_AccTypeKeyID_debit	= 90003 ;
		--expense_AccTypeKeyID_credit	= 90001;
		--expense_debitacc	= op_rec.Disc3LedgerID;
		--expense_creditacc		int = CurrentAccountID;
