			PartName  ,  PartRank	,  Rank	,  AccountType	,  AccountID	,  LedgerID	
			,  EngDesc	,  ArbDesc	,  Amount	
			,  AmountFC	,  Qty	,  DebitAmount	,  CreditAmount	,  Reverse	,  CurrencyID	,  CurrencyRate	,  IsReverse	
		)
		
		-- Debit Side
		Select 'Invoice' As PartName  ,  1 PartRank	 ,1 Rank , invoice_AccTypeKeyID_debit , invoice_debitacc , Invoice_MainLedger4AccountDebit
				,   varEngDesc ,   varArbDesc , Invoice_DebitAmount 
				,	Invoice_DebitAmount  , 1 As Qty 
				,	Invoice_DebitAmount 
				,	0  CreditAmount 
				,   1 Reverse ,op_rec.CurrencyID , op_rec.CurrencyRate  , False IsReverse
		from inv_Operations OH
		Where OH.ID = paramOperationID

		Union All

		-- Credit Side
		Select 'Invoice' As PartName  ,  2 PartRank ,1 Rank,invoice_AccTypeKeyID_credit, invoice_creditacc , Invoice_MainLedger4AccountCredit
				,  varEngDesc ,  varArbDesc , Invoice_CreditAmount
				,  Invoice_CreditAmount  , 1 As Qty 
				,  0  DebitAmount 
				,  ABS(Invoice_CreditAmount) 
				,  1 Reverse ,op_rec.CurrencyID , op_rec.CurrencyRate  , False IsReverse
		from inv_Operations OH
		Where OH.ID = paramOperationID;

----======End Register Invoice Jour

--DISCOUNTS----====== Start Discount PartName
	IF op_rec.Disc1Amount <> 0 And  op_rec.Disc1LedgerID = 0  then
		varMSGText =   'Error No Account For Discount 1 Check Your Operation Discount Setting';
		SELECT RaiseError(varMSGText);  
	End if;

	IF op_rec.Disc1Amount <> 0 And  op_rec.Disc1LedgerID <> 0  then
		Insert Into TempOJL 
		(
		PartName  ,  PartRank	,  Rank	,  AccountType	,  AccountID	,  LedgerID	
		,  EngDesc	,  ArbDesc	,  Amount	
		,  AmountFC	,  Qty	,  DebitAmount	,  CreditAmount	,  Reverse	,  CurrencyID	,  CurrencyRate	,  IsReverse	
		)
		------ Debit Side
		Select 'Discount1' As PartName  ,  1 PartRank	,1 Rank ,disc1_AccTypeKeyID_debit , disc1_debitacc , disc1_debitacc
			, varEngDesc || ' - Discount 1' , varArbDesc  || ' - Discount 1'  ,  disc1_DebitAmount
			, disc1_DebitAmount  , 1 As Qty 
			, disc1_DebitAmount 
			, 0	  CreditAmount 
			,1 Reverse ,op_rec.CurrencyID , op_rec.CurrencyRate , false IsReverse
		Union All
		------ Credit Side
		Select 'Discount1' As PartName  ,  2 PartRank	,1 Rank , disc1_AccTypeKeyID_credit , disc1_creditacc,  disc1_MainLedger4AccountCredit
			, varEngDesc || ' - Discount 1' , varArbDesc  || ' - Discount 1' , disc1_CreditAmount 
			, disc1_CreditAmount  , 1 As Qty 
			, 0  DebitAmount 
			, ABS(disc1_CreditAmount) 
			,1 Reverse ,op_rec.CurrencyID , op_rec.CurrencyRate , false IsReverse;
	End if;

	IF op_rec.Disc2Amount <> 0 And  op_rec.Disc2LedgerID = 0 then
		varMSGText =   'Error No Account For Discount 2 Check Your Operation Discount Setting';
		SELECT RaiseError(varMSGText);  
	End if ;

	IF op_rec.Disc2Amount <> 0 And  op_rec.Disc2LedgerID <> 0  then
		Insert Into TempOJL 
		(
		PartName  ,  PartRank	,  Rank	,  AccountType	,  AccountID	,  LedgerID	
		,  EngDesc	,  ArbDesc	,  Amount	
		,  AmountFC	,  Qty	,  DebitAmount	,  CreditAmount	,  Reverse	,  CurrencyID	,  CurrencyRate	,  IsReverse	
		)
		------ Debit Side
		Select 'Discount2' As PartName  ,  1 PartRank	,1 Rank ,disc2_AccTypeKeyID_debit , disc1_debitacc , disc2_debitacc
			, varEngDesc || ' - Discount 2' , varArbDesc  || ' - Discount 2'  ,  disc2_DebitAmount
			, disc2_DebitAmount  , 1 As Qty 
			, disc2_DebitAmount 
			, 0	  CreditAmount 
			,1 Reverse ,op_rec.CurrencyID , op_rec.CurrencyRate , false IsReverse
		Union All
		------ Credit Side
		Select 'Discount2' As PartName  ,  2 PartRank	,1 Rank , disc2_AccTypeKeyID_credit , disc2_creditacc,  disc2_MainLedger4AccountCredit
			, varEngDesc || ' - Discount 2' , varArbDesc  || ' - Discount 2' , disc2_CreditAmount 
			, disc2_CreditAmount  , 1 As Qty 
			, 0  DebitAmount 
			, ABS(disc2_CreditAmount) 
			,1 Reverse ,op_rec.CurrencyID , op_rec.CurrencyRate , false IsReverse;
	End if;

	IF op_rec.Disc3Amount <> 0 And  op_rec.Disc3LedgerID = 0 then
		varMSGText =   'Error No Account For Discount 3 Check Your Operation Discount Setting' ;
		SELECT RaiseError(varMSGText);  
	End if;
	IF op_rec.Disc3Amount <> 0 And  op_rec.Disc3LedgerID <> 0  then
		Insert Into TempOJL 
		(
		PartName  ,  PartRank	,  Rank	,  AccountType	,  AccountID	,  LedgerID	
		,  EngDesc	,  ArbDesc	,  Amount	
		,  AmountFC	,  Qty	,  DebitAmount	,  CreditAmount	,  Reverse	,  CurrencyID	,  CurrencyRate	,  IsReverse	
		)
		------ Debit Side
		Select 'Discount3' As PartName  ,  1 PartRank	,1 Rank ,disc3_AccTypeKeyID_debit , disc3_debitacc , disc3_debitacc
			, varEngDesc || ' - Discount 3' , varArbDesc  || ' - Discount 3'  ,  disc3_DebitAmount
			, disc3_DebitAmount  , 1 As Qty 
			, disc3_DebitAmount 
			, 0	  CreditAmount 
			,1 Reverse ,op_rec.CurrencyID , op_rec.CurrencyRate , false IsReverse
		Union All
		------ Credit Side
		Select 'Discount3' As PartName  ,  2 PartRank	,1 Rank , disc3_AccTypeKeyID_credit , disc3_creditacc,  disc3_MainLedger4AccountCredit
			, varEngDesc || ' - Discount 3' , varArbDesc  || ' - Discount 3' , disc3_CreditAmount 
			, disc3_CreditAmount  , 1 As Qty 
			, 0  DebitAmount 
			, ABS(disc3_CreditAmount) 
			,1 Reverse ,op_rec.CurrencyID , op_rec.CurrencyRate , false IsReverse;
	End if;

	----====== End Discount PartName

--TAXES	----====== Start Tax PartName
	IF varTaxTransTypeID = 0 then
		varMSGText =   'Error Check Operation Type TaxTransType Not Selected' ;
		SELECT RaiseError(varMSGText);  
	End if;

	IF not exists(
		Select * from (
		Select Sum(linetotal) TaxBaseAmount, OD.Tax_ID , Sum(OD.TaxAmount) TaxAmount  ,TH.taxLedger_id  
		from inv_OperationsLine  OD
		Inner Join sy_Taxes TH On TH.ID = OD.tax_id 
		Where Operation_id = paramOperationID
		Group By OD.Tax_ID ,TH.Taxledger_ID

		Union All

		Select Sum(explinetotal) TaxBaseAmount, OD.expTax_ID , Sum(OD.expTaxAmount) TaxAmount  ,TH.Taxledger_ID  
		from inv_operationsexpensesline  OD
		Inner Join sy_Taxes TH On TH.ID = OD.expTax_ID 
		Where OD.Operation_id = paramOperationID
		Group By OD.expTax_ID ,TH.Taxledger_ID --, OD.expTaxPercent

		)AA
		Where COALESCE(taxLedger_id,0) <> 0

	) then
		varMSGText =   'Error No Account Tax Check Your Taxs Setting Or Tax Period Setting';
		SELECT RaiseError(varMSGText);  
						  
	End if;

	Insert into gl_TaxesTrans (TransType_ID ,SourceTableName ,SourceRecID ,TransDate 
			,Tax_ID ,TaxBaseAmount , TaxPercent ,TaxAmount ,Ledger_ID , DueDate ,Closed)

	Select  varTaxTransTypeID  ,'inv_Operations' as  SourceTableName ,paramOperationID As SourceRecID , op_rec.OperationDate  TransDate
		,OD.Tax_ID TaxID , Sum(linetotal) TaxBaseAmount ,OD.TaxPercent , -1 * ABS(Sum(OD.TaxAmount)) TaxAmount  ,TH.Taxledger_ID , taxDueDate ,False
	from inv_OperationsLine  OD
	Inner Join sy_Taxes TH On TH.ID = OD.Tax_ID 
	Where Operation_id = paramOperationID --56086
	Group By OD.Tax_ID ,TH.TaxLedger_ID ,OD.TaxPercent --,TPL.ToDate
	Having Sum(OD.TaxAmount) <> 0

	Union All

	Select  varTaxTransTypeID  ,'inv_operations' as  SourceTableName ,paramOperationID As SourceRecID , op_rec.OperationDate  TransDate
		,OD.expTax_ID TaxID , Sum(explinetotal) TaxBaseAmount ,OD.expTaxPercent , -1 * ABS(Sum(OD.expTaxAmount)) TaxAmount  ,TH.TaxLedger_ID ,taxDueDate ,False
	from inv_operationsexpensesline  OD
	Inner Join sy_Taxes TH On TH.ID = OD.expTax_ID 
	Where OD.Operation_id = paramOperationID
	Group By OD.expTax_ID ,TH.TaxLedger_ID ,OD.expTaxPercent 
	Having Sum(OD.expTaxAmount) <> 0 ;
	if   op_rec.OperationKindID = 3202 or op_rec.OperationKindID = 3204 or op_rec.OperationKindID = 3207 or op_rec.OperationKindID = 3209  then
		signamount = 1;
	else
		signamount = -1;
	end if ;
	Insert Into TempOJL 
	(
		PartName  ,  PartRank	,  Rank	,  AccountType	,  AccountID	,  LedgerID	
		--,  CostCenter1ID	,  CostCenter2ID	,  CostCenter3ID	,  CostCenter4ID	
		,  EngDesc	,  ArbDesc	,  Amount	
		,  AmountFC	,  Qty	,  DebitAmount	,  CreditAmount	,  Reverse	,  CurrencyID	,  CurrencyRate	,  IsReverse	
	)

	------ Debit Side
	Select 'Tax' As PartName  ,  1 PartRank	,1 Rank 
			, case when  op_rec.OperationKindID = 3202 or op_rec.OperationKindID = 3204 or op_rec.OperationKindID = 3207 or op_rec.OperationKindID = 3209 then    CurrentAccountTypeKeyID
				else LedgerAccountTypeKeyID End AccountTypeID 
				
			, case when  op_rec.OperationKindID = 3202 or op_rec.OperationKindID = 3204 or op_rec.OperationKindID = 3207 or op_rec.OperationKindID = 3209 then CurrentAccountID   
				else TH.TaxLedger_ID End AccountID 
				
			, case when  op_rec.OperationKindID = 3202 or op_rec.OperationKindID = 3204 or op_rec.OperationKindID = 3207 or op_rec.OperationKindID = 3209 then MainLedger4Account   
				else TH.TaxLedger_ID End mainLedger 

			, varEngDesc || ' - Tax ' , varArbDesc || ' - Tax' 

			, -1 * signamount * op_rec.OperationSign *   ABS(Sum(OD.TaxAmount)) Amount 
			, -1 * signamount * op_rec.OperationSign *   ABS(Sum(OD.TaxAmount)) AmountFC  , 1 As Qty 
			, case when -1 * signamount *  op_rec.OperationSign *  Abs(Sum(OD.TaxAmount)) >=0  then Abs(Sum(OD.TaxAmount)) Else 0 end  DebitAmount 
			, case when -1 * signamount *  op_rec.OperationSign *  Abs(Sum(OD.TaxAmount)) < 0  then   Abs(Sum(OD.TaxAmount)) Else 0 end  CreditAmount  
			,1 Reverse ,op_rec.CurrencyID , op_rec.CurrencyRate , false IsReverse

	from inv_OperationsLine  OD
	Inner Join sy_Taxes TH On TH.ID = OD.Tax_ID 
	Where Operation_id = paramOperationID --56086
	Group By OD.Tax_ID ,TH.TaxLedger_ID --,OD.TaxPercent

	Union All

	------ Credit Side
	Select 'Tax' As PartName  ,  2 PartRank	,1 Rank 
			, case when  op_rec.OperationKindID = 3202 or op_rec.OperationKindID = 3204 or op_rec.OperationKindID = 3207 or op_rec.OperationKindID = 3209 then LedgerAccountTypeKeyID   
				else CurrentAccountTypeKeyID End AccountTypeID 
				
			, case when  op_rec.OperationKindID = 3202 or op_rec.OperationKindID = 3204 or op_rec.OperationKindID = 3207 or op_rec.OperationKindID = 3209 then TH.TaxLedger_ID   
				else CurrentAccountID End AccountID 
				
			, case when  op_rec.OperationKindID = 3202 or op_rec.OperationKindID = 3204 or op_rec.OperationKindID = 3207 or op_rec.OperationKindID = 3209 then TH.TaxLedger_ID   
				else MainLedger4Account End mainLedger 

			, varEngDesc || ' - Tax ' , varArbDesc || ' - Tax' 
			,  signamount * op_rec.OperationSign *   ABS(op_rec.TotalTaxAmount) Amount 
			, signamount *  op_rec.OperationSign *   ABS(op_rec.TotalTaxAmount) AmountFC  , 1 As Qty 
			, case when  signamount * op_rec.OperationSign *  Abs(op_rec.TotalTaxAmount) >=0  then   Abs(op_rec.TotalTaxAmount) Else 0 end  DebitAmount 
			, case when  signamount *  op_rec.OperationSign *  Abs(op_rec.TotalTaxAmount) < 0  then   Abs(op_rec.TotalTaxAmount) Else 0 end  CreditAmount  
			,1 Reverse ,op_rec.CurrencyID , op_rec.CurrencyRate , false IsReverse

	from inv_OperationsLine  OD
	Inner Join sy_Taxes TH On TH.ID = OD.Tax_ID 
	Where Operation_id = paramOperationID --56086
	Group By OD.Tax_ID ,TH.TaxLedger_ID --,OD.TaxPercent

	Union All

	Select 'Tax' As PartName  ,  1 PartRank	,1 Rank 
			, case when  op_rec.OperationSign > 0 then LedgerAccountTypeKeyID  else CurrentAccountTypeKeyID End AccountTypeID 
			, case when  op_rec.OperationSign > 0 then TH.TaxLedger_ID  else CurrentAccountID end  AccountID
			, case when  op_rec.OperationSign > 0 then     TH.TaxLedger_ID else MainLedger4Account  end mainLedger
			, varEngDesc || ' - Expense Tax ' , varArbDesc || ' - Expense Tax' , op_rec.OperationSign *   ABS(Sum(OD.expTaxAmount)) Amount 
			, op_rec.OperationSign *   ABS(Sum(OD.expTaxAmount)) AmountFC  , 1 As Qty 
			, case when  op_rec.OperationSign *  Abs(Sum(OD.expTaxAmount)) >=0  then op_rec.OperationSign *  Abs(Sum(OD.expTaxAmount)) Else 0 end  DebitAmount 
			, case when  op_rec.OperationSign *  Abs(Sum(OD.expTaxAmount)) < 0  then op_rec.OperationSign *  Abs(Sum(OD.expTaxAmount)) Else 0 end  CreditAmount  
			,1 Reverse ,op_rec.CurrencyID , op_rec.CurrencyRate , false IsReverse

	from inv_OperationsExpensesLine  OD
	Inner Join sy_Taxes TH On TH.ID = OD.expTax_ID 
	Where OD.Operation_id = paramOperationID
	Group By OD.expTax_ID ,TH.TaxLedger_ID --,OD.expTaxPercent

	Union All

	------ Credit Side
	Select 'Tax' As PartName  ,  2 PartRank	,1 Rank 
			, case when  op_rec.OperationSign > 0 then CurrentAccountTypeKeyID else LedgerAccountTypeKeyID End AccountTypeID 
			, case when  op_rec.OperationSign > 0 then CurrentAccountID else TH.TaxLedger_ID  end  AccountID
			, case when  op_rec.OperationSign > 0 then MainLedger4Account else TH.TaxLedger_ID end  mainLedger
			, varEngDesc || ' - Expense Tax ' , varArbDesc || ' - Expense Tax' , -1 * op_rec.OperationSign *   ABS(op_rec.TotalTaxAmount) Amount 
			, op_rec.OperationSign *   ABS(op_rec.TotalTaxAmount) AmountFC  , 1 As Qty 
			, case when  op_rec.OperationSign *  Abs(op_rec.TotalTaxAmount) <=0  then op_rec.OperationSign *  Abs(op_rec.TotalTaxAmount) Else 0 end  DebitAmount 
			, case when  op_rec.OperationSign *  Abs(op_rec.TotalTaxAmount) > 0  then op_rec.OperationSign *  Abs(op_rec.TotalTaxAmount) Else 0 end  CreditAmount  
			,1 Reverse ,op_rec.CurrencyID , op_rec.CurrencyRate , false IsReverse

	from inv_OperationsExpensesLine  OD
	Inner Join sy_Taxes TH On TH.ID = OD.expTax_ID 
	Where OD.Operation_id = paramOperationID
	Group By OD.expTax_ID ,TH.TaxLedger_ID ;--,OD.expTaxPercent ;

	----====== End Tax PartName

--AR EXPENSES ----====== Expenses PartName
	--for all agencies services
	--Add Vendor create voucher for vendor agency
	-- From expense Acc to vendor agency acc
	IF (Select count(*) From inv_ExpensesTypes Where COALESCE(ledger_id,0) =0 ) > 0 then
			varMSGText =   'Error Expenses Types Accounts Setting  Not Selected';
			SELECT RaiseError(varMSGText);  
	End if;

	varEngDesc	    = 'Expenses Ref = ' || op_rec.OperationNumber ;
	varArbDesc	    = 'Expenses Ref = ' || op_rec.OperationNumber ;
	Insert Into TempOJL 
	(
		PartName  ,  PartRank	,  Rank	,  AccountType	,  AccountID	,  LedgerID	
		,  EngDesc	,  ArbDesc	,  Amount	
		,  AmountFC	,  Qty	,  DebitAmount	,  CreditAmount	,  Reverse	,  CurrencyID	,  CurrencyRate	,  IsReverse	
	)
	------ Debit Side
	Select 'Expenses' As PartName  ,  1 PartRank	,1 Rank 
			, case when  op_rec.OperationSign > 0 then CurrentAccountTypeKeyID  else LedgerAccountTypeKeyID End AccountTypeID 
			, case when  op_rec.OperationSign > 0 then CurrentAccountID  else OE.Ledger_ID end  AccountID
			, case when  op_rec.OperationSign > 0 then  MainLedger4Account else OE.Ledger_ID  end 
			, varEngDesc || ' - Expense Fees', varArbDesc || ' - Expense Fees', op_rec.OperationSign *  Abs(Amount) Amount 
			, op_rec.OperationSign  *   Abs(Amount) AmountFC  , 1 As Qty 
			, case when  op_rec.OperationSign *  Abs(Amount) >=0  then op_rec.OperationSign *  Abs(Amount) Else 0 end  DebitAmount 
			, case when  op_rec.OperationSign *  Abs(Amount) < 0  then op_rec.OperationSign *  Abs(Amount) Else 0 end  CreditAmount  
			 
			,1 Reverse ,op_rec.CurrencyID , op_rec.CurrencyRate , false IsReverse
	from inv_OperationsExpensesLine OSA
	Inner join inv_ExpensesTypes OE On OE.ID = serviceexpense_ID 
	Where OSA.Operation_id = paramOperationID

	------ Credit Side
	Union all 

	Select 'Expenses' As PartName  ,  2 PartRank	,1 Rank 
			, case when  op_rec.OperationSign > 0 then CurrentAccountTypeKeyID  else LedgerAccountTypeKeyID End AccountTypeID 
			, case when  op_rec.OperationSign > 0 then CurrentAccountID  else OE.Ledger_ID end  AccountID
			, case when  op_rec.OperationSign > 0 then  MainLedger4Account else OE.Ledger_ID  end 
			, varEngDesc || ' - Expense Fees', varArbDesc || ' - Expense Fees',op_rec.OperationSign  *  Abs(Amount) Amount 
			, op_rec.OperationSign  *   Abs(Amount) AmountFC  , 1 As Qty 
			, case when  op_rec.OperationSign *  Abs(Amount) >=0  then op_rec.OperationSign *  Abs(Amount) Else 0 end  DebitAmount 
			, case when  op_rec.OperationSign *  Abs(Amount) < 0  then op_rec.OperationSign *  Abs(Amount) Else 0 end  CreditAmount  
			,1 Reverse ,op_rec.CurrencyID , op_rec.CurrencyRate , false IsReverse
	from inv_OperationsExpensesLine OSA
	Inner join inv_ExpensesTypes OE On OE.ID = serviceexpense_ID 
	inner Join inv_agencies a on a.id = osa.agency_id
	inner join sy_lookup lu on lu.id = a.AccountType_id
	Where OSA.Operation_id = paramOperationID;

----====== End Expenses PartName
-------=========  Start Create Journal
	diffamount = (Select Sum(Amount) From TempOJL);

	If (Select Sum(Amount) From TempOJL) <> cast(0 as money) then
			varMSGText =   'Error The Voucher Not Balanced Check Your Setting The diff amount is ' || cast(diffamount as varchar(20)) ;
			SELECT RaiseError(varMSGText);  
	End if;
	
	------ Start Insert Accounts Jour

	IF ModuleCode = 'AR'  then----  Sales
		----- Insert Customer Jour
		Insert Into ar_customersjour  (  
			TransType_ID
			,JournalNumber
			,JournalDate,JournalYear,FiscalYearPeriod
			,reference1,ConfirmDate                 ,PostDate     ,created_by_id ,created_date
			,Remarks,IsLocked,Operation_id,Status_ID 
			,TotalAmount,Currency_ID,CurrencyRate  ,itemtransid 
			)
				
		Select newfcsTransTypeID TransTypeID
			,cast( (Select code From gl_transtypes Where id =newfcsTransTypeID ) as varchar(20)) || '-' || cast(   (Select Count(*) +1 from ar_customersJour where transtype_id = newfcsTransTypeID) as varchar(20))  Number 
			,current_date varJourDate ,EXTRACT(YEAR FROM OperationDate) JourYear ,FiscalYearPeriodID 
			, Number   Reference , null  ConfirmDate ,null PostDate ,loginuserid ,current_date
			,Remarks, True IsLocked , ID Operation_id ,null StatusID 
			,(Select Sum(DebitAmount) From TempOJL)  NetAmount ,op_rec.CurrencyID,op_rec.CurrencyRate   , op_rec.ItemTransHeadID
		from inv_Operations 
		Where ID = paramOperationID  returning id into varJourID ;

		Insert into ar_CustomersJourLine (
			customerjour_ID,Rank,AccountType_id 
			,Ledger_ID
			,customer_ID 
			,CostCenter1_ID,CostCenter2_ID,CostCenter3_ID,CostCenter4_ID,EngDesc,ArbDesc
			,DebitAmount ,CreditAmount  ,Amount,Qty,Currency_ID,CurrencyRate,Reverse
			) 
		Select 
			varJourID JourHeadID ,Rank, (Select id from sy_lookup where keyid = AccountType ) AccountType  
			,LedgerID 
			,  case when  AccountType = CurrentAccountTypeKeyID then  AccountID else null end  AccountID 
			, CostCenter1ID,CostCenter2ID,CostCenter3ID,CostCenter4ID ,EngDesc,ArbDesc
			,DebitAmount ,CreditAmount ,Amount, 0 Qty ,op_rec.CurrencyID,op_rec.CurrencyRate ,1 Reverse 
			From  TempOJL
			Where TempOJL.Amount <> cast(0 as money) ;

		Insert Into ar_CustomersTrans (
		TransType_ID,Customer_ID,CostCenter1_ID,CostCenter2_ID,CostCenter3_ID,CostCenter4_ID,TransDate,DocNumber
		,operationid,customerjour_ID,EngDesc,ArbDesc,Amount,AmountFC,SettleAmount
		,Currency_ID,CurrencyRate,DueDate,LastSettleDate,approvalby_ID,approvaldate
		,created_by_ID,created_date,fiscalyearperiod )

		Select 
			newfcsTransTypeID TransTypeID ,AccountID CustomerID ,CostCenter1ID,CostCenter2ID,CostCenter3ID,CostCenter4ID ,current_date varJourDate ,op_rec.OperationNumber  
			,paramOperationID,varJourID ,COALESCE(varEngDesc,'') EngDesc,COALESCE(varArbDesc ,'') ArbDesc,Sum(Amount) Amount,Sum(AmountFC ) AmountFC ,0 SettleAmount
			,op_rec.CurrencyID,op_rec.CurrencyRate ,null DueDate , null LastSettleDate , loginuserid  ApprovedByID , current_date  ApprovedDate
			,loginuserid ,current_date  ,FiscalYearPeriodID

		From  TempOJL
		Where AccountType = CurrentAccountTypeKeyID
		And  TempOJL.Amount <> cast(0 as money)
		Group By
		AccountID  ,CostCenter1ID,CostCenter2ID,CostCenter3ID,CostCenter4ID ;
	End if;
		-------=========  End Customer Journal 
	IF ModuleCode = 'AP'  then----  Purchase  مشتريات
		----- Insert Vendor Jour
		Insert Into ap_vendorsjour  (  
			TransType_ID
			,JournalNumber
			,JournalDate,JournalYear,FiscalYearPeriod
			,reference1,ConfirmDate                 ,PostDate     ,created_by_id ,created_date
			,Remarks,IsLocked,Operation_id,Status_ID 
			,TotalAmount,Currency_ID,CurrencyRate  ,itemtransid 
			)
				
		Select newfcsTransTypeID TransTypeID
			,cast( (Select code From gl_transtypes Where id =newfcsTransTypeID ) as varchar(20)) || '-' || cast(   (Select Count(*) +1 from ap_VendorsJour where transtype_id = newfcsTransTypeID) as varchar(20))  Number 
			,current_date varJourDate ,EXTRACT(YEAR FROM OperationDate) JourYear ,FiscalYearPeriodID 
			, Number   Reference , null  ConfirmDate ,null PostDate ,loginuserid ,current_date
			,Remarks, True IsLocked , ID Operation_id ,null StatusID 
			,(Select Sum(DebitAmount) From TempOJL)  NetAmount ,op_rec.CurrencyID,op_rec.CurrencyRate   , op_rec.ItemTransHeadID
		from inv_Operations 
		Where ID = paramOperationID  returning id into varJourID ;

		Insert into ap_vendorsJourLine (
			vendorjour_ID,Rank,AccountType_id 
			,Ledger_ID
			,vendor_ID 
			,CostCenter1_ID,CostCenter2_ID,CostCenter3_ID,CostCenter4_ID,EngDesc,ArbDesc
			,DebitAmount ,CreditAmount  ,Amount,Qty,Currency_ID,CurrencyRate,Reverse
			) 
		Select 
			varJourID JourHeadID ,Rank, (Select id from sy_lookup where keyid = AccountType ) AccountType  
			,LedgerID 
			,  case when  AccountType = CurrentAccountTypeKeyID then  AccountID else null end  AccountID 
			, CostCenter1ID,CostCenter2ID,CostCenter3ID,CostCenter4ID ,EngDesc,ArbDesc
			,DebitAmount ,CreditAmount ,Amount, 0 Qty ,op_rec.CurrencyID,op_rec.CurrencyRate ,1 Reverse 
			From  TempOJL
			Where TempOJL.Amount <> cast(0 as money) ;

		Insert Into ap_VendorsTrans (
		TransType_ID,vendor_ID,CostCenter1_ID,CostCenter2_ID,CostCenter3_ID,CostCenter4_ID,TransDate,DocNumber
		,operationid,vendorjour_ID,EngDesc,ArbDesc,Amount,AmountFC,SettleAmount
		,Currency_ID,CurrencyRate,DueDate,LastSettleDate,approvalby_ID,approvaldate
		,created_by_ID,created_date,fiscalyearperiod )

		Select 
			newfcsTransTypeID TransTypeID ,AccountID vendorID ,CostCenter1ID,CostCenter2ID,CostCenter3ID,CostCenter4ID ,current_date varJourDate ,op_rec.OperationNumber  
			,paramOperationID,varJourID ,COALESCE(varEngDesc,'') EngDesc,COALESCE(varArbDesc ,'') ArbDesc,Sum(Amount) Amount,Sum(AmountFC ) AmountFC ,0 SettleAmount
			,op_rec.CurrencyID,op_rec.CurrencyRate ,null DueDate , null LastSettleDate , loginuserid  ApprovedByID , current_date  ApprovedDate
			,loginuserid ,current_date  ,FiscalYearPeriodID

		From  TempOJL
		Where AccountType = CurrentAccountTypeKeyID
		And  TempOJL.Amount <> cast(0 as money)
		Group By
		AccountID  ,CostCenter1ID,CostCenter2ID,CostCenter3ID,CostCenter4ID ;

		-------=========  End Vendor Journal 

		End if;

	------ End Insert Accounts Jour

	------ Start Insert Ledger Trans
	Insert Into gl_LedgerTrans (
	TransType_ID,Ledger_ID,CostCenter1_ID,CostCenter2_ID,CostCenter3_ID,CostCenter4_ID,TransDate,DocNumber
	,Operation_id,customerjour , vendorjour,EngDesc,ArbDesc,Amount,AmountFC,SettleAmount
	,Currency_ID,CurrencyRate,DueDate,LastSettleDate,closedate,approvalby_ID,approvaldate
	,created_by_id,created_date,FiscalYearPeriod
	)
	Select 
		newfcsTransTypeID TransTypeID , LedgerID ,CostCenter1ID,CostCenter2ID,CostCenter3ID,CostCenter4ID ,current_date varJourDate ,op_rec.OperationNumber 
		, paramOperationID,case when ModuleCode = 'AR' then varJourID else null end ,case when  ModuleCode = 'AP' then varJourID else null end,COALESCE(EngDesc,'') EngDesc,COALESCE(ArbDesc ,'') ArbDesc ,Amount,AmountFC ,0 SettleAmount
		,op_rec.CurrencyID,op_rec.CurrencyRate ,null DueDate , null LastSettleDate , null Closed , loginuserid  ApprovedByID , current_date  ApprovedDate
		,loginuserid ,current_date ,FiscalYearPeriodID
	From  TempOJL
	Where TempOJL.Amount <> cast(0 as money) ;
	------ End Insert Ledger Trans

	drop Table TempOJL;				    				
end;
$$;


ALTER PROCEDURE public.in_createoperationsjour(paramoperationid integer, loginuserid integer) OWNER TO postgres;

--
-- Name: in_dashsumtargettopdown(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.in_dashsumtargettopdown() RETURNS TABLE(t_areaid integer, t_areacode character varying, t_areaengname character varying, t_areaarbname character varying, t_sizeid integer, t_sizekeyid integer, t_sizecode character varying, t_sizeengname character varying, t_sizearbname character varying, t_itmcatcode character varying, t_itmcatengname character varying, t_itmcatarbname character varying, t_cclsid integer, t_cclscode character varying, t_cclsengname character varying, t_cclsarbname character varying, t_nooflocperarea bigint, t_invlocid integer, t_invloccode character varying, t_invlocengname character varying, t_invlocarbname character varying, t_tarmonthlyamount double precision, t_mm integer, t_totalactamount numeric, t_count bigint)
    LANGUAGE plpgsql
    AS $$
declare myrec	record;

	BEGIN

CREATE TEMP TABLE temp_custsales AS

Select  
	Sum(linetotal) TotalActAmount
	,count(o.id) noofinvoice  
	,EXTRACT(month FROM operationdate) Mm 
	,cit.area_id areaid
	,lu.id sizeid
	,ccls.id classid
	,invloc.id invlocid
from inv_operations o 
inner join inv_operationsline ol On o.id = ol.operation_id
inner Join inv_operationsTypes ot on ot.id = o.operationtype_id
inner join ar_customers c on c.id = o.customer_id
Inner Join ar_customersaddresses cad ON cad.customer_id = c.id 
Inner Join ar_customersclasses ccls ON ccls.id =  c.customerclass_id 
inner join sy_cities cit on cit.id = cad.city_id	
inner join sy_lookup lu on lu.id = c.accountsize_id
inner join sy_lookup lukind on lu.id = ot.operationkind_id
inner join sy_lookup lustatus on lustatus.id = o.status_id
inner join inv_inventorieslocations invloc on invloc.id = o.invlocation_id
where lu.remarks = 'SALES'
and lustatus.keyid = 10004
group by 
	EXTRACT(month FROM operationdate) 
	,cit.area_id 
	,lu.id 
	,ccls.id 
	,invloc.id 
	;

CREATE TEMP TABLE cust_result AS 

Select 

lu.id sizeid,lu.keyid sizekeyid ,lu.code sizecode,lu.engname  sizeengname,lu.arbname  sizearbname 
,area.id areaid ,area.code areacode,area.code areaengname ,area.code areaarbname
,ccls.id classid,ccls.code  cclscode,ccls.code cclsengname ,ccls.code cclsarbname
,ccls.pricelevel_id pricelevelid
,count(c.id)
,(Select Count(L.id) from inv_inventorieslocations l inner join sy_cities c on c.id = l.city_id Where c.area_id = area.id ) NoOfLocPerarea
, il.id invlocid  ,il.code invloccode ,il.engname invlocengname ,il.arbname invlocarbname
from ar_customers c 
Inner Join ar_customersaddresses cad ON cad.customer_id = c.id 
Inner Join ar_customersclasses ccls ON ccls.id =  c.customerclass_id 
inner join sy_cities cit on cit.id = cad.city_id	
left Join inv_inventorieslocations il on cit.id = il.city_id
inner join sy_lookup lu on lu.id = c.accountsize_id
inner join sy_areas area on area.id = cit.area_id

where c.allowtarget = true 
group by
lu.id ,lu.keyid  ,lu.code ,lu.engname ,lu.arbname  
,area.id  ,area.code ,area.code  ,area.code 
,ccls.id ,ccls.code  ,ccls.code  ,ccls.code 
,ccls.pricelevel_id
, il.id ,il.code ,il.engname  ,il.arbname ;

--CREATE TEMP TABLE cust_result AS 
----drop TABLE cust_result 
--Select 

--lu.id sizeid,lu.keyid sizekeyid ,lu.code sizecode,lu.engname  sizeengname,lu.arbname  sizearbname 
--,area.id areaid ,area.code areacode,area.code areaengname ,area.code areaarbname
--,ccls.id classid,ccls.code  cclscode,ccls.code cclsengname ,ccls.code cclsarbname
--,ccls.pricelevel_id pricelevelid
--,count(c.id)

--from ar_customers c 
--Inner Join ar_customersaddresses cad ON cad.customer_id = c.id 
--Inner Join ar_customersclasses ccls ON ccls.id =  c.customerclass_id 
--inner join sy_cities cit on cit.id = cad.city_id	
--inner join sy_lookup lu on lu.id = c.accountsize_id
--inner join sy_areas area on area.id = cit.area_id

--where c.allowtarget = true 
--group by
--lu.id ,lu.keyid  ,lu.code ,lu.engname ,lu.arbname  
--,area.id  ,area.code ,area.code  ,area.code 
--,ccls.id ,ccls.code  ,ccls.code  ,ccls.code 
--,ccls.pricelevel_id ;

---============================
CREATE TEMP TABLE item_result AS 
--drop table item_result
Select 
i.id itemid,tb.itemuom_id itemuomid,itmcat.Code itmcatcode, itmcat.engname itmcatengname , itmcat.arbname itmcatarbname
,iuom.baseunitfactor
,itmsea.mm
,itmsea.area_id areaid
,tbb.channel_id classid
,	tb.yearly_qty * (tbb.contribution /100 ::float) *  case when false = true then 1 else (itmsea.quotapercent/100::float) end  * (tbb.small/100::float)  * (itmsea.mpercent/100::float) SmlQty
,	tb.yearly_qty * (tbb.contribution /100 ::float) * case when false = true then 1 else (itmsea.quotapercent/100::float) end  * (tbb.medium/100::float)  * (itmsea.mpercent/100::float) medQty
,	tb.yearly_qty * (tbb.contribution /100 ::float) * case when false = true then 1 else (itmsea.quotapercent/100::float) end  * (tbb.large/100::float)  * (itmsea.mpercent/100::float)  lrgQty

from inv_targetbuildingblocksitems tbb 
inner join inv_targetbuildingblocks tb On  tb.id = tbb.targetbuildingblocks_id
inner join inv_items i on i.id = tb.item_id
inner join inv_itemsuom iuom on iuom.id = tb.itemuom_id
inner join inv_viewitemsseasonality itmsea ON itmsea.item_id = i.id  
left join inv_itemscategories itmcat ON itmcat.id = i.itemcategory_id  ;
----============================================

return query 

Select 
	c.areaid , c.areacode , c.areaengname , c.areaarbname 
	,c.sizeid,c.sizekeyid , c.sizecode , c.sizeengname , c.sizearbname 
	,itmcatcode , itmcatengname , itmcatarbname 
	,c.classid,c.cclscode , c.cclsengname , c.cclsarbname 
	,c.NoOfLocPerarea
	, c.invlocid  ,c.invloccode ,c.invlocengname ,c.invlocarbname
,case when sizekeyid = 2102 then
	Sum(smlqty)
-- 	smlqty
else case when sizekeyid = 2103 then
	sum(medqty)
-- 	medqty
else case when sizekeyid = 2104 then	
	sum(lrgqty)
-- 	lrgqty
end
end
end   
/count / case when coalesce(NoOfLocPerarea ,0) > 0 then NoOfLocPerarea else 1 end
* firstprc.price TarMonthlyAmount
,   i.mm

,coalesce(sum(TotalActAmount),0) TotalActAmount
,count

from 
cust_result c
Inner Join item_result i On c.areaid = i.areaid and c.classid= i.classid 
left join temp_custsales cs On cs.classid = c.classid and cs.sizeid = c.sizeid  and cs.Mm = i.mm and cs.areaid = c.areaid and cs.invlocid = c.invlocid
LEFT JOIN LATERAL 
(Select price from  inv_itemspriceslists ipl where  ipl.item_id= i.itemid and ipl.pricelevel_id = c.pricelevelid and ipl.itemuom_id =i.itemuomid limit 1) AS firstprc ON true

group by
	c.areaid , c.areacode , c.areaengname , c.areaarbname 
	,c.sizeid,c.sizekeyid , c.sizecode , c.sizeengname , c.sizearbname 
	,itmcatcode , itmcatengname , itmcatarbname 
	,c.classid,c.cclscode , c.cclsengname , c.cclsarbname 
	,   i.mm,count,firstprc.price 
	,c.NoOfLocPerarea
	, c.invlocid  ,c.invloccode ,c.invlocengname ,c.invlocarbname
	
	;

--Select 
--	c.areaid , c.areacode , c.areaengname , c.areaarbname 
--	,c.sizeid,c.sizekeyid , c.sizecode , c.sizeengname , c.sizearbname 
--	,itmcatcode , itmcatengname , itmcatarbname 
--	,c.classid,c.cclscode , c.cclsengname , c.cclsarbname 
--	,c.NoOfLocPerarea
--	, c.invlocid  ,c.invloccode ,c.invlocengname ,c.invlocarbname

--,case when sizekeyid = 2102 then
--	smlqty
--else case when sizekeyid = 2103 then
--	medqty
--else case when sizekeyid = 2104 then	
--	lrgqty
--end
--end
--end   
--/count
--* firstprc.price TarMonthlyAmount

--	,   i.mm
	
--,coalesce(TotalActAmount,0) TotalActAmount

--,count

--from 
--cust_result c
--Inner Join item_result i On c.areaid = i.areaid and c.classid= i.classid 
--left join temp_custsales cs On cs.classid = c.classid and cs.sizeid = c.sizeid  and cs.Mm = i.mm and cs.areaid = c.areaid 
--LEFT JOIN LATERAL 
--(Select price from  inv_itemspriceslists ipl where  ipl.item_id= i.itemid and ipl.pricelevel_id = c.pricelevelid and ipl.itemuom_id =i.itemuomid limit 1) AS firstprc ON true;

DROP TABLE IF EXISTS temp_custsales;
DROP TABLE IF EXISTS cust_result;
DROP TABLE IF EXISTS item_result;

end;
$$;


ALTER FUNCTION public.in_dashsumtargettopdown() OWNER TO postgres;

