--

CREATE FUNCTION public.in_dashtargettopdown() RETURNS TABLE(t_custid integer, t_itemcode character varying, t_itemengname character varying, t_itemarbname character varying, t_custcode character varying, t_custengname character varying, t_custarbname character varying, t_salesmanname character varying, t_areaid integer, t_cityid integer, t_price numeric, t_tarqty double precision, t_custcount bigint, t_sizekeyid integer, t_sizecode character varying, t_sizeengname character varying, t_sizearbname character varying, t_baseunitfactor numeric, t_tarmqty double precision, t_salespersonid integer, t_yearlyqty integer, t_contribution integer, t_large integer, t_medium integer, t_small integer, t_quotapercent integer, t_mpercent numeric, t_mm integer, t_areacode character varying, t_areaengname character varying, t_areaarbname character varying, t_citcode character varying, t_citengname character varying, t_citarbname character varying, t_cclscode character varying, t_cclsengname character varying, t_cclsarbname character varying, actamount numeric, actqty numeric, t_invlocation integer)
    LANGUAGE plpgsql
    AS $$
declare myrec	record;

	BEGIN

--DROP TABLE IF EXISTS temp_custcount;
CREATE TEMP TABLE temp_custcount AS
	Select Count(*) custcount,accountsize_id , customerclass_id , area_id from ar_customers cc
	Inner Join ar_customersaddresses cad1 ON cad1.customer_id = cc.id
	inner join sy_cities cit1 on cit1.id = cad1.city_id
	inner join sy_lookup lu on lu.id = cc.accountsize_id
	Where cc.allowtarget = true
	group by accountsize_id , customerclass_id , area_id;

--DROP TABLE IF EXISTS temp_custsales;
CREATE TEMP TABLE temp_custsales AS

Select  

sum(linetotal) amount,sum(baseequivalentquantity) qty,invlocation_id, item_id
	,EXTRACT(month FROM operationdate) Mm ,customer_id
	from inv_operations o 
inner join inv_operationsline ol On o.id = ol.operation_id
inner Join inv_operationsTypes ot on ot.id = o.operationtype_id
inner join sy_lookup lu on lu.id = ot.operationkind_id
inner join sy_lookup lustatus on lustatus.id = o.status_id
where lu.remarks = 'SALES'
and lustatus.keyid = 10004
group by invlocation_id, item_id
	,EXTRACT(month FROM operationdate) ,customer_id;
	

return query 
Select  
c.id customer_id,
i.code,i.engname,i.arbname,
c.code,c.engname,c.arbname,
sm.name,cit.area_id,cit.id city_id,

(Select price from  inv_itemspriceslists ipl where  ipl.item_id= i.id and ipl.pricelevel_id = cc.pricelevel_id and ipl.itemuom_id =tb.itemuom_id limit 1) Price ,
case when lu.keyid = 2102 then
	tb.yearly_qty * (tbb.contribution /100 ::float) *  case when false = true then 1 else (itmsea.quotapercent/100::float) end  * (tbb.small/100::float)  
else case when lu.keyid = 2103 then
	tb.yearly_qty * (tbb.contribution /100 ::float) * case when false = true then 1 else (itmsea.quotapercent/100::float) end  * (tbb.medium/100::float)  
else case when lu.keyid = 2104 then	
	tb.yearly_qty * (tbb.contribution /100 ::float) * case when false = true then 1 else (itmsea.quotapercent/100::float) end  * (tbb.large/100::float)  
end
end
end taqty
,tcc.custcount

,lu.keyid ,lu.code,lu.engname  ,lu.arbname ,iuom.baseunitfactor

,case when lu.keyid = 2102 then
	tb.yearly_qty * (tbb.contribution /100 ::float) *  case when false = true then 1 else (itmsea.quotapercent/100::float) end  * (tbb.small/100::float)  * (itmsea.mpercent/100::float)
else case when lu.keyid = 2103 then
	tb.yearly_qty * (tbb.contribution /100 ::float) * case when false = true then 1 else (itmsea.quotapercent/100::float) end  * (tbb.medium/100::float)  * (itmsea.mpercent/100::float)
else case when lu.keyid = 2104 then	
	tb.yearly_qty * (tbb.contribution /100 ::float) * case when false = true then 1 else (itmsea.quotapercent/100::float) end  * (tbb.large/100::float)  * (itmsea.mpercent/100::float)
end
end
end  /tcc.custcount taqty

,c.salesperson_id ,tb.yearly_qty , tbb.contribution ,tbb.large ,tbb.medium ,tbb.small ,itmsea.quotapercent 
,itmsea.mpercent ,itmsea.mm

,area.code areacode,area.code areaengname ,area.code areaarbname
,cit.code citcode,cit.code citengname ,cit.code citarbname
,ccls.code cclscode,ccls.code cclsengname ,ccls.code cclsarbname

,cs.amount actamount,cs.qty/iuom.baseunitfactor  actqty,invlocation_id 

--into 		myrec 

from ar_customers c 
Inner Join ar_customersaddresses cad ON cad.customer_id = c.id 
Inner Join ar_customersclasses ccls ON ccls.id =  c.customerclass_id 

inner join sy_cities cit on cit.id = cad.city_id	
inner join sy_lookup lu on lu.id = c.accountsize_id
inner join inv_targetbuildingblocksitems tbb on tbb.channel_id = c.customerclass_id
inner join inv_targetbuildingblocks tb On  tb.id = tbb.targetbuildingblocks_id
inner join inv_items i on i.id = tb.item_id
inner join inv_itemsuom iuom on iuom.id = tb.itemuom_id

inner join inv_viewitemsseasonality itmsea ON itmsea.item_id = i.id  and cit.area_id = itmsea.area_id 
inner join sy_areas area on area.id = itmsea.area_id
inner join crm_salesman sm on sm.id = c.salesperson_id
inner join ar_customersclasses cc on cc.id = c.customerclass_id
inner join temp_custcount tcc on tcc.accountsize_id = c.accountsize_id and tcc.customerclass_id = c.customerclass_id and tcc.area_id = itmsea.area_id
left join temp_custsales cs On cs.customer_id = c.id and cs.item_id = i.id  and cs.Mm = itmsea.mm

where c.allowtarget = true

order by i.id;

--Select * from myrec ;

end;
$$;


ALTER FUNCTION public.in_dashtargettopdown() OWNER TO postgres;

--
-- Name: in_getitemsbalancesview(date, boolean, integer, boolean, boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.in_getitemsbalancesview(paramuptodate date, paramisnow boolean, paramuomtype integer, paramisidentifier boolean, paramisbinlocation boolean) RETURNS TABLE(ritem_id integer, ritemidentifier_id integer, rinvlocation_id integer, rinvbinlocation_id integer, rqtybalance numeric, rqtyreq numeric, ritemuom_id integer, rchangedate date)
    LANGUAGE plpgsql
    AS $$
Declare LedgerID 	Int;
	    UpToDate date ;
	   InCludeUpToDate  int   ;
Declare PeriodID int;
Declare PeriodToDate	date;
Begin

-----------===========================How to Use
--Select * from [dbo].[fn_mms_GetItemsBalancesView] ('',1,0,0,0) V
--Inner join mms_Items I on V.ItemID = I.ID
----------------===========================
	return query
	Select Item_ID,ItemIdentifier_ID ,invLocation_ID,invBinLocation_ID,ROUND(TotQty,4) QtyBalance
				,sign(TotQty) * Floor(Abs(TotQty)) QtyReq,  ItemUOM_ID  UOMIDReq 
				, ChangeDate 
				--,UnitFactor
				--,UnitID 
				--,BaseUnitID 
	From
	(
		Select   
		   COALESCE(Sum(QtyBalance * 1),0)	TotQty
		   --,QtyDec					QtyDec
		   ,Item_ID
		   ,Case When paramIsIdentifier = true Then ItemIdentifier_ID Else 0 End ItemIdentifier_ID
		   ,Max(ChangeDate) ChangeDate
		   ,invLocation_ID
		   ,Case when paramIsBinLocation = true Then invBinLocation_ID Else 0 End invBinLocation_ID
		   --,UC.UnitFactor
			,itemUOM_ID
		from 
			(Select * From 
				(Select Item_ID,ItemIdentifier_ID ,  ChangeDate ,Qtybalance ,invLocation_ID,invBinLocation_ID ,itemUOM_ID
					,ROW_NUMBER() OVER (Partition BY Item_ID,ItemIdentifier_ID ,  invLocation_ID,invBinLocation_ID,itemUOM_ID  Order By ChangeDate Desc) AS RowNum
					from inv_Inventory  Inv 
					Where    (   ( ChangeDate <= paramUpToDate And paramIsNow = false ))	Or ( paramIsNow = true )
				)G	
			) Inv1
		Where Inv1.RowNum = 1
		group by Item_ID
			,ItemIdentifier_ID
			,invLocation_ID,invBinLocation_ID ,itemUOM_ID
	) inv
	Group By
	   --QtyDec				
	   Item_ID
	   ,Case When paramIsIdentifier = true  Then ItemIdentifier_ID Else 0 End
	   ,invLocation_ID
	   ,invBinLocation_id
	   ,ItemIdentifier_ID
	   ,TotQty
		,ItemUOM_ID
		,ChangeDate
		,Case when paramIsBinLocation = true Then invBinLocation_id Else 0 End ;
	   --,UnitFactor;

end;		

--Order by ItemID

$$;


ALTER FUNCTION public.in_getitemsbalancesview(paramuptodate date, paramisnow boolean, paramuomtype integer, paramisidentifier boolean, paramisbinlocation boolean) OWNER TO postgres;

--
-- Name: in_getitemscost(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.in_getitemscost(rettype integer) RETURNS TABLE(rno bigint, marrno bigint, ltransdate date, itemid integer, lcostprice numeric)
    LANGUAGE plpgsql
    AS $$
Declare myrec float;

Begin
	return query
Select * from
	(
		Select 
		 ROW_NUMBER() OVER(PARTITION BY  item_id ORDER BY transDate Desc ,  ID desc) AS RowNo,
		 COUNT(*) OVER (PARTITION BY  item_id ) AS MaxRowNo,
		 transDate , Item_ID , CostPrice   From inv_ItemsCosts 
	 ) v
 Where 
 	--RowNo = 1;
	(RowNo <>  -1 And retType = 2 ) Or  (RowNo =  1 And retType = 0 )   Or  (RowNo =  MaxRowNo  And retType = 1 )  ;

end;

	
$$;


ALTER FUNCTION public.in_getitemscost(rettype integer) OWNER TO postgres;

--
-- Name: in_itemsaftersave(integer); Type: PROCEDURE; Schema: public; Owner: postgres
--

CREATE PROCEDURE public.in_itemsaftersave(paramitemid integer)
    LANGUAGE plpgsql
    AS $$
begin 
	
	if not EXISTS (Select * from inv_items i inner Join inv_itemsUom uom on i.id= uom.item_id 
				where i.id =paramitemID
				and uom.baseunitfactor = 1 and uom.unit_id =  i.baseunit_id ) then 
	
		insert into inv_itemsUom(item_id,baseunitfactor , unit_id, barcode)
		Select id,1,baseunit_id, barcode from inv_items  Where id = paramitemID ;
		
	end if;	
	
		
	update inv_items Set baseuom_id = (Select id from inv_itemsUom uom Where item_id =  paramitemID and uom.baseunitfactor = 1 and uom.unit_id =  inv_items.baseunit_id limit 1)
	where 
		id = paramitemID
		and coalesce(baseuom_id ,0) =0
	;

	

	Insert into inv_itemsidentifiers(barcode,expiredate,batchnumber,lotnumber,serialnumber,item_id,itemuom_id , baseitemuom_id)
	Select IU.barcode,null,null,null , null ,i.id item_id, iu.id itemuom_id ,i.baseuom_id  from inv_itemsuom iu
	inner join inv_Items i on IU.Item_id = i.ID
	inner join inv_itemsClasses Ic on i.itemclass_id = IC.id
	inner Join sy_lookup lu on lu.id = itemtrack_id
	where I.id = paramitemID 
	And lu.keyid = 3001 -- None Track (standard Item)
	And
	cast(i.id as varchar(10))   || '-' ||   cast(iu.id as varchar(10)) 
	not in(
	Select cast(item_id as varchar(10))   || '-' ||   cast(itemuom_id as varchar(10)) 
		From inv_itemsidentifiers
		);

	insert into inv_ItemsPricesLevels(item_id,pricelevel_id)
	Select i.id,pl.id from sy_PriceLevels pl,inv_Items I
	where  I.id = paramitemID
	And cast(i.id as varchar(10))  || '-' ||   cast(pl.id as varchar(10))  not in
	( Select cast(ipl.item_id as varchar(10))  || '-' ||  cast(ipl.pricelevel_id as varchar(10)) From inv_ItemsPricesLevels ipl);

	insert into inv_itemsinventorieslocations(item_id , invlocation_id,binlocation_id , status_id)
	Select  paramitemID , il.id, (Select id from inv_inventoriesbinlocations ibl Where ibl.id = il.id order by ibl.id limit 1 ) binid ,(Select id from sy_lookup Where keyid = 3101 ) statusid 
	from inv_inventoriesLocations il
	where  
		cast(paramitemID  as varchar(10))  || '-' ||   cast(il.id as varchar(10))  || '-' ||   cast(coalesce( (Select id from inv_inventoriesbinlocations ibl Where ibl.id = il.id order by ibl.id limit 1 ) ,0) as varchar(10))   not in
		( Select cast(iil.item_id as varchar(10))  || '-' ||  cast(iil.invlocation_id as varchar(10)) || '-' ||  cast( coalesce(iil.binlocation_id ,0) as varchar(10))   From inv_itemsinventorieslocations iil);

	insert into inv_ItemsPricesLists(invlocation_ID,item_id,Itemuom_id,unit_id,pricelevel_id,price)
	Select invlocation_id,L.item_id,U.id, U.unit_id ,pl.pricelevel_id,0
	from  inv_ItemsPricesLevels Pl ,inv_itemsinventorieslocations L ,  inv_itemsuom U ,inv_items i
	where L.item_id = paramitemID and pl.item_id = paramitemID and i.id = paramitemID and u.item_id = paramitemID
	and
	cast(i.id as varchar(10))  || '-' ||  cast(invlocation_id as varchar(10))  || '-' ||  cast(U.id as varchar(10))  || '-' ||  cast(pl.pricelevel_id as varchar(10))  || '-' ||  cast(U.unit_id as varchar(10)) 
	not in(
	Select cast(item_id as varchar(10))  || '-' ||  cast(invlocation_id as varchar(10))  || '-' ||  cast(itemuom_id as varchar(10))  || '-' ||  cast(pricelevel_id as varchar(10))  || '-' ||  cast(unit_id as varchar(10)) 
		From inv_ItemsPricesLists
		);

end;

$$;


ALTER PROCEDURE public.in_itemsaftersave(paramitemid integer) OWNER TO postgres;

--
-- Name: in_operationapproval(integer, integer); Type: PROCEDURE; Schema: public; Owner: postgres
--

CREATE PROCEDURE public.in_operationapproval(operationid integer DEFAULT 0, loginuserid integer DEFAULT 0)
    LANGUAGE plpgsql
    AS $$
Declare 
		statuskeyid	int = 0;
		approvalid int =0;
declare myrec record;
Declare 
	varMSGText		varchar(512) = '' ;
	vartotalcost		float = 0 ;
begin
	--Select  varOperationsStatus = COALESCE(Status_ID ,0),varOperationsStatuschangeby = statuschangedby_id   From in_Operations Where ID = operationid ;
	Select COALESCE(Status_ID ,0) as oldStatusID ,statuschangedby_id as oldstatuschangedbyid ,statusdate as oldstatusdate  into myrec  
		From inv_Operations Where ID = operationid ;
		
	Select keyid  from sy_lookup Where id = myrec.oldStatusID into statuskeyid;

	if COALESCE(statuskeyid ,0) > 10002 then
		varMSGText =   'Error Operation Appoved Before';
		SELECT RaiseError(varMSGText);
	else if COALESCE(statuskeyid ,0) < 10002 then
		varMSGText =   'Error Operation Not Submited';
		SELECT RaiseError(varMSGText);

	end if;
	end if;

	Select id  from sy_lookup Where keyid = '10003' into approvalid;

	insert into inv_OperationsStatusLog (operation_id,status_id,statusdate,statuschangedby_id)
	Select operationid , myrec.oldStatusid , myrec.OLDstatusdate,myrec.oldstatuschangedbyid ;
		
	vartotalcost = (select sum(baseequivalentquantity * costprice) totcst from inv_operationsline Where operation_id = operationid ); 
	
	update inv_operationsline Set price = ParentLine.Price ,costprice = ParentLine.costPrice 
			,Linetotal = ParentLine.Price * quantity,Originalprice = ParentLine.Originalprice
	from
	(Select Curr.id ,parnt.Price, parnt.OriginalPrice ,parnt.costprice 
	 	from inv_operationsline curr 
	 	inner join inv_operationsline parnt on curr.Parent = parnt.id where curr.operation_id = operationid ) ParentLine
	where ParentLine.ID = inv_operationsline.id 
	and inv_operationsline.operation_id = operationid;
	
	
	If statuskeyid In ( 10002 ) then
		Update inv_Operations Set Status_ID = approvalid , statuschangedby_id = loginuserid ,statusdate = current_date ,islocked = true, totalcost = vartotalcost 
		Where ID = OperationID And COALESCE(wfStatus_ID ,0) = 0 ;
	End if;

end;
$$;


ALTER PROCEDURE public.in_operationapproval(operationid integer, loginuserid integer) OWNER TO postgres;

--
-- Name: in_operationpost(integer, integer); Type: PROCEDURE; Schema: public; Owner: postgres
--

CREATE PROCEDURE public.in_operationpost(paramoperationid integer, loginuserid integer DEFAULT 0)
    LANGUAGE plpgsql
    AS $$
Declare 
	varMSGText					varchar(512) = '' ;
	varItemTransHeadID			int  =0 ;	
	varDefCurrencyID			int  = 0  ;
	varDefCurRate				float = 0 ;
	varDecCount					int  = 0;
	varLastDI					Numeric(18,10) ;
	varCurrentStatus			int  = 0 ;
	varOperationsStatus			int  =0 ;
	varIsLocked					boolean  = 0 ;

declare myrec record;
Declare StockCountRefID	   int = 0 ;
Declare 
 OTOutID			 int = 0;
 OTInID			 int= 0;
 ITTOutID		 int = 0;
 ITTInID		 int = 0;
 varITOutHID		 int = 0;
 varITInHID		 int = 0;

 declare 
		vardueamount  float = 0 ;
		vardueremainamount  float = 0 ;
		varduedate		date;
		varcreditdays	varchar;
		varcreditdaysval  int;
		varstartdate  date;
		varday int;

----Select * from sy_Lookup Where KeyName = 'OperationsStatus'
----------10001	OperationsStatus	1	Initiated	تم الانشاء
----------10002	OperationsStatus	2	Submitted	معتمدة
----------10003	OperationsStatus	3	Approved	موافق عليه
----------10004	OperationsStatus	4	Posted	مرحل			

-- 92	3201	"OperationsKinds"	"NONE"	"None"	"غير محدد"	"1"	"NONE"
-- 93	3202	"OperationsKinds"	"CS"	"Cash Sales"	"مبيعات نقدية"	"-1"	"SALES"
-- 94	3203	"OperationsKinds"	"RCS"	"Refund Cash Sales"	"مرتجع مبيعات نقدية"	"1"	"SALES"
-- 95	3204	"OperationsKinds"	"CRS"	"Credit Sales"	"مبيعات آجلة"	"-1"	"SALES"
-- 96	3205	"OperationsKinds"	"RCRS"	"Refund Credit Sales"	"مرتجع مبيعات آجلة"	"1"	"SALES"
-- 97	3206	"OperationsKinds"	"CP"	"Cash Purchase"	"مشتريات نقدية"	"1"	"PURCHASE"
-- 98	3207	"OperationsKinds"	"RCP"	"Refund Cash Purchase"	"مرتجع مشتريات نقدية"	"-1"	"PURCHASE"
-- 99	3208	"OperationsKinds"	"CRP"	"Credit Purchase"	"مشتريات آجلة"	"1"	"PURCHASE"
-- 100	3209	"OperationsKinds"	"RCRP"	"Refund Credit Purchase"	"مرتجع مشتريات آجلة"	"-1"	"PURCHASE"
-- 101	3210	"OperationsKinds"	"ADJ+"	"Adjusment +"	"تعديل بالزيادة"	"1"	"INVENTORY"
-- 102	3211	"OperationsKinds"	"ADJ-"	"Adjusment -"	"تعديل بالنقص"	"-1"	"INVENTORY"
-- 103	3212	"OperationsKinds"	"PCE"	"Physical Count Entry"	"إدخال الجرد"	"1"	"INVENTORY"
-- 104	3213	"OperationsKinds"	"PCP"	"Physical Count Post"	"ترحيل الجرد"	"1"	"INVENTORY"
-- 105	3214	"OperationsKinds"	"TO"	"Transfer Out"	"إخراج بغاية النقل"	"-1"	"INVENTORY"
-- 106	3215	"OperationsKinds"	"TI"	"Transfer In"	"إدخال بغاية النقل"	"1"	"INVENTORY"
-- 107	3216	"OperationsKinds"	"DT"	"Direct Transfer"	"نقل مباشر"	"1"	"INVENTORY"
-- 108	3217	"OperationsKinds"	"CC"	"Change Cost"	"تغيير التكلفة "	"1"	"INVENTORY"

begin

		Select
		number ,subject,operationdate,discper1,discper2,discper3,discamt1,discamt2,discamt3
		,expenseamount,grossamount,taxamount,netamount,oh.statusdate,oh.statusreason,oh.remarks,oh.accounttype_id
		,costcenter1_id,costcenter2_id,costcenter3_id,costcenter4_id,oh.currency_id,department_id,destinationinvlocation_id  DstLocationID ,fiscalyearperiod_id
		,invlocation_id,ledger_id,operationtype_id,oh.parent_id,oh.salesperson_id,sourceinvlocation_id,oh.status_id,oh.statuschangedby_id
		,wfstatus_id,wfstatuschangedby_id,wfstatusDate,wfstatusreason
		,ot.id otid,ot ,ot.code otcode, ot.engname otengname , ot.arbname otarbname ,ot.effectcostprice,ot.viewlocationqty,ot.viewaccountbalance
		,ot.allowrevise,ot.allowadditem,ot.allowdeleteitem,ot.allowadjustqty,ot.usepaymethod,ot.defaultqty,ot.defaultdiscounttype
		,ot.useshipping,ot.isinventory,ot.remarks otremarks,ot.accounttype_id otaccounttypeid,ot.usecostcenter1
		,ot.usecostcenter2,ot.usecostcenter3,ot.usecostcenter4
		,lu.id luid , lu.code lucode , lu.engname luengname , lu.arbname luarbname , lu.keyid lukeyid , lu.keyname lukeyname , lu.value luOperationKindSignValue ,lu.remarks luremarks
		,LUstatus.id LUstatusid , LUstatus.code LUstatuscode , LUstatus.engname LUstatusengname , LUstatus.arbname LUstatusarbname 
		,LUstatus.keyid LUstatuskeyid , LUstatus.keyname LUstatuskeyname , LUstatus.value LUstatusValue ,LUstatus.remarks LUstatusremarks
		
		,oh.customer_id

		,case when coalesce(c.paymenttearm_id, 0 ) = 0 then
				case when coalesce(cc.paymenttearm_id, 0 ) = 0 then null else cc.paymenttearm_id end 
			else c.paymenttearm_id  end paymenttearm_id

		,case when coalesce(c.creditlimit ,0)= 0 then 
			case when coalesce(pt.creditlimit , 0 ) = 0 then
				case when coalesce(cpt.creditlimit , 0 ) = 0 then 0 else cpt.creditlimit end 
			else pt.creditlimit  end
		else c.creditlimit end arcreditlimit

		,case when coalesce(c.creditdays,0)= 0 then 
			case when coalesce(pt.creditdays, 0 ) = 0 then
				case when coalesce(cpt.creditdays, 0 ) = 0 then 0 else cpt.creditdays end 
			else pt.creditdays  end
		else c.creditdays end arcreditdays
		
		,case when coalesce(pt.noofpayment, 0 ) = 0 then
				case when coalesce(cpt.noofpayment, 0 ) = 0 then 1 else cpt.noofpayment end 
			else pt.noofpayment  end arnoofpayment

		--,case when coalesce(pt.minpercentpayment, 0 ) = 0 then
		--		case when coalesce(cpt.minpercentpayment, 0 ) = 0 then 100 else cpt.minpercentpayment end 
		--	else pt.minpercentpayment  end arminpercentpayment
		 
		,case when coalesce(pt.paymentintervalday, 0 ) = 0 then
				case when coalesce(cpt.paymentintervalday, 0 ) = 0 then 5 else cpt.paymentintervalday end 
			else pt.paymentintervalday  end arpaymentintervalday
		
		,pt.isperiod
		,case when coalesce(pt.perioddays, 0 ) = 0 then 0 else pt.perioddays end  perioddays

		,coalesce(grossamount ,0)+ coalesce(taxamount,0) + coalesce(expenseamount,0) - coalesce(discamt1,0) - coalesce(discamt2,0) - coalesce(discamt3,0) operationamount

		into myrec
		From inv_operations OH
		Left Join inv_operationsTypes OT On OT.ID = OH.OperationType_ID 
		Left join sy_Lookup LU On LU.ID = OT.OperationKind_id 
		Left join sy_Lookup LUstatus On LUstatus.ID = OH.status_id 
		left join ar_customers c on C.id = oh.customer_id
		left Join sy_paymentsTearms pt on pt.id = c.paymenttearm_id
		left join ar_customersclasses cc on cc.id = c.customerclass_id
		left Join sy_paymentsTearms cpt on cpt.id = cc.paymenttearm_id

		Where OH.ID = paramOperationID;

	--- Only Submitted Record And Not lock
	

	If myrec.LUstatuskeyid <> 10003 then
		varMSGText =   'Error You Can not Post Currenct Operation (It is Not Approved)';
		SELECT RaiseError(varMSGText);
	End if;

	Select currency_id from crm_company into varDefCurrencyID ;
	Select rate from crm_currency  where id = varDefCurrencyID into varDefCurRate;

	--Select varDefCurRate from crm_company into varDefCurrencyID ;

	if loginuserid = 0 then
		varMSGText ='Error Check User Code not Avaliable in User Table';
		SELECT RaiseError(varMSGText);
	end if;

	if varDefCurrencyID = 0 then 
		varMSGText ='Error Check Default (Local ) Currency in Company Screen';
		SELECT RaiseError(varMSGText);
	end if;

	if varDefCurRate = 0 then
		varMSGText ='Error Check Currency Rate For Default Currency ';
		SELECT RaiseError(varMSGText);
	end if;

--10101	OperationsKinds	0	None	غير محدد	NULL	1
    If myrec.lukeyid = 10101 then
	   Select luOperationKindSignValue ;
	
    
--------10102	OperationsKinds	1	Cash Sales	مبيعات نقدية	NULL	-1
    ElseIf myrec.lukeyid = 3202  then

		Call public.in_CreateOperationsJour (paramOperationID,loginuserid);

		Update inv_operations Set Status_ID  =(Select id from sy_lookup Where keyid = 10004 )   
		,rdstatus_id = (Select id from sy_lookup Where keyid = 10031 ) ,rdstatusdate = current_date , rdstatuschangedby_id = loginuserid  
		,amountstatus_id = (Select id from sy_lookup Where keyid = 10051 ) ,amountstatusdate = current_date , amountstatuschangedby_id = loginuserid  
		Where ID = paramOperationID;

    
--------10103	OperationsKinds	2	Refund Cash Sales	مرتجع مبيعات نقدية	NULL	1
    ElseIf myrec.lukeyid = 3203 then

		Call public.in_CreateOperationsJour (paramOperationID,loginuserid);

		Update inv_operations Set Status_ID  =(Select id from sy_lookup Where keyid = 10004 )   
		,rdstatus_id = (Select id from sy_lookup Where keyid = 10031 ) ,rdstatusdate = current_date , rdstatuschangedby_id = loginuserid  
		,amountstatus_id = (Select id from sy_lookup Where keyid = 10051 ) ,amountstatusdate = current_date , amountstatuschangedby_id = loginuserid  
		Where ID = paramOperationID;
    
    
--------10104	OperationsKinds	3	Credit Sales	مبيعات آجلة	NULL	-1
    ElseIf myrec.lukeyid = 3204 then

		if not exists(	Select * from ar_CustomersPaymentsSchedule Where operation_id = paramOperationID ) then
			vardueamount  = cast( (myrec.operationamount / myrec.arnoofpayment) as int) ;
			varcreditdaysval = cast( myrec.arcreditdays as int) ;

			if myrec.isperiod then
				varstartdate = cast( date_trunc('month',  cast(current_date as date)) as date) ;
				if coalesce(myrec.perioddays,0) = 0 then
					varduedate	= 	varstartdate + cast( myrec.arcreditdays as int) ;
				else
					varday = cast( EXTRACT(DAY FROM current_date) as int) / case when myrec.perioddays > 0 then myrec.perioddays else 1 end;
					varduedate	= 	varstartdate::date   + (varday * myrec.perioddays) + myrec.perioddays  + cast( myrec.arcreditdays as int);
				end if;
			else
				varduedate	= 	current_date::date  + varcreditdaysval;
			end if ;

			
			vardueremainamount = myrec.operationamount -   (vardueamount * myrec.arnoofpayment) ;
	
		for counter in 1..myrec.arnoofpayment loop
				
				--raise notice 'counter: %', counter;
				insert into ar_CustomersPaymentsSchedule( customer_id, operation_id, operationdate,operationamount ,operationamountfc , paymenttearm_id ,currency_id ,isclose ,paidamount
					,duedate ,dueamount 	,dueamountfc)
				Select myrec.customer_id , paramOperationID , myrec.operationdate , myrec.operationamount , myrec.operationamount ,myrec.paymenttearm_id,myrec.currency_id  ,false ,0 paidamount
					,varduedate , case when counter = 1 then  vardueamount +vardueremainamount  else  vardueamount end    
						,case when counter = 1 then  vardueamount +vardueremainamount  else  vardueamount end ;
				
				varduedate	= 	varduedate  ::date + myrec.arpaymentintervalday;

			end loop;

		end if;
		
		Call public.in_CreateOperationsJour (paramOperationID,loginuserid);

		Update inv_operations Set Status_ID  =(Select id from sy_lookup Where keyid = 10004 )   
		,rdstatus_id = (Select id from sy_lookup Where keyid = 10031 ) ,rdstatusdate = current_date , rdstatuschangedby_id = loginuserid  
		,amountstatus_id = (Select id from sy_lookup Where keyid = 10051 ) ,amountstatusdate = current_date , amountstatuschangedby_id = loginuserid  
		Where ID = paramOperationID;
    
    
--------10105	OperationsKinds	4	Refund Credit Sales	مرتجع مبيعات آجلة	NULL	1
    ElseIf myrec.lukeyid = 3205 then
	   If myrec.isinventory = true then

	   End if;
    
		update ar_CustomersPaymentsSchedule set isclose = true where operation_id = myrec.parent_id ;

		Call public.in_CreateOperationsJour (paramOperationID,loginuserid);

		Update inv_operations Set Status_ID  =(Select id from sy_lookup Where keyid = 10004 )   
		,rdstatus_id = (Select id from sy_lookup Where keyid = 10031 ) ,rdstatusdate = current_date , rdstatuschangedby_id = loginuserid  
		,amountstatus_id = (Select id from sy_lookup Where keyid = 10051 ) ,amountstatusdate = current_date , amountstatuschangedby_id = loginuserid  
		Where ID = paramOperationID;

    
--------10106	OperationsKinds	5	Cash Purchase	مشتريات نقدية	NULL	1
    ElseIf myrec.lukeyid = 3206 then

		Call public.in_CreateOperationsJour (paramOperationID,loginuserid);

		  Update inv_operations Set Status_ID  =(Select id from sy_lookup Where keyid = 10004 )   
		  	,rdstatus_id = (Select id from sy_lookup Where keyid = 10031 ) ,rdstatusdate = current_date , rdstatuschangedby_id = loginuserid  
			,amountstatus_id = (Select id from sy_lookup Where keyid = 10051 ) ,amountstatusdate = current_date , amountstatuschangedby_id = loginuserid  
		  Where ID = paramOperationID;

    
    
--------10107	OperationsKinds	6	Refund Cash Purchase	مرتجع مشتريات نقدية	NULL	-1
    ElseIf myrec.lukeyid = 3207 then
	   If myrec.isinventory = true then

	   End if;
    
		Call public.in_CreateOperationsJour (paramOperationID,loginuserid);

		Update inv_operations Set Status_ID  =(Select id from sy_lookup Where keyid = 10004 )   
		,rdstatus_id = (Select id from sy_lookup Where keyid = 10031 ) ,rdstatusdate = current_date , rdstatuschangedby_id = loginuserid  
		,amountstatus_id = (Select id from sy_lookup Where keyid = 10051 ) ,amountstatusdate = current_date , amountstatuschangedby_id = loginuserid  
		Where ID = paramOperationID;
    
--------10108	OperationsKinds	7	Credit Purchase	مشتريات آجلة	NULL	1
    ElseIf myrec.lukeyid = 3208 then
		Call public.in_CreateOperationsJour (paramOperationID,loginuserid);

		Update inv_operations Set Status_ID  =(Select id from sy_lookup Where keyid = 10004 )   
		,rdstatus_id = (Select id from sy_lookup Where keyid = 10031 ) ,rdstatusdate = current_date , rdstatuschangedby_id = loginuserid  
		,amountstatus_id = (Select id from sy_lookup Where keyid = 10051 ) ,amountstatusdate = current_date , amountstatuschangedby_id = loginuserid  
		Where ID = paramOperationID;
    
    
--------10109	OperationsKinds	8	Refund Credit Purchase	مرتجع مشتريات آجلة	NULL	-1
    ElseIf myrec.lukeyid = 3209 then
		Call public.in_CreateOperationsJour (paramOperationID,loginuserid);

		Update inv_operations Set Status_ID  =(Select id from sy_lookup Where keyid = 10004 )   
		,rdstatus_id = (Select id from sy_lookup Where keyid = 10031 ) ,rdstatusdate = current_date , rdstatuschangedby_id = loginuserid  
		,amountstatus_id = (Select id from sy_lookup Where keyid = 10051 ) ,amountstatusdate = current_date , amountstatuschangedby_id = loginuserid  
		Where ID = paramOperationID;
    
    
--------10110	OperationsKinds	9	Adjusment +	تعديل بالزيادة	NULL	1
    ElseIf myrec.lukeyid = 3210 then
		Call public.in_CreateOperationsJour (paramOperationID,loginuserid);

		Update inv_operations Set Status_ID  =(Select id from sy_lookup Where keyid = 10004 )   
		,rdstatus_id = (Select id from sy_lookup Where keyid = 10031 ) ,rdstatusdate = current_date , rdstatuschangedby_id = loginuserid  
		,amountstatus_id = (Select id from sy_lookup Where keyid = 10051 ) ,amountstatusdate = current_date , amountstatuschangedby_id = loginuserid  
		Where ID = paramOperationID;
    
    
--------10111	OperationsKinds	10	Adjusment -	تعديل بالنقص	NULL	-1
    ElseIf myrec.lukeyid = 3211 then
		Call public.in_CreateOperationsJour (paramOperationID,loginuserid);

		Update inv_operations Set Status_ID  =(Select id from sy_lookup Where keyid = 10004 )   
		,rdstatus_id = (Select id from sy_lookup Where keyid = 10031 ) ,rdstatusdate = current_date , rdstatuschangedby_id = loginuserid  
		,amountstatus_id = (Select id from sy_lookup Where keyid = 10051 ) ,amountstatusdate = current_date , amountstatuschangedby_id = loginuserid  
		Where ID = paramOperationID;
    
    
--------10112	OperationsKinds	11	Physical Count Entry	إدخال الجرد	NULL	1
    ElseIf myrec.lukeyid = 3212 then
		Call public.in_CreateOperationsJour (paramOperationID,loginuserid);

		Update inv_operations Set Status_ID  =(Select id from sy_lookup Where keyid = 10004 )   
		,rdstatus_id = (Select id from sy_lookup Where keyid = 10031 ) ,rdstatusdate = current_date , rdstatuschangedby_id = loginuserid  
		,amountstatus_id = (Select id from sy_lookup Where keyid = 10051 ) ,amountstatusdate = current_date , amountstatuschangedby_id = loginuserid  
		Where ID = paramOperationID;
    
    
--------10113	OperationsKinds	12	Physical Count Post	ترحيل الجرد	NULL	1
    ElseIf myrec.lukeyid = 3213 then
	   If myrec.isinventory = true then
		  
		  Select StockCountRefID = COALESCE(StockCountPrepareRefID ,0) FROM inv_operations OH Where ID = paramOperationID ;
		  
		  If StockCountRefID = 0  then
			 varMSGText =   'Error No Stock Count Reference Please Check Stock Count verifying Submit';
			 SELECT RaiseError(varMSGText);
		  End if;

		  -----=========   Next Statement Insert int ;o mms_Inventory Table
				
		  Update mms_StockCountPrepareRef Set CloseDateTime = getdate() Where ID = StockCountRefID ;

		  --EXEC sp_mms_SaveInventoryItemTrans varItemTransHeadID

		  -----=========   Next Statement Calc new Cost And insert int ;o mms_ItemsCost
		  --EXEC sp_mms_RecalcCostByOperation paramOperationID

		  -----=========   Next Statement Create Journal In Finance (Full Voucher) For operation
		  --Exec sp_mms_CreateOperationsJour paramOperationID

		  Update inv_operations Set IsLocked = 1 Where ID = paramOperationID;

	   End if ;
    
    
--------10114	OperationsKinds	13	Transfer Out	إخراج بغاية النقل	NULL	-1
    ElseIf myrec.lukeyid = 3214 then
	   If myrec.isinventory = true then

	   End if;
    
    
--------10115	OperationsKinds	14	Transfer In	إدخال بغاية النقل	NULL	1
    ElseIf myrec.lukeyid = 3215 then
	   If myrec.isinventory = true then

	   End if;
    
    
--------10116	OperationsKinds	15	Direct Transfer	نقل مباشر
    ElseIf myrec.lukeyid = 3216 then
	   If myrec.isinventory = true then
		  If myrec.DstLocationID = 0 then
			 varMSGText =   'Error Check Destination Location Not selected You have to Select Target Location' ;
			 SELECT RaiseError(varMSGText);
		  End if;

		  Select OTOutID = ID , ITTOutID = ItemTransTypeID  From inv_operationsTypes OT   Where OperationKind = 10114 ;    ---Out
		  Select OTInID = ID  , ITTInID  = ItemTransTypeID  From inv_operationsTypes OT   Where OperationKind = 10115 ;    --- IN

		  If COALESCE(OTOutID,0) = 0 Or  COALESCE(OTInID,0) = 0  Or  COALESCE(ITTOutID,0) = 0   Or  COALESCE(ITTInID,0) = 0  then
			 varMSGText =   'Error Check Operation type the Transfer Out Or transfer in Not Defined' ;
			 SELECT RaiseError(varMSGText);
		  End if;
		  ----======   Check Abaliable Qty 
		  If Exists(Select *  
				From inv_operations H
				Inner Join inv_OperationsLine D On H.ID = D.OperationHeadID 
				Inner join fn_mms_GetItemsBalancesView(Null,1,1,1,0) Bal On Bal.ItemIdentifierID = D.ItemIdentifierID And Bal.LocationID = H.LocationID
				--cross Apply fn_UnitConvert (D.UnitofMeasurementID  , 1,0) LUOM
				Where H.ID = paramOperationID
					     
				And (D.Quantity  * LUOM.UnitFactor) > Bal.TotalQty 
				) then
				varMSGText =   'Error Qty Not Enough In Source Location';
				SELECT RaiseError(varMSGText);
		  End if ; 
		  ------ Next Insert For Transfer OUT    
		  INSERT into inv_ItemsTrans(ItemTransTypeID,SequenceID,Number,TransDate,LocationID,OperationHeadID,InvoiceOperationHeadID,FixedFiscalYearPeriodID,CancelDate)
		  SELECT 
			 ITTOutID,OH.SequenceID,OH.Number,OH.OperationDate,OH.LocationID,OH.ID OperationheadID
			 ,NULL InvoiceOperationHeadID,OH.FiscalYearPeriodID,NULL CancelDate
		  FROM inv_operations OH
		  INNER JOIN inv_operationsTypes OT ON OT.ID = OH.OperationTypeID
		  WHERE OH.ID = paramOperationID   returning id into varITOutHID;

		  

		  INSERT into inv_ItemsTransLine(
				ItemTransHeadID,ItemIdentifierID,LocationID,BinLocation,Quantity,UnitofMeasurementID
				,UnitofMeasurementEngName,UnitofMeasurementArbName,BaseUnitofMeasurementID
				,BaseUnitofMeasurementEngName,BaseUnitofMeasurementArbName,BaseUnitofMeasurementEquivalentQty
				,QuantityCount,OrigionalPrice,CostPrice,LineTotal,LastDI,CurrenceyID,ExchangeRate
				,IsBonusQuantity,OperationDetailID,ItemID , ExpireDate1
			 )
		  SELECT 
			 varITOutHID
			 --ITH.ID ItemTransHeadID
			 ,OD.ItemIdentifierID
			 ,OH.LocationID
			 ,'' BinLocation
			 ,-1 *  ABs(OD.Quantity) Quantity
			 ,OD.UnitofMeasurementID
			 ,OD.UnitofMeasurementEngName
			 ,OD.UnitofMeasurementArbName
			 ,OD.BaseUnitofMeasurementID
			 ,OD.BaseUnitofMeasurementEngName
			 ,OD.BaseUnitofMeasurementArbName
			 ,OD.BaseUnitofMeasurementEquivalentQty
			 ,OD.QuantityCount
			 ,OD.OrigionalPrice
			 ,LastCostTable.CostPrice
			 ,OD.LineTotal
			 ,OD.LastDI
			 ,OH.CurrencyID
			 ,OH.CurrencyExchange
			 ,OD.IsBonusQuantity
			 ,OD.ID OperationDetailID
			 ,OD.ItemID
			 ,OD.ExpireDate1

		  FROM inv_operations OH
		  INNER JOIN inv_OperationsLine OD ON OD.OperationHeadID = OH.ID
		  --Left Join [dbo].[fn_mms_GetItemsCost] (0 ) LastCostTable On LastCostTable.ItemID =OD.ItemID
		  WHERE OH.ID = paramOperationID;

		  ------ Next Insert For Transfer In    

		  INSERT into inv_ItemsTrans(ItemTransTypeID,SequenceID,Number,TransDate,LocationID,OperationHeadID,InvoiceOperationHeadID,FixedFiscalYearPeriodID,CancelDate,ItemTransHeadParentID)
		  SELECT 
			 ITTOutID,OH.SequenceID,OH.Number,OH.OperationDate,OH.destinationinvlocation_id,OH.ID OperationheadID
			 ,NULL InvoiceOperationHeadID,OH.FiscalYearPeriodID,NULL CancelDate ,varITOutHID
		  FROM inv_operations OH
		  INNER JOIN inv_operationsTypes OT ON OT.ID = OH.OperationTypeID
		  WHERE OH.ID = paramOperationID    returning id into varITInHID;

		  

		  INSERT into inv_ItemsTransLine(
				ItemTransHeadID,ItemIdentifierID,LocationID,BinLocation,Quantity,UnitofMeasurementID
				,UnitofMeasurementEngName,UnitofMeasurementArbName,BaseUnitofMeasurementID
				,BaseUnitofMeasurementEngName,BaseUnitofMeasurementArbName,BaseUnitofMeasurementEquivalentQty
				,QuantityCount,OrigionalPrice,CostPrice,LineTotal,LastDI,CurrenceyID,ExchangeRate
				,IsBonusQuantity,OperationDetailID,ItemID , ExpireDate1 
			 )
		  SELECT 
			 varITInHID
			 --ITH.ID ItemTransHeadID
			 ,OD.ItemIdentifierID
			 ,OH.DstLocationID
			 ,'' BinLocation
			 ,ABs(OD.Quantity) Quantity
			 ,OD.UnitofMeasurementID
			 ,OD.UnitofMeasurementEngName
			 ,OD.UnitofMeasurementArbName
			 ,OD.BaseUnitofMeasurementID
			 ,OD.BaseUnitofMeasurementEngName
			 ,OD.BaseUnitofMeasurementArbName
			 ,OD.BaseUnitofMeasurementEquivalentQty
			 ,OD.QuantityCount
			 ,OD.OrigionalPrice
			 ,LastCostTable.CostPrice
			 ,OD.LineTotal
			 ,OD.LastDI
			 ,OH.CurrencyID
			 ,OH.CurrencyExchange
			 ,OD.IsBonusQuantity
			 ,OD.ID OperationDetailID
			 ,OD.ItemID
			 ,OD.ExpireDate1

		  FROM inv_operations OH
		  INNER JOIN inv_OperationsLine OD ON OD.OperationHeadID = OH.ID
		  --Left Join [dbo].[fn_mms_GetItemsCost] (0 ) LastCostTable On LastCostTable.ItemID =OD.ItemID
		  WHERE OH.ID = paramOperationID;

		  --EXEC sp_mms_SaveInventoryItemTrans varITOutHID

		  --EXEC sp_mms_SaveInventoryItemTrans varITInHID

		  -----=========   Next Statement Create Journal In Finance (Full Voucher) For operation
		  --Exec sp_mms_CreateOperationsJour paramOperationID 

		  Update inv_operations Set Status_ID  =(Select id from sy_lookup Where keyid = 10004 )   
		  	,rdstatus_id = (Select id from sy_lookup Where keyid = 10031 ) ,rdstatusdate = current_date , rdstatuschangedby_id = loginuserid  
			,amountstatus_id = (Select id from sy_lookup Where keyid = 10051 ) ,amountstatusdate = current_date , amountstatuschangedby_id = loginuserid  
		  
		  Where ID = paramOperationID;

	   End if;
    
    
--------10117	OperationsKinds	15	Change Cost	تغيير التكلفة 	NULL	1
    ElseIf myrec.lukeyid = 3217 then
	   If myrec.isinventory = true then

	   End if;
    End if;
end;

$$;


ALTER PROCEDURE public.in_operationpost(paramoperationid integer, loginuserid integer) OWNER TO postgres;

--
-- Name: in_operationpostinventory_new(integer, integer); Type: PROCEDURE; Schema: public; Owner: postgres
--

CREATE PROCEDURE public.in_operationpostinventory_new(paramoperationid integer, loginuserid integer DEFAULT 0)
    LANGUAGE plpgsql
    AS $$
Declare 
	varMSGText					varchar(512) = '' ;
	varItemTransHeadID			int  =0 ;	
	varDefCurrencyID			int  = 0  ;
	varDefCurRate				float = 0 ;
	varDecCount					int  = 0;
	varLastDI					Numeric(18,10) ;
	varCurrentStatus			int  = 0 ;
	varOperationsStatus			int  =0 ;
	varIsLocked					boolean  = 0 ;

declare myrec record;
Declare StockCountRefID	   int = 0 ;
Declare 
 OTOutID			 int = 0;
 OTInID			 int= 0;
 ITTOutID		 int = 0;
 ITTInID		 int = 0;
 varITOutHID		 int = 0;
 varITInHID		 int = 0;

----Select * from sy_Lookup Where KeyName = 'OperationsStatus'
----------10001	OperationsStatus	1	Initiated	تم الانشاء
----------10002	OperationsStatus	2	Submitted	معتمدة
----------10003	OperationsStatus	3	Approved	موافق عليه
----------10004	OperationsStatus	4	Posted	مرحل			

-- 92	3201	"OperationsKinds"	"NONE"	"None"	"غير محدد"	"1"	"NONE"
-- 93	3202	"OperationsKinds"	"CS"	"Cash Sales"	"مبيعات نقدية"	"-1"	"SALES"
-- 94	3203	"OperationsKinds"	"RCS"	"Refund Cash Sales"	"مرتجع مبيعات نقدية"	"1"	"SALES"
-- 95	3204	"OperationsKinds"	"CRS"	"Credit Sales"	"مبيعات آجلة"	"-1"	"SALES"
-- 96	3205	"OperationsKinds"	"RCRS"	"Refund Credit Sales"	"مرتجع مبيعات آجلة"	"1"	"SALES"
-- 97	3206	"OperationsKinds"	"CP"	"Cash Purchase"	"مشتريات نقدية"	"1"	"PURCHASE"
-- 98	3207	"OperationsKinds"	"RCP"	"Refund Cash Purchase"	"مرتجع مشتريات نقدية"	"-1"	"PURCHASE"
-- 99	3208	"OperationsKinds"	"CRP"	"Credit Purchase"	"مشتريات آجلة"	"1"	"PURCHASE"
-- 100	3209	"OperationsKinds"	"RCRP"	"Refund Credit Purchase"	"مرتجع مشتريات آجلة"	"-1"	"PURCHASE"
-- 101	3210	"OperationsKinds"	"ADJ+"	"Adjusment +"	"تعديل بالزيادة"	"1"	"INVENTORY"
-- 102	3211	"OperationsKinds"	"ADJ-"	"Adjusment -"	"تعديل بالنقص"	"-1"	"INVENTORY"
-- 103	3212	"OperationsKinds"	"PCE"	"Physical Count Entry"	"إدخال الجرد"	"1"	"INVENTORY"
-- 104	3213	"OperationsKinds"	"PCP"	"Physical Count Post"	"ترحيل الجرد"	"1"	"INVENTORY"
-- 105	3214	"OperationsKinds"	"TO"	"Transfer Out"	"إخراج بغاية النقل"	"-1"	"INVENTORY"
-- 106	3215	"OperationsKinds"	"TI"	"Transfer In"	"إدخال بغاية النقل"	"1"	"INVENTORY"
-- 107	3216	"OperationsKinds"	"DT"	"Direct Transfer"	"نقل مباشر"	"1"	"INVENTORY"
-- 108	3217	"OperationsKinds"	"CC"	"Change Cost"	"تغيير التكلفة "	"1"	"INVENTORY"

begin

		Select
		number ,subject,operationdate,discper1,discper2,discper3,discamt1,discamt2,discamt3
		,expenseamount,grossamount,taxamount,netamount,statusdate,statusreason,oh.remarks,oh.accounttype_id
		,costcenter1_id,costcenter2_id,costcenter3_id,costcenter4_id,currency_id,department_id,destinationinvlocation_id  DstLocationID ,fiscalyearperiod_id
		,invlocation_id,ledger_id,operationtype_id,parent_id,salesperson_id,sourceinvlocation_id,status_id,statuschangedby_id
		,wfstatus_id,wfstatuschangedby_id,wfstatusDate,wfstatusreason
		,ot.id otid,ot ,ot.code otcode, ot.engname otengname , ot.arbname otarbname ,ot.effectcostprice,ot.viewlocationqty,ot.viewaccountbalance
		,ot.allowrevise,ot.allowadditem,ot.allowdeleteitem,ot.allowadjustqty,ot.usepaymethod,ot.defaultqty,ot.defaultdiscounttype
		,ot.useshipping,ot.isinventory,ot.remarks otremarks,ot.accounttype_id otaccounttypeid,ot.usecostcenter1
		,ot.usecostcenter2,ot.usecostcenter3,ot.usecostcenter4
		,lu.id luid , lu.code lucode , lu.engname luengname , lu.arbname luarbname , lu.keyid lukeyid , lu.keyname lukeyname , lu.value luOperationKindSignValue ,lu.remarks luremarks
		,LUstatus.id LUstatusid , LUstatus.code LUstatuscode , LUstatus.engname LUstatusengname , LUstatus.arbname LUstatusarbname 
		,LUstatus.keyid LUstatuskeyid , LUstatus.keyname LUstatuskeyname , LUstatus.value LUstatusValue ,LUstatus.remarks LUstatusremarks

		into myrec
		From inv_operations OH
		Left Join inv_operationsTypes OT On OT.ID = OH.OperationType_ID 
		Left join sy_Lookup LU On LU.ID = OT.OperationKind_id 
		Left join sy_Lookup LUstatus On LUstatus.ID = OH.status_id 
		Where OH.ID = paramOperationID;

	--- Only Submitted Record And Not lock
	

	If myrec.LUstatuskeyid <> 10003 then
		varMSGText =   'Error You Can not Post Currenct Operation (It is Not Approved)';
		SELECT RaiseError(varMSGText);
	End if;

	Select currency_id from crm_company into varDefCurrencyID ;
	Select rate from crm_currency  where id = varDefCurrencyID into varDefCurRate;

	--Select varDefCurRate from crm_company into varDefCurrencyID ;

	if loginuserid = 0 then
		varMSGText ='Error Check User Code not Avaliable in User Table';
		SELECT RaiseError(varMSGText);
	end if;

	if varDefCurrencyID = 0 then 
		varMSGText ='Error Check Default (Local ) Currency in Company Screen';
		SELECT RaiseError(varMSGText);
	end if;

	if varDefCurRate = 0 then
		varMSGText ='Error Check Currency Rate For Default Currency ';
		SELECT RaiseError(varMSGText);
	end if;

	   If myrec.isinventory = true then
	   		
		  If Exists(Select ID From inv_ItemsTrans Where Operation_ID = paramOperationID) then
			 varMSGText =   'Error Check already posted Before ' ;
			 SELECT RaiseError(varMSGText);
		  End if;
		
		  INSERT into inv_ItemsTrans(operationtype_ID,Number,TransDate,invlocation_id,Operation_ID,fiscalyearperiod_ID)
		  SELECT 
			 OH.operationtype_id,OH.Number,OH.OperationDate,OH.invlocation_id,OH.ID OperationheadID
			 ,OH.fiscalyearperiod_ID
		  FROM inv_operations OH
		  INNER JOIN inv_operationsTypes OT ON OT.ID = OH.OperationType_ID
		  WHERE OH.ID = paramOperationID returning id into varItemTransHeadID;

		  
		
		  INSERT into inv_ItemsTransLine(
				itemtrans_id,itemidentifier_ID,invbinlocation_id,Quantity,itemuom_ID,unit_id
				,baseunit_ID,baseuom_id,baseequivalentquantity,baseunitfactor
				,quantitycount,price,originalprice,costprice,linetotal,lastdi
			  	
				,isbonus,item_id, expiredate ,batchnumber ,lotdate ,lotnumber ,serialnumber ,operationlineid
			 )
		  SELECT 
			 varItemTransHeadID
			 ,OD.itemidentifier_id
			 ,OD.invbinlocation_id 
			 ,OD.Quantity *  cast(myrec.luOperationKindSignValue as int)
			 ,OD.itemuom_id
			 ,OD.unit_id
			 ,OD.baseunit_id
			 ,OD.baseuom_id
			 ,OD.baseequivalentquantity * cast(myrec.luOperationKindSignValue as int)
			 ,OD.baseunitfactor
			 ,OD.quantitycount
			 ,OD.price
			 ,OD.originalprice
			 ,LastCostTable.lCostPrice
			 ,OD.linetotal
			 ,OD.lastdi
			 ,OD.isbonus
			 ,OD.item_id
			 ,OD.expiredate
			 ,OD.batchnumber
			 ,OD.lotdate
			 ,OD.lotnumber
			 ,OD.serialnumber
			 ,OD.ID
		
		
		  FROM inv_operations OH
		  INNER JOIN inv_OperationsLine OD ON OD.Operation_ID = OH.ID
		  Left Join in_GetItemsCost(0) LastCostTable On LastCostTable.ItemID =OD.Item_ID
		  WHERE OH.ID = paramOperationID;

			call in_SaveInventoryItemTrans(varItemTransHeadID);
			call in_RecalcCostByOperation(paramOperationID,loginuserid);
			Call public.in_OperationPostInventoryJour_new (paramOperationID,loginuserid);

		   Update inv_operations Set IsLocked = true ,status_ID = (Select id from sy_lookup where keyid = 10004  ) Where ID = paramOperationID;
		   
		  --EXEC sp_mms_SaveInventoryItemTrans varItemTransHeadID

		  -----=========   Next Statement Create Journal In Finance (Full Voucher) For operation
		  --Exec sp_mms_CreateOperationsJour paramOperationID

		  --Update in_operations Set IsLocked = 1 Where ID = paramOperationID;
	   End if;

    
    
end;

$$;


ALTER PROCEDURE public.in_operationpostinventory_new(paramoperationid integer, loginuserid integer) OWNER TO postgres;

--
-- Name: in_operationpostinventoryjour_new(integer, integer); Type: PROCEDURE; Schema: public; Owner: postgres
--

CREATE PROCEDURE public.in_operationpostinventoryjour_new(paramoperationid integer, loginuserid integer DEFAULT 0)
    LANGUAGE plpgsql
    AS $$
	--Select  varDecimalFraction = Cur.DecimalFraction   From in_Operations OH
	--inner join sys_Currencies Cur on Cur.id = OH.CurrencyID 
	--Where OH.ID = paramOperationID

Declare 
	varMSGText		varchar(512) = '' ;
   	varDecimalFraction	  int = 2;
	   
	varEngDesc	  varchar(4000)='';
	varArbDesc	  varchar(4000)='';

	varJourDate			date ;
	FiscalYearPeriodID	int= 0 ;
	ModuleCode			varchar(20) = '';

	varJourID		int = 0;
    StockCountPostOptionsID	 int = 0 ;

	varOldInventoryLedgerValue	   money = 0 ;
	varStckCountValueValue	   money = 0 ;

	newfcsTransTypeID integer;
	varTaxTransTypeID  integer;
	taxDueDate			date ;

	debitacc		int = 0;
	creditacc		int = 0;
	jour_amount		numeric(30,12);
	op_rec		record;
	locInfo_Rec record;
	op_parentinfo record;

Begin

	Select 
		 COALESCE(Customer_ID ,0) CustomerID 
		,COALESCE(Vendor_ID ,0) VendorID 
		,ot.code otcode
		,LU.keyID  OperationKindID
		,LU.Value OperationSign --, ITT.Sign ItemTransTypeSign 
		,LU.code kindcode
		,LU.engname kindengname
		,LU.arbname kindarbname
		,COALESCE(	TransType_id,0) fcsTransTypeID
		,COALESCE(OT.ID,0)	OperationTypeID
		,COALESCE(Status_ID ,0) OPCurrStatusID
		,COALESCE(OH.invLocation_ID,0) CurLocationID
		,COALESCE(destinationinvlocation_ID ,0) DstLocationID
		,COALESCE(GrossAmount ,0) GrossAmount
		,COALESCE(NetAmount ,0) NetAmount
		,COALESCE(TaxAmount  ,0) TotalTaxAmount
		,COALESCE(discamt1  ,0) Disc1Amount
		,COALESCE(discamt2 ,0) Disc2Amount
		,COALESCE(discamt3 ,0) Disc3Amount
		,Case When COALESCE((Select APLedger_ID from ap_vendors Where ID = Vendor_ID ),0) = 0 Then  COALESCE((Select APLedger_ID from ap_VendorsClasses Where ID = (Select VendorClass_ID From ap_Vendors Where ID = Vendor_ID)),0) Else COALESCE((Select APLedger_ID from ap_vendors Where ID = Vendor_ID ),0) End LedAPID
		,Case When COALESCE((Select ARLedger_ID from ar_Customers Where ID = Customer_ID ),0) = 0 Then  COALESCE((Select ARLedger_ID from ar_CustomersClasses Where ID = (Select CustomerClass_ID From ar_Customers Where ID = Customer_ID)),0) Else COALESCE((Select ARLedger_ID from ar_Customers Where ID = Customer_ID ),0)  End LedARID
		,OH.Number  OperationNumber
		,OperationDate  OperationDate
 		,loginuserid  RegUserID
		,Current_date RegDate
		,ITH.ID ItemTransHeadID
		,OH.Currency_ID  CurrencyID
		,1 CurrencyRate--,COALESCE(OH.CurrencyExchange ,1) CurrencyRate
		,COALESCE(OT.ledgerdisc1_id,0) Disc1LedgerID
		,COALESCE(OT.ledgerdisc2_id,0) Disc2LedgerID
		,COALESCE(OT.ledgerdisc3_id,0) Disc3LedgerID
		--,COALESCE(TaxTransTypeID ,0) TaxTransTypeID
		--,COALESCE(StockCountPrepareRefID ,0) StockCountPrepareRefID
		--,COALESCE(OH.RefObjectName ,'') RefObjectName
		--,COALESCE(OH.RefRecordID ,0) RefRecordID
		,COALESCE(OH.Parent_ID ,0) ParentID
		,COALESCE(OT.ledgergoodsonway_ID ,0) ledgergoodsonwayID
		,COALESCE(OH.totalcost ,0) 	totalcost	
		into op_rec
		from inv_Operations OH
		Inner join inv_OperationsTypes OT On OT.ID = OH.OperationType_ID
		Inner join inv_ItemsTrans ITH On ITH.Operation_id = OH.ID
		Inner Join sy_LookUp LU On LU.ID = OT.OperationKind_id 
		Where OH.ID = paramOperationID;

	If  op_rec.CurLocationID = 0 Then ----- No Location 		  
		varMSGText =   'Error Please Check Location You have to Select Location Before Post Or Operation Not inserted Into Inventory Trans' ;
		SELECT RaiseError(varMSGText);
	End if ;

	varJourDate = current_Date ;
	-- RAISE NOTICE 'value of a : %',  op_rec.OperationKindID;
	
	--Select * from sy_modules
	ModuleCode = 'IN';

	Select fyp.id 
	from sy_fiscalyears fy 
	inner join sy_fiscalyearsperiods fyp on fy.id = fiscalyear_id
	inner join sy_fiscalyearsperiodsmodules fypm on fypm.fiscalyearperiod_id = fyp.id
	inner join sy_modules m on m.id= fypm.module_id
	where m.code = ModuleCode
	and varJourDate between fyp.fromdate and fyp.todate  into FiscalYearPeriodID	;		

------======  End Next Part to Get Payment Date And Fiscal Period According date 

	Create  TEMPORARY Table TempOJL 
	(
		ID	SERIAL NOT null,  PartName  varchar(100),  PartRank	int	   ,  Rank	int	   ,  AccountType	int	   ,  AccountID	int   ,  LedgerID	int   
		,  CostCenter1ID	int	   ,  CostCenter2ID	int	   ,  CostCenter3ID	int	   ,  CostCenter4ID	int	   ,  EngDesc	varchar(512)	   ,  ArbDesc	varchar(512)	   ,  Amount	money	   
		,  AmountFC	money	   ,  Qty	real	   ,  DebitAmount	money   ,  CreditAmount	money   ,  Reverse	int   ,  CurrencyID	int   ,  CurrencyRate	real	   ,  IsReverse	boolean
	);

	Select  COALESCE(InvLedger_ID,0)  varInventoryLedgerID , COALESCE(CostSalesLedger_ID ,0)  varCostOfSalesLedgerID
		, COALESCE(PurLedger_ID,0) varPurchasesLedgerID ,COALESCE(SettleLedger_ID,0) InventorySettlementLedgerID
		, COALESCE(RPurLedger_ID ,0) varRefundPurchasesLedgerID, COALESCE(CostCenter1_ID,0) varCostCenter1ID,COALESCE(CostCenter2_ID,0) varCostCenter2ID
		, COALESCE(CostCenter3_ID ,0)  varCostCenter3ID, COALESCE(CostCenter4_ID ,0) varCostCenter4ID
	into locInfo_Rec
	From inv_inventorieslocations 
	Where ID = op_rec.CurLocationID;
		
------Select * From sy_LookUp  Where KeyName ='"RecordStatus"'
------keyid keyname			code name		name
------10001	RecordStatus	1	Initiated	تم الانشاء
------10002	RecordStatus	2	Submitted	معتمدة
------10003	RecordStatus	3	Approved	موافق عليه
------10004	RecordStatus	4	Posted	مرحل

------- parent Info
	
	Select lu.keyid , o.islocked , o.number parentNumber  ,ledgergoodsonway_ID , COALESCE(netAmount ,0) netAmount ,COALESCE( taxamount,0) taxamount 
					,COALESCE( grossamount ,0) grossamount
					,COALESCE( expenseamount,0) expenseamount , COALESCE(discamt1,0) discamt1,COALESCE( discamt2,0) discamt2 ,COALESCE(discamt3 ,0) discamt3
	into op_parentinfo	
	from inv_operations o 
	inner join inv_operationsTypes ot on ot.id = o.operationtype_id
	inner join sy_lookup lu on lu.id = ot.operationkind_id
	Where o.id = op_rec.parentid ;
	
	
	----====== Check All Variables Before Create operation Jour
	---==== Check Inventory Ledger
	---==== Check Goods On the Way Ledger From operations type
	---==== Check Parent Operation if Kind is AR or AP or IN
	---==== Check Check Currency
--IN CHECK
		--check Parent Operation if Close or not
-- 		IF  op_parentinfo.islocked = true Then
-- 			varMSGText =   'Error The Operation it was completley Deliverd ';
-- 			SELECT RaiseError(varMSGText);
-- 		End if;
		
		-- get parentid and get ledgergoodsonway to make Journal

-- 		IF Exists( Select * from ar_CustomersJour Where Operation_id = paramOperationID ) Then
-- 			varMSGText =   'Error The Operation it was Posted Before ';
-- 			SELECT RaiseError(varMSGText);
-- 		End if;
		
		If  op_rec.OPCurrStatusID = (Select ID from sy_LookUp Where  keyid = 10004) then ------ Posted	 
			varMSGText =   'Error The Operation it was Posted Before ';
			SELECT RaiseError(varMSGText);
		End if;

		If  op_rec.OPCurrStatusID <> (Select ID from sy_LookUp Where  keyid = 10003) then ------ Approved	موافق عليه   keyname = 'RecordStatus' 
			varMSGText =   'Error The Operation Not Approved You Have Make Approve Before Post ';
			SELECT RaiseError(varMSGText);
		End if;
		
		

		
		if COALESCE(op_rec.fcsTransTypeID ,0) = 0 then
				if not exists(Select * from gl_transtypes Where lower(code) = lower( op_rec.kindcode || '\' || op_rec.otcode) ) then
					insert into gl_transtypes (code , Engname , arbname , alloweditdate,alloweditnumber ,ismanual,transkind_id,remarks 
					,isreceipt,iscash,ischeck,iscreditcard,iscollectorneeded,iscashdisc,useref1,useref2,istaxtrans,isautoposttogl )
					values( op_rec.kindcode || '\' || op_rec.otcode  ,op_rec.kindengname ,op_rec.kindarbname ,false ,false,false,(select id from sy_lookup where keyid =53 limit 1),'This is Trans Created automatic from Operation' 
					,false,false,false,false,false,false,false,false,false,false	)
 					returning id  into newfcsTransTypeID; 
					update inv_operationstypes Set transtype_id = newfcsTransTypeID Where id = op_rec.OperationTypeID;
					op_rec.fcsTransTypeID = newfcsTransTypeID;
				
				else
					Select id into  newfcsTransTypeID from gl_transtypes Where lower(code) = lower( op_rec.kindcode || '\' || op_rec.otcode);
					
				end if;

		else
			Select id into  newfcsTransTypeID from gl_transtypes Where lower(code) = lower( op_rec.kindcode || '\' || op_rec.otcode);

		End if;

		if COALESCE(newfcsTransTypeID ,0) = 0 then
			varMSGText =   'Error system cant create trans type Please call support';
			SELECT RaiseError(varMSGText);

		end if;

		IF (Select count(*) From inv_inventorieslocations Where id = op_rec.CurLocationID  
				and ( COALESCE(invledger_id,0) = 0   or COALESCE(slsledger_id,0) = 0 or COALESCE(rslsledger_id,0) = 0 or COALESCE(costsalesledger_id,0) = 0 ) ) >0  then
				varMSGText =   'Error Inventory Accounts Setting  Not Selected';
				SELECT RaiseError(varMSGText);  
		End if;
-- INVENTORY ----====== Inventory PartName
		----====== Start Inventory Voucher
		
		IF op_parentinfo.keyid = 3202  then  ---- cash sales
			debitacc  = locInfo_Rec.varCostOfSalesLedgerID;
			creditacc = locInfo_Rec.varInventoryLedgerID ;
			jour_amount = op_rec.totalcost ;
		else if op_parentinfo.keyid = 3203  then  ---- Return Cash Sales
			debitacc  = locInfo_Rec.varInventoryLedgerID;
			creditacc = locInfo_Rec.varCostOfSalesLedgerID ;
			jour_amount = op_rec.totalcost ;

		else if op_parentinfo.keyid = 3204  then  ---- credit Sales
			debitacc  = locInfo_Rec.varCostOfSalesLedgerID;
			creditacc = locInfo_Rec.varInventoryLedgerID ;
			jour_amount = op_rec.totalcost ;

		else if op_parentinfo.keyid = 3205  then  ---- Refund Credit Sales
			debitacc  = locInfo_Rec.varInventoryLedgerID;
			creditacc = locInfo_Rec.varCostOfSalesLedgerID ;
			jour_amount = op_rec.totalcost ;

		else if op_parentinfo.keyid = 3206  then  ---- cash Puchase
			debitacc  =  locInfo_Rec.varInventoryLedgerID ;
			creditacc = op_parentinfo.ledgergoodsonway_id ;
			jour_amount =  op_parentinfo.grossamount  + op_parentinfo.expenseamount  - op_parentinfo.discamt1  - op_parentinfo.discamt2 - op_parentinfo.discamt1   ;
		else if op_parentinfo.keyid = 3207  then  ---- Refund cash Puchase
			debitacc  =  op_parentinfo.ledgergoodsonway_id   ;
			creditacc = locInfo_Rec.varInventoryLedgerID;
			jour_amount =  op_parentinfo.grossamount  + op_parentinfo.expenseamount  - op_parentinfo.discamt1  - op_parentinfo.discamt2 - op_parentinfo.discamt1   ;

		else if op_parentinfo.keyid = 3208  then  ---- Credit Puchase
			debitacc  =  locInfo_Rec.varInventoryLedgerID ;
			creditacc = op_parentinfo.ledgergoodsonway_id ;
			jour_amount =  op_parentinfo.grossamount  + op_parentinfo.expenseamount  - op_parentinfo.discamt1  - op_parentinfo.discamt2 - op_parentinfo.discamt1   ;

		else if op_parentinfo.keyid = 3209  then  ---- Refund Credit Puchase
			debitacc  =  op_parentinfo.ledgergoodsonway_id   ;
			creditacc = locInfo_Rec.varInventoryLedgerID;
			jour_amount =  op_parentinfo.grossamount  + op_parentinfo.expenseamount  - op_parentinfo.discamt1  - op_parentinfo.discamt2 - op_parentinfo.discamt1   ;

		else if op_parentinfo.keyid = 3210  then  ---- Adj +
			debitacc  =  1 ;
			creditacc = 1 ;
			jour_amount = op_rec.totalcost ;
		else if op_parentinfo.keyid = 3211  then  ---- Adj -
			debitacc  =  1 ;
			creditacc = 1 ;
			jour_amount = op_rec.totalcost ;
		else if op_parentinfo.keyid = 3213  then  ---- Physical Count Post
			debitacc  =  1 ;
			creditacc = 1 ;
			jour_amount = op_rec.totalcost ;
		else if op_parentinfo.keyid = 3214  then  ---- Transfer Out
			debitacc  =  1 ;
			creditacc = 1 ;
			jour_amount = op_rec.totalcost ;
		else if op_parentinfo.keyid = 3215  then  ---- Transfer In
			debitacc  =  1 ;
			creditacc = 1 ;
			jour_amount = op_rec.totalcost ;
		else if op_parentinfo.keyid = 3216  then  ---- Direct Transfer
			debitacc  =  1 ;
			creditacc = 1 ;
			jour_amount = op_rec.totalcost ;
		else if op_parentinfo.keyid = 3217  then  ---- Change Cost
			debitacc  =  1 ;
			creditacc = 1 ;
			jour_amount = op_rec.totalcost ;

		end if;
		end if;
		end if;
		end if;
		end if;
		end if;
		end if;
		end if;
		end if;
		end if;
		end if;
		end if;
		end if;
		end if;
		end if;

		RAISE NOTICE 'value of a : %',  op_parentinfo.ParentNumber ;
		
		varEngDesc	    = 'Inventory Ref = ' || op_rec.OperationNumber  || ' : Parent Ref = ' || op_parentinfo.ParentNumber;
		varArbDesc	    = 'Inventory Ref = ' || op_rec.OperationNumber || ' : Parent Ref = ' || op_parentinfo.ParentNumber; 
		Insert Into TempOJL 
		(
			PartName  ,  PartRank	,  Rank	,  AccountType	,  AccountID	,  LedgerID	
			--,  CostCenter1ID	,  CostCenter2ID	,  CostCenter3ID	,  CostCenter4ID	
			,  EngDesc	,  ArbDesc	,  Amount	
			,  AmountFC	,  Qty	,  DebitAmount	,  CreditAmount	,  Reverse	,  CurrencyID	,  CurrencyRate	,  IsReverse	
		)

		-- Debit Side
		Select 'Inventory' As PartName  ,  1 PartRank	 ,1 Rank , 90001 AccountTypeID , debitacc  AccountID , debitacc
				--, null CostCenter1ID	,null  CostCenter2ID	,null  CostCenter3ID	,null  CostCenter4ID	
				,   varEngDesc ,   varArbDesc , 1 *   Abs(jour_amount  ) Amount 
				, 1 *   Abs(jour_amount  ) AmountFC  , 1 As Qty 
				,Abs(jour_amount ) DebitAmount 
				,0  CreditAmount 
				,1 Reverse ,op_rec.CurrencyID , op_rec.CurrencyRate  , False IsReverse
		from inv_Operations OH
		Where OH.ID = paramOperationID

		Union All

		-- Credit Side
		Select 'Inventory' As PartName  ,  2 PartRank ,1 Rank,90001 AccountTypeID , creditacc AccountID , creditacc  
				--, null CostCenter1ID	,null  CostCenter2ID	,null  CostCenter3ID	,null  CostCenter4ID	
				,  varEngDesc ,  varArbDesc , -1 *   Abs(jour_amount ) Amount 
				, -1 *   Abs(jour_amount  ) AmountFC  , 1 As Qty 
				,0  DebitAmount 
				--,Abs(op_rec.NetAmount  - op_rec.TotalTaxAmount )    CreditAmount 
				,Abs(jour_amount ) CreditAmount 
				,1 Reverse ,op_rec.CurrencyID , op_rec.CurrencyRate  , False IsReverse

		from inv_Operations OH
		Where OH.ID = paramOperationID;
		----====== End Inventory PartName

		-------=========  Start Create Journal

		If (Select Sum(Amount) From TempOJL) <> cast(0 as money) then
				varMSGText =   'Error The Voucher Not Balanced Check Your Setting';
				SELECT RaiseError(varMSGText);  
		End if;
				    
		
		Insert Into gl_ledgerjour  (  
			TransType_ID
			,JournalNumber
			,JournalDate,JournalYear,FiscalYearPeriod
			,reference1,ConfirmDate                 ,PostDate     ,created_by_id ,created_date
			,Remarks,IsLocked,Operation_id,Status_ID 
			,TotalAmount,Currency_ID,CurrencyRate  ,itemtransid 
			)
				
		Select newfcsTransTypeID TransTypeID
			,cast( (Select code From gl_transtypes Where id =newfcsTransTypeID ) as varchar(20)) || '-' || cast(   (Select Count(*) +1 from gl_LedgerJour where transtype_id = newfcsTransTypeID) as varchar(20))  Number 
			,current_date varJourDate ,EXTRACT(YEAR FROM OperationDate) JourYear ,FiscalYearPeriodID 
			, Number   Reference , null  ConfirmDate ,null PostDate ,loginuserid ,current_date
			,Remarks, True IsLocked , ID Operation_id ,null StatusID --- @JourStatusID 
			,(Select Sum(DebitAmount) From TempOJL)  NetAmount ,op_rec.CurrencyID,op_rec.CurrencyRate   , op_rec.ItemTransHeadID
		from inv_Operations 
		Where ID = paramOperationID  returning id into varJourID ;

					

		Insert into gl_LedgerJourLine (
			ledgerjour_ID,Rank
			--,AccountType_id 
			,Ledger_ID
			--,customer_ID 
			,CostCenter1_ID,CostCenter2_ID,CostCenter3_ID,CostCenter4_ID,EngDesc,ArbDesc
			,DebitAmount ,CreditAmount  ,Amount,Qty,Currency_ID,CurrencyRate,Reverse
			) 
		Select 
			varJourID JourHeadID ,Rank
			--, (Select id from sy_lookup where keyid = AccountType ) AccountType  
			,LedgerID --case when  AccountType = 90001 then  AccountID else null end  LedgerID
			--,  case when  AccountType = 90003 then  AccountID else null end  AccountID 
			, CostCenter1ID,CostCenter2ID,CostCenter3ID,CostCenter4ID ,EngDesc,ArbDesc
			,DebitAmount ,CreditAmount ,Amount, 0 Qty ,op_rec.CurrencyID,op_rec.CurrencyRate ,1 Reverse 
			From  TempOJL
			Where TempOJL.Amount <> cast(0 as money) ;

		varEngDesc	    = 'Ref = Invoice Number = ' || op_rec.OperationNumber ;
		varArbDesc	    = 'Ref = Invoice Number = ' || op_rec.OperationNumber ;
	 RAISE NOTICE 'value of a : %',  'khaldoun';

		Insert Into gl_LedgerTrans (
		TransType_ID,Ledger_ID,CostCenter1_ID,CostCenter2_ID,CostCenter3_ID,CostCenter4_ID,TransDate,DocNumber
		,Operation_id,customerjour,EngDesc,ArbDesc,Amount,AmountFC,SettleAmount
		,Currency_ID,CurrencyRate,DueDate,LastSettleDate,closedate,approvalby_ID,approvaldate
		,created_by_id,created_date,FiscalYearPeriod
		)
		Select 
			newfcsTransTypeID TransTypeID , LedgerID ,CostCenter1ID,CostCenter2ID,CostCenter3ID,CostCenter4ID ,current_date varJourDate ,op_rec.OperationNumber 
			, paramOperationID,varJourID ,COALESCE(EngDesc,'') EngDesc,COALESCE(ArbDesc ,'') ArbDesc ,Amount,AmountFC ,0 SettleAmount
			,op_rec.CurrencyID,op_rec.CurrencyRate ,null DueDate , null LastSettleDate , null Closed , loginuserid  ApprovedByID , current_date  ApprovedDate
			,loginuserid ,current_date ,FiscalYearPeriodID
		From  TempOJL
		Where TempOJL.Amount <> cast(0 as money) ;
		-------=========  End Create Journal 

		drop Table TempOJL;			    				

end;

$$;


ALTER PROCEDURE public.in_operationpostinventoryjour_new(paramoperationid integer, loginuserid integer) OWNER TO postgres;

--
-- Name: in_operationsubmit(integer, integer); Type: PROCEDURE; Schema: public; Owner: postgres
--

CREATE PROCEDURE public.in_operationsubmit(operationid integer DEFAULT 0, loginuserid integer DEFAULT 0)
    LANGUAGE plpgsql
    AS $$
Declare 
		statuskeyid	int = 0;
		statussubmitid int =0;
declare myrec record;
Declare 
	varMSGText		varchar(512) = '' ;

begin
	--Select  varOperationsStatus = COALESCE(Status_ID ,0),varOperationsStatuschangeby = statuschangedby_id   From inv_Operations Where ID = operationid ;
	Select COALESCE(Status_ID ,0) as oldStatusID ,statuschangedby_id as oldstatuschangedbyid ,statusdate as oldstatusdate  into myrec  
		From inv_Operations Where ID = operationid ;
		
	Select keyid  from sy_lookup Where id = myrec.oldStatusID into statuskeyid;
	if COALESCE(statuskeyid ,0) > 10001 then
		varMSGText =   'Error Operation Submited Before';
		SELECT RaiseError(varMSGText);
	end if;

	
	Select id  from sy_lookup Where keyid = '10002' into statussubmitid;

	insert into inv_OperationsStatusLog (operation_id,status_id,statusdate,statuschangedby_id)
	Select operationid , myrec.oldStatusid , myrec.OLDstatusdate,myrec.oldstatuschangedbyid ;
		

	If statuskeyid In ( 0 , 10001 ) then
		Update inv_Operations Set Status_ID = statussubmitid , statuschangedby_id = loginuserid ,statusdate = current_date Where ID = OperationID And COALESCE(wfStatus_ID ,0) = 0 ;
	End if;

end;
$$;


ALTER PROCEDURE public.in_operationsubmit(operationid integer, loginuserid integer) OWNER TO postgres;

--
-- Name: in_recalccostbyoperation(integer, integer); Type: PROCEDURE; Schema: public; Owner: postgres
--

CREATE PROCEDURE public.in_recalccostbyoperation(paramoperationid integer, loginuserid integer DEFAULT 0)
    LANGUAGE plpgsql
    AS $$

    DECLARE 
		FromDate				date;
		varIsEffectingItemCostPrice	boolean = false;
	
	DECLARE 
		Cur_Items RECORD;
		Cur_Trans RECORD;

	declare myrec record;
	Declare 
		varOpen_ItemBal Numeric(18, 10) ;
		varCur_ItemBal  Numeric(18, 10);
		varold_cost	    Numeric(18, 10);
		varCur_Cost	    Numeric(18, 10);
		varNewAvgCost   Numeric(18, 10);
	
BEGIN

		 RAISE NOTICE 'value of a : %',  'Start';
    SELECT 
	
	    cast(Oh.OperationDate - INTERVAL '1 day' as date) FromDate
	  , COALESCE(EffectCostPrice  ,  false) varIsEffectingItemCostPrice
  	into myrec
    FROM inv_Operations OH
	Inner join inv_Operations OHparent On oh.parent_id = OHparent.ID
    Inner Join inv_OperationsTypes  OT On OHparent.OperationType_ID = OT.ID

    WHERE OH.ID = paramOperationID;

	RAISE NOTICE 'value of a : varIsEffectingItemCostPrice %',  myrec.FromDate;

    IF myrec.varIsEffectingItemCostPrice = true then
	   Delete from inv_ItemsCosts WHERE Cast(TransDate As Date ) >=  myrec.FromDate   AND Item_ID IN (SELECT Item_ID FROM inv_Operationsline WHERE Operation_ID = paramOperationID) ;

		FOR Cur_Items in
			Select 	 I.ID
			from inv_Items I
			Where I.ID IN (SELECT Item_id FROM inv_Operationsline WHERE Operation_ID = paramOperationID)
		LOOP
		varOpen_ItemBal = COALESCE((Select SUM(rqtybalance) rqtybalance  from in_GetItemsBalancesView (myrec.FromDate  ,   false  ,  0  ,  false  ,  false) Where rItem_ID =  Cur_Items.ID )  ,  0) ;
		varold_cost = COALESCE((Select CostPrice From inv_ItemsCosts Where Item_ID = Cur_Items.ID   Order by TransDate desc limit 1)  ,  0) ;

		RAISE NOTICE 'value of a : varOpen_ItemBal %',  varOpen_ItemBal;
		RAISE NOTICE 'value of a : varold_cost %',  varold_cost;
		
		FOR Cur_Trans in
			
		   Select 
		   H.TransDate  ,  H.invlocation_ID  ,  D.Quantity  ,  D.itemuom_ID  ,  COALESCE(D.CostPrice  ,  0) TCostPrice 
		   ,  (Select  CostPrice From inv_ItemsCosts IC Where IC.item_ID = D.Item_ID And IC.TransDate <= H.TransDate Order by TransDate Desc limit 1 ) ICCostprice
		   ,  OH1.EngName  ,  OH1.Price  ,  OH1.CostPrice  ,  OH1.LineTotal	  ,  OH1.ID
		   ,  EngName ITT_EngName
		   ,  OH1.Discount1 Disc1  ,  OH1.Discount2 Disc2  ,  OH1.Discount3 Disc3  ,  COALESCE(IsEffectingItemCostPrice  ,  false) IsEffectingItemCostPrice		
		   ,  baseunitfactor  ,  D.itemuom_id  ,  D.ID	ITDID  ,  H.ID	ITHID  ,  (Select  id From inv_warehouses S limit 1  ) StoreCostGroupID  ,  OHDisc1  ,  OHDisc2
		   ,	  D.LastDI , D.baseequivalentquantity ,D.unit_id
		   from inv_ItemsTrans H 
		   Inner join inv_ItemsTransline D On H.ID = D.ItemTrans_ID  
		   Left join 
		   (
		   Select 
		   OH.ID  ,  OT.EngName  ,   OD.Price  ,   OD.CostPrice  ,   OD.LineTotal  ,   OD.discamt1 Disc1  ,   OD.discamt2 Disc2  ,   OD.discamt3 Disc3  
			   ,   COALESCE(EffectCostPrice  ,  true) IsEffectingItemCostPrice  ,   OD.Item_ID  --,   OT.ItemTransTypeID
		   ,  COALESCE(OD.discamt1  ,  0) Discount1  ,   COALESCE(OD.discamt2  ,  0) Discount2  ,   COALESCE(OD.discamt3  ,  0) Discount3  
			   ,   Itemuom_ID  ,   OD.ID ODID  ,   COALESCE(OH.discamt1  ,  0) OHDisc1  ,   COALESCE(OH.discamt2  ,  0) OHDisc2 

		   from inv_Operations OH 
		   Inner join inv_Operationsline OD On OH.ID = OD.Operation_ID 
		   --Inner Join inv_OperationsTypes OT On OT.ID = OH.OperationType_ID
			Inner join inv_Operations OHparent On oh.parent_id = OHparent.ID
			Inner Join inv_OperationsTypes  OT On OHparent.OperationType_ID = OT.ID

		   )OH1 On OH1.ODID = D.OperationLineID 
		   --cross Apply [dbo].[fn_UnitConvert](D.UnitOfMeasurementID  ,  0  ,  0 ) fnUnit1
		   Where D.Item_ID = Cur_Items.ID AND TransDate >= myrec.FromDate
		   Order by TransDate Asc  ,  ODID Asc

		LOOP 
	
		if Cur_Trans.IsEffectingItemCostPrice	= true then
			if Cur_Trans.baseequivalentquantity + varOpen_ItemBal >0  then
				if varOpen_ItemBal > 0  then
					varNewAvgCost = Case When Cur_Trans.Quantity + varOpen_ItemBal >0 Then 
							COALESCE(((varOpen_ItemBal * COALESCE(varold_cost  ,  0)) + (Cur_Trans.LineTotal * Cur_Trans.LastDI ) )
									 /( (Cur_Trans.baseequivalentquantity)  + varOpen_ItemBal)  ,  0)
			   				Else
								COALESCE(Cur_Trans.ICCostprice  ,  0)
			   				End ;
				Else

					varNewAvgCost = COALESCE( Cur_Trans.LineTotal/ (Cur_Trans.baseequivalentquantity)  ,  0) - Abs(COALESCE(Cur_Trans.OHDisc1  ,  0) * (Cur_Trans.LineTotal/ (Cur_Trans.baseequivalentquantity))/ 100)	;
				End if;
			Else
				varNewAvgCost = COALESCE( Cur_Trans.LineTotal/ (Cur_Trans.baseequivalentquantity)  ,  0) - Abs(COALESCE(Cur_Trans.OHDisc1  ,  0) * (Cur_Trans.LineTotal/ (Cur_Trans.baseequivalentquantity))/ 100);
			End if;

			update inv_ItemsTransline Set CostPrice = varold_cost , NewCostPrice = varNewAvgCost --, TotalOldQty =varOpen_ItemBal 
				--, CurLocationOldQty = (Select  rqtybalance from inv_GetItemsBalancesView(myrec.FromDate,   false  ,  0  ,  false  , false)
				--				   Where Item_ID = Cur_Items.ID  And rinvlocation_ID = Cur_Trans.invlocation_ID limit 1 )  
			Where ID = Cur_Trans.ITDID ;

			update inv_Operationsline Set CostPrice = varold_cost , NewCostPrice = varNewAvgCost  Where ID = (Select  OperationlineID From inv_ItemsTransLine Where ID = Cur_Trans.ITDID limit 1 ) ; 
				
			
			Insert into inv_ItemsCosts (Item_ID  ,  warehouse_ID  ,  TransDate    ,  CostPrice  ,  unit_ID , itemuom_id ,itemtransid,itemtranslineid)
			(Select   Cur_Items.ID  ,  Cur_Trans.StoreCostGroupID  ,  Cur_Trans.Transdate  ,   varNewAvgCost  ,  Cur_Trans.unit_id, Cur_Trans.itemuom_id ,   Cur_Trans.ITHID  ,  Cur_Trans.ITDID  );

			varOpen_ItemBal = varOpen_ItemBal + (Cur_Trans.baseequivalentquantity);
			varold_cost = varNewAvgCost;
	 	Else

			

			update inv_ItemsTransline Set CostPrice = varold_cost , NewCostPrice = varNewAvgCost  
			--, TotalOldQty =varOpen_ItemBal 
			--, CurLocationOldQty = (Select rqtybalance from inv_GetItemsBalancesView(myrec.FromDate,   false  ,  0  ,  false  , false) Where rItem_ID = Cur_Items.ID  And rinvLocation_ID = Cur_Trans.invlocation_ID )  
			Where ID = Cur_Trans.ITDID ;
			update inv_Operationsline Set CostPrice = varold_cost , NewCostPrice = varNewAvgCost  Where ID = Cur_Trans.ITDID ;
			varOpen_ItemBal = COALESCE(varOpen_ItemBal  ,  0)+ COALESCE((Cur_Trans.baseequivalentquantity)  ,  0);
		end if;
	END LOOP;   -- end loop Cur_Trans

		varOpen_ItemBal = 0 ;
		varold_cost = 0;
		varNewAvgCost = 0;
	END LOOP;   -- end loop Items
	end if;
END;

$$;


ALTER PROCEDURE public.in_recalccostbyoperation(paramoperationid integer, loginuserid integer) OWNER TO postgres;

--
-- Name: in_rpinventitemscardex(date, date, character varying, character varying, character varying, character varying, character varying, character varying, character varying, character varying, character varying); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.in_rpinventitemscardex(pfromdate date, ptodate date, plikeitemcode character varying DEFAULT ''::character varying, pfromitemcode character varying DEFAULT ''::character varying, ptoitemcode character varying DEFAULT ''::character varying, plikestorecode character varying DEFAULT ''::character varying, pfromstorecode character varying DEFAULT ''::character varying, ptostorecode character varying DEFAULT ''::character varying, plikeloccode character varying DEFAULT ''::character varying, pfromloccode character varying DEFAULT ''::character varying, ptoloccode character varying DEFAULT ''::character varying) RETURNS TABLE(trowno bigint, rowtotqty numeric, identrowtotqty numeric, tcode character varying, tengname character varying, tarbname character varying, tautotransdetid bigint, tbarcode character varying, totid bigint, totcode character varying, totengname character varying, totarbname character varying, ttransdate date, tnumber character varying, toriginalprice numeric, topenbal numeric, tvendor character varying, tdepartment character varying, tdestlocation character varying, texpirydate date, tbatchno character varying, tquantityin numeric, tquantityout numeric, tquantity numeric, tquantitycount numeric, tuomid integer, tbaseuomeqqty numeric, tbaseunitfactor numeric, tuomid1 integer, tucode character varying, tuengname character varying, tuarbname character varying, tlid integer, tlcode character varying, tlengname character varying, tlarbname character varying, twarehouseid integer, twhcode character varying, twhengname character varying, twharbname character varying, tdcostprice numeric, tdid bigint, titemidentifierid integer, tengref character varying, tarbref character varying)
    LANGUAGE plpgsql
    AS $$

DECLARE 
	pOpenBalanceDate  date ;

BEGIN
	pOpenBalanceDate = cast(pFromDate - INTERVAL '1 day' as date)  ;

return query 

SELECT 
	   ROW_NUMBER() Over(Order by TransDate, DID) RowNo  
	   , Sum(BaseUnitofMeasurementEquivalentQty) Over  (Order by TransDate, DID) RowTotQty 
	   ,cast(0 as numeric) IdentRowTotQty 
	   --,ItemIdentifierID
    ,* 
    FROM(
	SELECT 
     I.Code , I.EngName ,I.ArbName ,cast(0 as bigint) AutoTransDetID
    ,I.Code    BarCode , cast(0 as bigint) OTID, cast('0' as varchar(100))   OTCode ,cast('Open Balance' as varchar(100))  OTEngName  , cast('Open Balance' as varchar(100))  OTArbName 
    ,pOpenBalanceDate TransDate  , cast('0' as varchar(100)) Number 
	,(select CostPrice from inv_ItemsCosts ic where ic.TransDate <=pOpenBalanceDate AND Item_ID = I.ID ORDER BY ID DESC  limit 1) originalprice
    ,(Select  rqtybalance  From in_GetItemsBalancesView(pOpenBalanceDate,false,0,false,false) BV1  Where BV1.rItem_ID = I.ID AND BV1.rinvLocation_ID = L.ID limit 1) OpenBal
	,cast( '' as varchar(100)) Vendor
	,cast( '' as varchar(100))  Department
	,cast( '' as varchar(100))  DestLocation
	,null  ExpiryDate
	,cast( '' as varchar(100))  BatchNo
    ,Case When BV.rqtybalance >= 0 Then CAST(BV.rqtybalance  as numeric) Else 0 End QuantityIn
	,Case When BV.rqtybalance < 0 Then CAST(BV.rqtybalance  as numeric) Else 0 End QuantityOut
    ,CAST(BV.rqtybalance  as numeric) Quantity,CAST(BV.rqtybalance  as numeric) QuantityCount ,UOM.ID UnitofMeasurementID   ,BV.rqtybalance BaseUnitofMeasurementEquivalentQty , cast(1 as numeric) BaseUnitFactor 
    ,UOM.ID UOMID ,U.Code UCode , U.engname UengName , U.Arbname Uarbname
    ,L.ID LID,L.Code LCode ,L.EngName LEngName ,L.ArbName LArbName
    ,s.id StoreID,S.Code SCode ,S.EngName SEngName ,S.ArbName SArbName
	,(select CostPrice from inv_ItemsCosts ic where ic.TransDate <=pOpenBalanceDate AND Item_ID = I.ID ORDER BY ID DESC  limit 1) DCostPrice
	,cast(0 as bigint) DID
	,rItemIdentifier_ID 
	,cast( '' as varchar(100))  engref
	,cast( '' as varchar(100))  arbref
		
FROM inv_Items I
	Left JOIN inv_ItemsInventoriesLocations IL ON I.ID = IL.Item_ID
	INNER JOIN inv_InventoriesLocations L ON L.ID = IL.invLocation_ID
	INNER JOIN inv_Warehouses S ON S.ID = L.Warehouse_ID
	INNER JOIN in_GetItemsBalancesView(pOpenBalanceDate,false,0,false,false) BV  ON BV.rItem_ID = I.ID AND BV.rinvLocation_ID = L.ID
	INNER JOIN inv_ItemsUOM UOM ON UOM.ID = BV.ritemUOM_ID
	Inner  Join inv_Units U On U.ID = UOM.Unit_ID
WHERE 
	BV.rItem_ID = I.ID 
	AND I.Code = pLikeItemCode  
	AND S.CODE LIKE pLIKESTORECODE || '%'
	AND S.CODE BETWEEN pFROMSTORECODE || ' ' AND pTOSTORECODE || 'ZZZ'
	AND L.CODE LIKE pLIKELOCCODE || '%'
	AND L.CODE BETWEEN pFROMLOCCODE || ' ' AND pTOLOCCODE || 'ZZZ'

UNION All

Select 

 I.Code , I.EngName ,I.ArbName ,AutoTransDetID
,II.BarCode ,COALESCE(OTID,1000) OTID,COALESCE(OTCode,'') ,COALESCE(OTEngName,'') ,COALESCE(OTArbName,'') 
,TransDate  , Number 
,originalprice
,cast(0 as numeric) OpenBal
, Vendor
, Department
, COALESCE(DestLocation ,'') DestLocation
, ExpiryDate
, BatchNo
,QuantityIn ,QuantityOut 
,Quantity ,QuantityCount ,vw.itemuom_ID   ,baseequivalentquantity ,baseunitfactor 
,vw.UOMID 
--,UCode , UengName , Uarbname
,U.Code UCode , U.engname UengName , U.Arbname Uarbname
,LID,LCode ,LEngName ,LArbName
,StoreID,SCode ,SEngName ,SArbName
,DCostPrice
,DID
,ItemIdentifier_ID 
,engref
,arbref
		
From 
inv_Items I 
Inner join inv_ItemsIdentifiers  II On I.ID = II.Item_ID 
Inner  Join inv_Units U On U.ID = I.baseunit_id
INNER Join 
(
	Select 
	 H.TransDate  , COALESCE(OH.Number ,H.Number) Number
	,OT.ID OTID,OT.Code OTCode,OT.EngName  OTEngName ,OT.ArbName  OTArbName 
	,H.ID AutoTransHeadID,D.ID AutoTransDetID
	,D.ItemIdentifier_ID  
	,originalprice
	,CAST(Case When D.baseequivalentquantity  >= 0 Then D.baseequivalentquantity  Else 0 End AS numeric(18,4)) QuantityIn
	,CAST(Case When D.baseequivalentquantity  < 0 Then Abs(D.baseequivalentquantity)  Else 0 End AS numeric(18,4)) QuantityOut
	,D.Quantity ,D.QuantityCount ,D.itemuom_ID   ,D.baseequivalentquantity ,D.baseunitfactor
	,COALESCE(V.EngName,V.ArbName) AS Vendor
	,COALESCE(CC.EngName,CC.ArbName) AS Department
	,Dl.Code DestLocation
	,II.expiredate AS ExpiryDate
	,II.batchnumber AS BatchNo
	,UOM.ID UOMID 
	--,U.Code UCode , U.engname UengName , U.Arbname Uarbname
	,L.ID LID,L.Code LCode,L.EngName  LEngName ,L.ArbName  LArbName
	,S.ID StoreID,S.Code SCode ,S.EngName  SEngName ,S.ArbName  SArbName
	,D.CostPrice DCostPrice
	,D.ID DID
	,engref
	,arbref
	From inv_ItemsTrans H
	Inner Join inv_ItemsTransline D on H.ID = D.ItemTrans_ID 
	Inner Join inv_InventoriesLocations L On L.ID = H.invLocation_ID 
	Inner Join inv_Warehouses S On S.ID = L.Warehouse_ID 
	Inner Join inv_ItemsUOM UOM On UOM.ID = D.baseuom_ID  
	--Inner  Join inv_Units U On U.ID = UOM.Unit_ID

	LEFT JOIN inv_Operations OH ON OH.ID = H.Operation_ID
	Left Join(
		Select parentOP.ID  ParentID ,op.id mainopid
			,case When COALESCE(parentOP.ledger_id) <> 0 Then
				'Ref. No = ' || parentOP.number || ' - Trans = '|| COALESCE(parentOPType.engName,'') || ' - Ledger = ' || ( Select code || ':' || engname from gl_ledger Where id = ParentOP.Ledger_ID) 
			else case When COALESCE(parentOP.vendor_id) <> 0 Then 
				'Ref. No = ' || parentOP.number || ' - Trans = '|| COALESCE(parentOPType.engName,'') || ' - Vendor = ' || ( Select code || ':' || engname from ap_Vendors Where id = ParentOP.vendor_ID)
			else case When COALESCE(parentOP.customer_id) <> 0 Then 
				'Ref. No = ' || parentOP.number || ' - Trans = '|| COALESCE(parentOPType.engName,'') ||' - Customer =' ||   ( Select code  || ':' || engname from ar_customers Where id = ParentOP.Customer_ID)	
			end
			end
			end engref

			,case When COALESCE(parentOP.ledger_id) <> 0 Then
				'Ref. No = ' || parentOP.number || ' - Trans = '|| COALESCE(parentOPType.arbName,'') || ' - حساب = ' || ( Select COALESCE(code,'') || ':'|| COALESCE(arbname,'') from ar_customers Where id = ParentOP.Customer_ID) 
			else case When COALESCE(parentOP.vendor_id) <> 0 Then 
				'Ref. No = ' || parentOP.number || ' - Trans = '|| COALESCE(parentOPType.arbName) || ' - مورد = ' || ( Select COALESCE(code,'') || ':' || COALESCE(arbname,'') from ap_Vendors Where id = ParentOP.vendor_ID)
			else case When COALESCE(parentOP.customer_id) <> 0 Then 
				'Ref. No = ' || parentOP.number || ' - Trans = '|| COALESCE(parentOPType.arbName) || ' - عميل =' || ( Select COALESCE(code,'') || ':'|| COALESCE(arbname,'') from ar_customers Where id = ParentOP.Customer_ID)	
			end
			end
			end arbref

		from inv_operations op
		left Join inv_operations ParentOP on op.Parent_id = ParentOP.id
		left join inv_operationsTypes parentOPType on parentOPType.ID = ParentOP.Operationtype_id
		--limit 1
	) Parentinfo On Parentinfo.ParentID = oh.Parent_ID and Parentinfo.mainopid = oh.id
	
	LEFT JOIN inv_OperationsTypes OT ON OT.ID = OH.OperationType_ID
	LEFT JOIN ap_Vendors V ON OH.Vendor_ID = V.ID
	LEFT JOIN gl_CostCenters CC ON OH.CostCenter1_ID = CC.ID
	Left Join inv_InventoriesLocations DL On DL.ID = OH.destinationinvlocation_ID 
	left join inv_ItemsIdentifiers II ON D.itemidentifier_ID = ii.ID
	Where 	 H.Transdate Between pFromDate	And pToDate			
	And S.Code Like pLikeStoreCode || '%'
	And S.Code Between pFromStoreCode || ' ' And pToStoreCode || 'zzz'
	And L.Code Like pLikeLocCode || '%'
	And L.Code Between pFromLocCode || ' ' And pToLocCode || 'zzz'
) VW On vw.ItemIdentifier_ID = II.ID 
Where 
	I.Code = pLikeItemCode  
	And I.Code Between pFromItemCode || ' ' And pToItemCode || 'zzz'
	
)V

Order by   TransDate;

end;

$$;


ALTER FUNCTION public.in_rpinventitemscardex(pfromdate date, ptodate date, plikeitemcode character varying, pfromitemcode character varying, ptoitemcode character varying, plikestorecode character varying, pfromstorecode character varying, ptostorecode character varying, plikeloccode character varying, pfromloccode character varying, ptoloccode character varying) OWNER TO postgres;

--
-- Name: in_rpinventitemsjournal(character varying, character varying, character varying, character varying, character varying, character varying, character varying, character varying, character varying, character varying, character varying, date, date, character varying, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.in_rpinventitemsjournal(plikecustcode character varying, plikevendcode character varying, plikeslscode character varying, plikeusercode character varying, plikeitmcode character varying, pintrncode character varying, plikeloccode character varying, pvchno character varying, preferancenumber character varying, pshortdescription character varying, prequiredfor character varying, pfromdate date, puptodate date, poperationcat character varying, plang integer) RETURNS TABLE(ohid integer, vchdate date, strcode character varying, customercode character varying, customername character varying, vendorcode character varying, vendorname character varying, transname character varying, vchno character varying, dsstrcode character varying, dsstrname character varying, dsdeptcode character varying, dsdeptname character varying, referancenumber character varying, shortdescription character varying, requiredfor character varying, slscode character varying, slsname character varying, usrcode character varying, username character varying, itmcode character varying, itmname character varying, qty numeric, batchno character varying, expirydate date, price numeric, totalsales numeric, total numeric)
    LANGUAGE plpgsql
    AS $$
	BEGIN
		return query 

	              SELECT    
				  OH.ID OHID
				, H.TransDate AS VchDate
				, L.Code AS StrCode
				, C.Code AS CustomerCode
				, Case When pLang=0 then C.EngName else  C.ArbName end CustomerName
				, V.Code AS VendorCode
				, Case When pLang=0 then V.EngName else  V.ArbName end vendorName 
				, Case When pLang=0 then COALESCE(OT.EngName,'') else  COALESCE(OT.ArbName,'')  end transname
				, OH.Number  VchNo
				, DL.Code  DsStrCode
				, Case When pLang=0 then DL.EngName else  DL.ArbName end DsStrName
 				, CC.Code  DsDeptCode
				, Case When pLang=0 then CC.EngName else  CC.ArbName end  DsDeptName
				, OH.reference1 AS ReferanceNumber
				, OH.subject AS ShortDescription
				, cast('' as varchar(100)) AS RequiredFor
				, cast('' as varchar(100)) AS SlsCode

				, Case When pLang=0 then S.Name else  S.Name end SlsName
				, U.name AS UsrCode
				, Case When pLang=0 then U.Name else  U.Name end UserName
				, I.Code AS ItmCode 
				, Case When pLang=0 then I.EngName else  I.ArbName end ItmName 
				, D.Quantity  AS Qty
				, d.batchnumber AS BatchNo
				, d.expiredate AS ExpiryDate
			   , d.Price  AS Price
				,d.Price * D.Quantity TotalSales
				, (ABS(D.Quantity) * COALESCE(D.CostPrice,0) * 1) AS Total

		FROM inv_itemstrans  H 	
				INNER  JOIN inv_itemstransline   D                   ON H.ID                        = D.ItemTrans_ID  
				INNER  JOIN inv_ItemsIdentifiers    II 	                ON D.ItemIdentifier_ID	       = II.ID
				INNER  JOIN inv_Items 	            I 	                ON II.Item_ID 	               = I.ID
				INNER  JOIN inv_OperationsTypes     OT                  On H.operationtype_ID           = OT.ID 
				INNER  JOIN sy_lookup     lu                  On  OT.Operationkind_id = lu.ID
				INNER  JOIN inv_InventoriesLocations		    L					ON  H.invLocation_ID 	           = L.ID
				LEFT   JOIN inv_Operations      OH                  ON H.Operation_ID           = OH.ID  
				LEFT   JOIN users_user 		        U 	                ON OH.statuschangedby_id	               = U.ID
				LEFT   JOIN crm_Salesman 	    S	                ON OH.Salesperson_ID            = S.ID
				LEFT   JOIN ar_Customers  	        C  	                ON OH.Customer_ID               = C.ID 
				LEFT   JOIN ap_Vendors 	        V  	                ON  OH.Vendor_ID	               = V.ID 
				LEFT  JOIN inv_InventoriesLocations		    DL					ON OH.destinationinvlocation_ID            = DL.ID
				LEFT   JOIN gl_CostCenters 	    CC  	            ON  OH.costcenter1_ID	       = CC.ID 

		WHERE        I.Code Like pLikeItmCode || '%'
				And H.TransDate  >= pFromDate  And  H.TransDate <   cast(pUptoDate + INTERVAL '1 day' as date) 
				AND COALESCE(C.Code,'') Like  pLikeCustCode || '%'
				AND COALESCE(V.Code,'') Like  pLikeVendCode ||'%'
				And COALESCE(S.name,'') Like  pLikeSlsCode || '%'
				And COALESCE(U.name,'') Like  pLikeUserCode ||'%'
				And COALESCE(L.code,'') Like  pLikeLocCode || '%'
				And COALESCE(OH.reference1,'')   Like pReferanceNumber  || '%'
				And COALESCE(OH.subject,'')  Like pShortDescription || '%'
				AND pVchNo =case When pVchNo ='' then pVchNo Else COALESCE(OH.Number,H.Number) End

			Order By OH.ID,COALESCE(OH.OperationDate,H.TransDate), COALESCE(OH.Number,H.Number) ASC;

end;

$$;


ALTER FUNCTION public.in_rpinventitemsjournal(plikecustcode character varying, plikevendcode character varying, plikeslscode character varying, plikeusercode character varying, plikeitmcode character varying, pintrncode character varying, plikeloccode character varying, pvchno character varying, preferancenumber character varying, pshortdescription character varying, prequiredfor character varying, pfromdate date, puptodate date, poperationcat character varying, plang integer) OWNER TO postgres;

--
-- Name: in_rpitemsjournal(character varying, character varying, character varying, character varying, character varying, character varying, character varying, character varying, character varying, character varying, character varying, date, date, character varying, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.in_rpitemsjournal(plikecustcode character varying, plikevendcode character varying, plikeslscode character varying, plikeusercode character varying, plikeitmcode character varying, pintrncode character varying, plikeloccode character varying, pvchno character varying, preferancenumber character varying, pshortdescription character varying, prequiredfor character varying, pfromdate date, puptodate date, poperationcat character varying, plang integer) RETURNS TABLE(vchdate date, strcode character varying, customercode character varying, customername character varying, vendorcode character varying, vendorname character varying, transname character varying, vchno character varying, dsstrcode character varying, dsstrname character varying, dsdeptcode character varying, dsdeptname character varying, referancenumber character varying, shortdescription character varying, requiredfor character varying, slscode character varying)
    LANGUAGE plpgsql
    AS $$

BEGIN
	return query 

	              SELECT    
				  H.TransDate AS VchDate
				, L.Code AS StrCode
				, C.Code AS CustomerCode
				, Case When pLang=0 then C.EngName else  C.ArbName end CustomerName
				, V.Code AS VendorCode
				, Case When pLang=0 then V.EngName else  V.ArbName end vendorName 
				, Case When pLang=0 then COALESCE(OT.EngName,'') else  COALESCE(OT.ArbName,'')  end transname
				, OH.Number  VchNo
				, DL.Code  DsStrCode
				, Case When pLang=0 then DL.EngName else  DL.ArbName end DsStrName
 				, CC.Code  DsDeptCode
				, Case When pLang=0 then CC.EngName else  CC.ArbName end  DsDeptName
				, OH.reference1 AS ReferanceNumber
				, OH.subject AS ShortDescription
				, cast('' as varchar(100)) AS RequiredFor
				, cast('' as varchar(100)) AS SlsCode

		FROM inv_itemstrans  H 	
				INNER  JOIN inv_itemstransline   D                   ON H.ID                        = D.ItemTrans_ID  
				INNER  JOIN inv_ItemsIdentifiers    II 	                ON D.ItemIdentifier_ID	       = II.ID
				INNER  JOIN inv_Items 	            I 	                ON II.Item_ID 	               = I.ID
				INNER  JOIN inv_OperationsTypes     OT                  On H.operationtype_ID           = OT.ID 
				INNER  JOIN sy_lookup     lu                  On  OT.Operationkind_id = lu.ID
				INNER  JOIN inv_InventoriesLocations		    L					ON  H.invLocation_ID 	           = L.ID
				LEFT   JOIN inv_Operations      OH                  ON H.Operation_ID           = OH.ID  
				LEFT   JOIN users_user 		        U 	                ON OH.statuschangedby_id	               = U.ID
				LEFT   JOIN crm_Salesman 	    S	                ON OH.Salesperson_ID            = S.ID
				LEFT   JOIN ar_Customers  	        C  	                ON OH.Customer_ID               = C.ID 
				LEFT   JOIN ap_Vendors 	        V  	                ON  OH.Vendor_ID	               = V.ID 
				LEFT  JOIN inv_InventoriesLocations		    DL					ON OH.destinationinvlocation_ID            = DL.ID
				LEFT   JOIN gl_CostCenters 	    CC  	            ON  OH.costcenter1_ID	       = CC.ID 
				
		WHERE        I.Code Like pLikeItmCode || '%'
				And H.TransDate  >= pFromDate  And  H.TransDate <   cast(pUptoDate - INTERVAL '1 day' as date) 
				AND COALESCE(C.Code,'') Like  pLikeCustCode || '%'
				AND COALESCE(V.Code,'') Like  pLikeVendCode ||'%'
				And COALESCE(S.name,'') Like  pLikeSlsCode || '%'
				And COALESCE(U.name,'') Like  pLikeUserCode ||'%'
				And COALESCE(L.code,'') Like  pLikeLocCode || '%'
				And COALESCE(OH.reference1,'')   Like pReferanceNumber  || '%'
				And COALESCE(OH.subject,'')  Like pShortDescription || '%'
				AND pVchNo =case When pVchNo ='' then pVchNo Else COALESCE(OH.Number,H.Number) End

			Order By COALESCE(OH.OperationDate,H.TransDate), COALESCE(OH.Number,H.Number) ASC;

    
end;

$$;


ALTER FUNCTION public.in_rpitemsjournal(plikecustcode character varying, plikevendcode character varying, plikeslscode character varying, plikeusercode character varying, plikeitmcode character varying, pintrncode character varying, plikeloccode character varying, pvchno character varying, preferancenumber character varying, pshortdescription character varying, prequiredfor character varying, pfromdate date, puptodate date, poperationcat character varying, plang integer) OWNER TO postgres;

--
-- Name: in_rptareasalesreport(character varying, character varying, character varying, character varying, character varying, character varying, boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.in_rptareasalesreport(pareacode character varying, pitemcode character varying, pchannelcode character varying, psizecode character varying, pcatcode character varying, pbrandcode character varying, allsum boolean) RETURNS TABLE(t_areaengname character varying, t_areaarbname character varying, t_tarmqty double precision, t_tarmamount double precision, t_actqty numeric, t_actamount numeric, t_achqtypercent double precision, t_achamountpercent double precision, t_mm integer)
    LANGUAGE plpgsql
    AS $$
declare myrec	record;

	BEGIN

CREATE TEMP TABLE temp_custsales AS

Select  
	Sum(linetotal) TotalActAmount
	,count(o.id) noofinvoice  
	,EXTRACT(month FROM operationdate) Mm 
	,cit.area_id areaid
	,lu.id sizeid
	,ccls.id classid
	,invloc.id invlocid
	,sum(baseequivalentquantity) ActQty
from inv_operations o 
inner join inv_operationsline ol On o.id = ol.operation_id
inner Join inv_operationsTypes ot on ot.id = o.operationtype_id
inner join ar_customers c on c.id = o.customer_id
Inner Join ar_customersaddresses cad ON cad.customer_id = c.id 
Inner Join ar_customersclasses ccls ON ccls.id =  c.customerclass_id 
inner join sy_cities cit on cit.id = cad.city_id	
inner join sy_lookup lu on lu.id = c.accountsize_id
inner join sy_lookup lukind on lu.id = ot.operationkind_id
inner join sy_lookup lustatus on lustatus.id = o.status_id
inner join inv_inventorieslocations invloc on invloc.id = o.invlocation_id
where lu.remarks = 'SALES'
and c.allowtarget = true
and lustatus.keyid = 10004
group by 
	EXTRACT(month FROM operationdate) 
	,cit.area_id 
	,lu.id 
	,ccls.id 
	,invloc.id 
	;

CREATE TEMP TABLE cust_result AS 

Select 

lu.id sizeid,lu.keyid sizekeyid ,lu.code sizecode,lu.engname  sizeengname,lu.arbname  sizearbname 
,area.id areaid ,area.code areacode,area.code areaengname ,area.code areaarbname

,ccls.id classid,ccls.code  cclscode,ccls.code cclsengname ,ccls.code cclsarbname
,ccls.pricelevel_id pricelevelid
,count(c.id)
,(Select Count(L.id) from inv_inventorieslocations l inner join sy_cities c on c.id = l.city_id Where c.area_id = area.id ) NoOfLocPerarea
, il.id invlocid  ,il.code invloccode ,il.engname invlocengname ,il.arbname invlocarbname
from ar_customers c 
Inner Join ar_customersaddresses cad ON cad.customer_id = c.id 
Inner Join ar_customersclasses ccls ON ccls.id =  c.customerclass_id 
inner join sy_cities cit on cit.id = cad.city_id	
left Join inv_inventorieslocations il on cit.id = il.city_id
inner join sy_lookup lu on lu.id = c.accountsize_id
inner join sy_areas area on area.id = cit.area_id

where c.allowtarget = true 
group by
lu.id ,lu.keyid  ,lu.code ,lu.engname ,lu.arbname  
,area.id  ,area.code ,area.code  ,area.code 
,ccls.id ,ccls.code  ,ccls.code  ,ccls.code 
,ccls.pricelevel_id
, il.id ,il.code ,il.engname  ,il.arbname 
;

---============================
CREATE TEMP TABLE item_result AS 
--drop table item_result
Select 
i.id itemid,tb.itemuom_id itemuomid,itmcat.Code itmcatcode, itmcat.engname itmcatengname , itmcat.arbname itmcatarbname
,iuom.baseunitfactor
,itmsea.mm
,itmsea.area_id areaid
,tbb.channel_id classid
,	tb.yearly_qty * (tbb.contribution /100 ::float) *  case when false = true then 1 else (itmsea.quotapercent/100::float) end  * (tbb.small/100::float)  * (itmsea.mpercent/100::float) SmlQty
,	tb.yearly_qty * (tbb.contribution /100 ::float) * case when false = true then 1 else (itmsea.quotapercent/100::float) end  * (tbb.medium/100::float)  * (itmsea.mpercent/100::float) medQty
,	tb.yearly_qty * (tbb.contribution /100 ::float) * case when false = true then 1 else (itmsea.quotapercent/100::float) end  * (tbb.large/100::float)  * (itmsea.mpercent/100::float)  lrgQty
,i.code itemcode
,itmcat.code itemcatcode
,itmBrand.code itembrandcode
from inv_targetbuildingblocksitems tbb 
inner join inv_targetbuildingblocks tb On  tb.id = tbb.targetbuildingblocks_id
inner join inv_items i on i.id = tb.item_id
inner join inv_itemsuom iuom on iuom.id = tb.itemuom_id
inner join inv_viewitemsseasonality itmsea ON itmsea.item_id = i.id  
left join inv_itemscategories itmcat ON itmcat.id = i.itemcategory_id  
left join inv_itemsbrands itmBrand ON itmBrand.id = i.itemBrand_id  

-- where c.allowtarget = true
-- and area.code  like areacode || '%'
-- and i.code Like itemcode || '%'
-- and ccls.code like channelcode || '%'
-- and lu.code like sizecode || '%'
-- and itmcat.code like catcode || '%'
-- and itmbrand.code like brandcode || '%'

;

CREATE TEMP TABLE temp_result  AS 
Select 	
	i.mm 
	,case when sizekeyid = 2102 then
-- 		Sum(smlqty)
		smlqty
	else case when sizekeyid = 2103 then
-- 		sum(medqty)
		medqty		
	else case when sizekeyid = 2104 then	
-- 		sum(lrgqty)
		lrgqty
	end
	end
	end   tarmqty
	,price
	,actqty / baseunitfactor actqty
	,totalactamount
	,areaengname ,areaarbname
From cust_result c
Inner Join item_result i On c.areaid = i.areaid and c.classid= i.classid 
left join temp_custsales cs On cs.classid = c.classid and cs.sizeid = c.sizeid  and cs.Mm = i.mm and cs.areaid = c.areaid and cs.invlocid = c.invlocid
LEFT JOIN LATERAL 
(Select price from  inv_itemspriceslists ipl where  ipl.item_id= i.itemid and ipl.pricelevel_id = c.pricelevelid and ipl.itemuom_id =i.itemuomid limit 1) AS firstprc ON true
where c.areacode  like pareacode || '%'
and itemcode Like pitemcode || '%'
and c.cclscode like pchannelcode || '%'
and c.sizecode like psizecode || '%'
and itemcatcode like pcatcode || '%'
and itembrandcode like pbrandcode || '%'

--group by I.mm ,sizekeyid ,price ,baseunitfactor , actqty ,totalactamount
;

return query 

Select 	
	areaengname ,areaarbname
	, sum(tarmqty)   ,sum( tarmqty * price) tarmamount	,  sum(actqty) , sum(TotalActAmount) TotalActAmount
	, sum(  actqty / tarmqty ) * 100    achqtypercent 

	,sum( TotalActAmount )/ sum( price * tarmqty )* 100 achamountpercent 
	,case When allsum = true then 1 else   mm end
	--,((Select sum( actqty ) from temp_custsales tr Where tr.mm <= temp_result.mm )/(Select sum( tarmqty ) from temp_result tr Where tr.mm <= temp_result.mm )) * 100 accumqtypercent

	--,((Select sum( TotalActAmount ) from temp_custsales tr Where tr.mm <= temp_result.mm )/(Select sum( tarmqty ) from temp_result tr Where tr.mm <= temp_result.mm )) * 100 accumqtypercent

from  temp_result 
	group by case When allsum = true then 1 else   mm end,	areaengname ,areaarbname

 ;

DROP TABLE IF EXISTS cust_result;
DROP TABLE IF EXISTS temp_custcount;
DROP TABLE IF EXISTS item_result;
DROP TABLE IF EXISTS temp_custsales;
drop table if exists temp_result ;
end;
$$;


ALTER FUNCTION public.in_rptareasalesreport(pareacode character varying, pitemcode character varying, pchannelcode character varying, psizecode character varying, pcatcode character varying, pbrandcode character varying, allsum boolean) OWNER TO postgres;

--
-- Name: in_rptargettopdown(character varying, character varying, character varying, character varying, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.in_rptargettopdown(plikecustcode character varying, plikeslscode character varying, plikecitycode character varying, plikeitmcode character varying, plang integer) RETURNS TABLE(t_custid integer, t_itemcode character varying, t_itemengname character varying, t_itemarbname character varying, t_custcode character varying, t_custengname character varying, t_custarbname character varying, t_salesmanname character varying, t_areaid integer, t_cityid integer, t_price numeric, t_tarqty double precision, t_custcount bigint, t_sizekeyid integer, t_sizecode character varying, t_sizeengname character varying, t_sizearbname character varying, t_baseunitfactor numeric, t_tarmqty double precision, t_salespersonid integer, t_yearlyqty integer, t_contribution integer, t_large integer, t_medium integer, t_small integer, t_quotapercent integer, t_mpercent numeric, t_mm integer, t_areacode character varying, t_areaengname character varying, t_areaarbname character varying, t_citcode character varying, t_citengname character varying, t_citarbname character varying, t_cclscode character varying, t_cclsengname character varying, t_cclsarbname character varying, actamount numeric, actqty numeric, t_invlocation integer)
    LANGUAGE plpgsql
    AS $$
declare myrec	record;

	BEGIN

--DROP TABLE IF EXISTS temp_custcount;
CREATE TEMP TABLE temp_custcount AS
	Select Count(*) custcount,accountsize_id , customerclass_id , area_id from ar_customers cc
	Inner Join ar_customersaddresses cad1 ON cad1.customer_id = cc.id
	inner join sy_cities cit1 on cit1.id = cad1.city_id
	inner join sy_lookup lu on lu.id = cc.accountsize_id
	Where cc.allowtarget = true
	group by accountsize_id , customerclass_id , area_id;

--DROP TABLE IF EXISTS temp_custsales;
CREATE TEMP TABLE temp_custsales AS

Select  

sum(linetotal) amount,sum(baseequivalentquantity) qty,invlocation_id, item_id
	,EXTRACT(month FROM operationdate) Mm ,customer_id
	from in_operations o 
inner join in_operationsline ol On o.id = ol.operation_id
inner Join in_operationsTypes ot on ot.id = o.operationtype_id
inner join sy_lookup lu on lu.id = ot.operationkind_id
inner join sy_lookup lustatus on lustatus.id = o.status_id
where lu.remarks = 'SALES'
and lustatus.keyid = 10004
group by invlocation_id, item_id
	,EXTRACT(month FROM operationdate) ,customer_id;
	

return query 
Select  
c.id customer_id,
i.code,i.engname,i.arbname,
c.code,c.engname,c.arbname,
sm.name,cit.area_id,cit.id city_id,

(Select price from  in_itemspriceslists ipl where  ipl.item_id= i.id and ipl.pricelevel_id = cc.pricelevel_id and ipl.itemuom_id =tb.itemuom_id limit 1) Price ,
case when lu.keyid = 2102 then
	tb.yearly_qty * (tbb.contribution /100 ::float) *  case when false = true then 1 else (itmsea.quotapercent/100::float) end  * (tbb.small/100::float)  
else case when lu.keyid = 2103 then
	tb.yearly_qty * (tbb.contribution /100 ::float) * case when false = true then 1 else (itmsea.quotapercent/100::float) end  * (tbb.medium/100::float)  
else case when lu.keyid = 2104 then	
	tb.yearly_qty * (tbb.contribution /100 ::float) * case when false = true then 1 else (itmsea.quotapercent/100::float) end  * (tbb.large/100::float)  
end
end
end taqty
,tcc.custcount

,lu.keyid ,lu.code,lu.engname  ,lu.arbname ,iuom.baseunitfactor

,case when lu.keyid = 2102 then
	tb.yearly_qty * (tbb.contribution /100 ::float) *  case when false = true then 1 else (itmsea.quotapercent/100::float) end  * (tbb.small/100::float)  * (itmsea.mpercent/100::float)
else case when lu.keyid = 2103 then
	tb.yearly_qty * (tbb.contribution /100 ::float) * case when false = true then 1 else (itmsea.quotapercent/100::float) end  * (tbb.medium/100::float)  * (itmsea.mpercent/100::float)
else case when lu.keyid = 2104 then	
	tb.yearly_qty * (tbb.contribution /100 ::float) * case when false = true then 1 else (itmsea.quotapercent/100::float) end  * (tbb.large/100::float)  * (itmsea.mpercent/100::float)
end
end
end  /tcc.custcount taqty

,c.salesperson_id ,tb.yearly_qty , tbb.contribution ,tbb.large ,tbb.medium ,tbb.small ,itmsea.quotapercent 
,itmsea.mpercent ,itmsea.mm

,area.code areacode,area.code areaengname ,area.code areaarbname
,cit.code citcode,cit.code citengname ,cit.code citarbname
,ccls.code cclscode,ccls.code cclsengname ,ccls.code cclsarbname

,cs.amount actamount,cs.qty/iuom.baseunitfactor  actqty,invlocation_id 

--into 		myrec 

from ar_customers c 
Inner Join ar_customersaddresses cad ON cad.customer_id = c.id 
Inner Join ar_customersclasses ccls ON ccls.id =  c.customerclass_id 

inner join sy_cities cit on cit.id = cad.city_id	
inner join sy_lookup lu on lu.id = c.accountsize_id
inner join in_targetbuildingblocksitems tbb on tbb.channel_id = c.customerclass_id
inner join in_targetbuildingblocks tb On  tb.id = tbb.targetbuildingblocks_id
inner join in_items i on i.id = tb.item_id
inner join in_itemsuom iuom on iuom.id = tb.itemuom_id

inner join in_viewitemsseasonality itmsea ON itmsea.item_id = i.id  and cit.area_id = itmsea.area_id 
inner join sy_areas area on area.id = itmsea.area_id
inner join crm_salesman sm on sm.id = c.salesperson_id
inner join ar_customersclasses cc on cc.id = c.customerclass_id
inner join temp_custcount tcc on tcc.accountsize_id = c.accountsize_id and tcc.customerclass_id = c.customerclass_id and tcc.area_id = itmsea.area_id
left join temp_custsales cs On cs.customer_id = c.id and cs.item_id = i.id  and cs.Mm = itmsea.mm

where c.allowtarget = true
and c.code like plikecustcode || '%'
and sm.name like plikeslscode || '%'
and cit.code like plikeitmcode || '%'

order by i.id;

--Select * from myrec ;

end;

$$;


ALTER FUNCTION public.in_rptargettopdown(plikecustcode character varying, plikeslscode character varying, plikecitycode character varying, plikeitmcode character varying, plang integer) OWNER TO postgres;

--
-- Name: in_rptcatsalesreport(character varying, character varying, character varying, character varying, character varying, character varying, boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.in_rptcatsalesreport(pareacode character varying, pitemcode character varying, pchannelcode character varying, psizecode character varying, pcatcode character varying, pbrandcode character varying, allsum boolean) RETURNS TABLE(t_itemcatengname character varying, t_itemcatarbname character varying, t_tarmqty double precision, t_tarmamount double precision, t_actqty numeric, t_actamount numeric, t_achqtypercent double precision, t_achamountpercent double precision, t_mm integer)
    LANGUAGE plpgsql
    AS $$
declare myrec	record;

	BEGIN

CREATE TEMP TABLE temp_custsales AS

Select  
	Sum(linetotal) TotalActAmount
	,count(o.id) noofinvoice  
	,EXTRACT(month FROM operationdate) Mm 
	,cit.area_id areaid
	,lu.id sizeid
	,ccls.id classid
	,invloc.id invlocid
	,sum(baseequivalentquantity) ActQty
from inv_operations o 
inner join inv_operationsline ol On o.id = ol.operation_id
inner Join inv_operationsTypes ot on ot.id = o.operationtype_id
inner join ar_customers c on c.id = o.customer_id
Inner Join ar_customersaddresses cad ON cad.customer_id = c.id 
Inner Join ar_customersclasses ccls ON ccls.id =  c.customerclass_id 
inner join sy_cities cit on cit.id = cad.city_id	
inner join sy_lookup lu on lu.id = c.accountsize_id
inner join sy_lookup lukind on lu.id = ot.operationkind_id
inner join sy_lookup lustatus on lustatus.id = o.status_id
inner join inv_inventorieslocations invloc on invloc.id = o.invlocation_id
where lu.remarks = 'SALES'
and c.allowtarget = true
and lustatus.keyid = 10004
group by 
	EXTRACT(month FROM operationdate) 
	,cit.area_id 
	,lu.id 
	,ccls.id 
	,invloc.id 
	;

CREATE TEMP TABLE cust_result AS 

Select 

lu.id sizeid,lu.keyid sizekeyid ,lu.code sizecode,lu.engname  sizeengname,lu.arbname  sizearbname 
,area.id areaid ,area.code areacode,area.code areaengname ,area.code areaarbname

,ccls.id classid,ccls.code  cclscode,ccls.code cclsengname ,ccls.code cclsarbname
,ccls.pricelevel_id pricelevelid
,count(c.id)
,(Select Count(L.id) from inv_inventorieslocations l inner join sy_cities c on c.id = l.city_id Where c.area_id = area.id ) NoOfLocPerarea
, il.id invlocid  ,il.code invloccode ,il.engname invlocengname ,il.arbname invlocarbname
from ar_customers c 
Inner Join ar_customersaddresses cad ON cad.customer_id = c.id 
Inner Join ar_customersclasses ccls ON ccls.id =  c.customerclass_id 
inner join sy_cities cit on cit.id = cad.city_id	
left Join inv_inventorieslocations il on cit.id = il.city_id
inner join sy_lookup lu on lu.id = c.accountsize_id
inner join sy_areas area on area.id = cit.area_id

where c.allowtarget = true 
group by
lu.id ,lu.keyid  ,lu.code ,lu.engname ,lu.arbname  
,area.id  ,area.code ,area.code  ,area.code 
,ccls.id ,ccls.code  ,ccls.code  ,ccls.code 
,ccls.pricelevel_id
, il.id ,il.code ,il.engname  ,il.arbname 
;

---============================
CREATE TEMP TABLE item_result AS 
--drop table item_result
Select 
i.id itemid,tb.itemuom_id itemuomid,itmcat.Code itmcatcode, itmcat.engname itmcatengname , itmcat.arbname itmcatarbname
,iuom.baseunitfactor
,itmsea.mm
,itmsea.area_id areaid
,tbb.channel_id classid
,	tb.yearly_qty * (tbb.contribution /100 ::float) *  case when false = true then 1 else (itmsea.quotapercent/100::float) end  * (tbb.small/100::float)  * (itmsea.mpercent/100::float) SmlQty
,	tb.yearly_qty * (tbb.contribution /100 ::float) * case when false = true then 1 else (itmsea.quotapercent/100::float) end  * (tbb.medium/100::float)  * (itmsea.mpercent/100::float) medQty
,	tb.yearly_qty * (tbb.contribution /100 ::float) * case when false = true then 1 else (itmsea.quotapercent/100::float) end  * (tbb.large/100::float)  * (itmsea.mpercent/100::float)  lrgQty
,i.code itemcode
,itmcat.code itemcatcode
,itmBrand.code itembrandcode
from inv_targetbuildingblocksitems tbb 
inner join inv_targetbuildingblocks tb On  tb.id = tbb.targetbuildingblocks_id
inner join inv_items i on i.id = tb.item_id
inner join inv_itemsuom iuom on iuom.id = tb.itemuom_id
inner join inv_viewitemsseasonality itmsea ON itmsea.item_id = i.id  
left join inv_itemscategories itmcat ON itmcat.id = i.itemcategory_id  
left join inv_itemsbrands itmBrand ON itmBrand.id = i.itemBrand_id  

-- where c.allowtarget = true
-- and area.code  like areacode || '%'
-- and i.code Like itemcode || '%'
-- and ccls.code like channelcode || '%'
-- and lu.code like sizecode || '%'
-- and itmcat.code like catcode || '%'
-- and itmbrand.code like brandcode || '%'

;

CREATE TEMP TABLE temp_result  AS 
Select 	
	i.mm 
	,case when sizekeyid = 2102 then
-- 		Sum(smlqty)
		smlqty
	else case when sizekeyid = 2103 then
-- 		sum(medqty)
		medqty		
	else case when sizekeyid = 2104 then	
-- 		sum(lrgqty)
		lrgqty
	end
	end
	end   tarmqty
	,price
	,actqty / baseunitfactor actqty
	,totalactamount
	,itmcatengname ,itmcatarbname
From cust_result c
Inner Join item_result i On c.areaid = i.areaid and c.classid= i.classid 
left join temp_custsales cs On cs.classid = c.classid and cs.sizeid = c.sizeid  and cs.Mm = i.mm and cs.areaid = c.areaid and cs.invlocid = c.invlocid
LEFT JOIN LATERAL 
(Select price from  inv_itemspriceslists ipl where  ipl.item_id= i.itemid and ipl.pricelevel_id = c.pricelevelid and ipl.itemuom_id =i.itemuomid limit 1) AS firstprc ON true
where c.areacode  like pareacode || '%'
and itemcode Like pitemcode || '%'
and c.cclscode like pchannelcode || '%'
and c.sizecode like psizecode || '%'
and itemcatcode like pcatcode || '%'
and itembrandcode like pbrandcode || '%'

--group by I.mm ,sizekeyid ,price ,baseunitfactor , actqty ,totalactamount
;

return query 

Select 	
	itmcatengname ,  itmcatarbname
	, sum(tarmqty)   ,sum( tarmqty * price) tarmamount	,  sum(actqty) , sum(TotalActAmount) TotalActAmount
	, sum(  actqty / tarmqty ) * 100    achqtypercent 

	,sum( TotalActAmount )/ sum( price * tarmqty )* 100 achamountpercent 
	,case When allsum = true then 1 else   mm end
	--,((Select sum( actqty ) from temp_custsales tr Where tr.mm <= temp_result.mm )/(Select sum( tarmqty ) from temp_result tr Where tr.mm <= temp_result.mm )) * 100 accumqtypercent

	--,((Select sum( TotalActAmount ) from temp_custsales tr Where tr.mm <= temp_result.mm )/(Select sum( tarmqty ) from temp_result tr Where tr.mm <= temp_result.mm )) * 100 accumqtypercent

from  temp_result 
	group by 	case When allsum = true then 1 else   mm end,	itmcatengname ,  itmcatarbname

 ;

DROP TABLE IF EXISTS cust_result;
DROP TABLE IF EXISTS temp_custcount;
DROP TABLE IF EXISTS item_result;
DROP TABLE IF EXISTS temp_custsales;
drop table if exists temp_result ;
end;
$$;


ALTER FUNCTION public.in_rptcatsalesreport(pareacode character varying, pitemcode character varying, pchannelcode character varying, psizecode character varying, pcatcode character varying, pbrandcode character varying, allsum boolean) OWNER TO postgres;

