and c.sizecode like psizecode || '%'
and itemcatcode like pcatcode || '%'
and itembrandcode like pbrandcode || '%'

--group by I.mm ,sizekeyid ,price ,baseunitfactor , actqty ,totalactamount
;

return query 

Select 	
	cclsengname ,cclsarbname
	, sum(tarmqty)   ,sum( tarmqty * price) tarmamount	,  sum(actqty) , sum(TotalActAmount) TotalActAmount
	, sum(  actqty / tarmqty ) * 100    achqtypercent 

	,sum( TotalActAmount )/ sum( price * tarmqty )* 100 achamountpercent 
