,(Select Count(L.id) from inv_inventorieslocations l inner join sy_cities c on c.id = l.city_id Where c.area_id = area.id ) NoOfLocPerarea
, il.id invlocid  ,il.code invloccode ,il.engname invlocengname ,il.arbname invlocarbname
from ar_customers c 
