LEFT JOIN LATERAL 
(Select price from  inv_itemspriceslists ipl where  ipl.item_id= i.itemid and ipl.pricelevel_id = c.pricelevelid and ipl.itemuom_id =i.itemuomid limit 1) AS firstprc ON true
