ALTER FUNCTION public.in_rptmonthlysalesreport(pareacode character varying, pitemcode character varying, pchannelcode character varying, psizecode character varying, pcatcode character varying, pbrandcode character varying) OWNER TO postgres;

--
-- Name: in_rpttargetitemsinfo(character varying, character varying, character varying, character varying, character varying, character varying, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.in_rpttargetitemsinfo(pitemcode character varying, pareacode character varying, pchannelcode character varying, psizecode character varying, pcatcode character varying, pbrandcode character varying, pmonth integer) RETURNS TABLE(t_itemcode character varying, t_itemengname character varying, t_itemarbname character varying, t_classengname character varying, t_classarbname character varying, t_sizeengname character varying, t_sizearbname character varying, t_areaengname character varying, t_areaarbname character varying, t_catengname character varying, t_catarbname character varying, t_brandengname character varying, t_brandarbname character varying, t_price numeric, t_qty double precision, t_amount double precision, t_mm integer)
    LANGUAGE plpgsql
    AS $$
declare myrec	record;

	BEGIN

return query 

	Select 
		v.itemcode , v.itemengname, v.itemarbname
		,cc.engname classengname ,cc.arbname classarbname 
		,lu.engname sizeengname ,lu.arbname sizearbname 
		,area.engname areaengname ,area.arbname areaarbname 
		,cat.engname catengname ,cat.arbname catarbname 
		,brand.engname brandengname ,brand.arbname brandarbname 
		, price 
		,qty
		,price * qty Amount
		,mm
			
	from vw_TargetItemsQtyView v
	inner join ar_customersclasses cc on cc.id = v.classid
	inner join sy_lookup lu on lu.id = v.sizeid
	inner join sy_areas area on area.id = v.areaid
	inner join inv_itemscategories cat on cat.id = v.itemcategory_id
	inner join inv_itemsbrands brand on brand.id = v.itembrand_id

	LEFT JOIN LATERAL 
	(Select price from  inv_itemspriceslists ipl where  ipl.item_id= v.itemid and ipl.pricelevel_id = cc.pricelevel_id and ipl.itemuom_id =v.itemuomid limit 1) AS firstprc ON true

	where itemcode Like pitemcode || '%'
	and area.code  like pareacode || '%'
	and cc.code like pchannelcode || '%'
	and lu.code like psizecode || '%'
	and cat.code like pcatcode || '%'
	and brand.code like pbrandcode || '%'
	and ((mm = pmonth and pmonth != 0 )	or 	pmonth = 0)

 ;

end;
$$;


ALTER FUNCTION public.in_rpttargetitemsinfo(pitemcode character varying, pareacode character varying, pchannelcode character varying, psizecode character varying, pcatcode character varying, pbrandcode character varying, pmonth integer) OWNER TO postgres;

--
-- Name: in_rpttargetitemsinfosumm(character varying, character varying, character varying, character varying, character varying, character varying, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.in_rpttargetitemsinfosumm(pitemcode character varying, pareacode character varying, pchannelcode character varying, psizecode character varying, pcatcode character varying, pbrandcode character varying, pmonth integer) RETURNS TABLE(t_classengname character varying, t_classarbname character varying, t_sizeengname character varying, t_sizearbname character varying, t_areaengname character varying, t_areaarbname character varying, t_catengname character varying, t_catarbname character varying, t_brandengname character varying, t_brandarbname character varying, t_price numeric, t_qty double precision, t_amount double precision, t_mm integer)
    LANGUAGE plpgsql
    AS $$
declare myrec	record;

	BEGIN

return query 

	Select 
		cc.engname classengname ,cc.arbname classarbname 
		,lu.engname sizeengname ,lu.arbname sizearbname 
		,area.engname areaengname ,area.arbname areaarbname 
		,cat.engname catengname ,cat.arbname catarbname 
		,brand.engname brandengname ,brand.arbname brandarbname 
		, price 
		,sum(qty) qty
		,Sum(price * qty )Amount
		,mm
			
	from vw_TargetItemsQtyView v
	inner join ar_customersclasses cc on cc.id = v.classid
	inner join sy_lookup lu on lu.id = v.sizeid
	inner join sy_areas area on area.id = v.areaid
	inner join inv_itemscategories cat on cat.id = v.itemcategory_id
	inner join inv_itemsbrands brand on brand.id = v.itembrand_id

	LEFT JOIN LATERAL 
	(Select price from  inv_itemspriceslists ipl where  ipl.item_id= v.itemid and ipl.pricelevel_id = cc.pricelevel_id and ipl.itemuom_id =v.itemuomid limit 1) AS firstprc ON true

	where itemcode Like pitemcode || '%'
	and area.code  like pareacode || '%'
	and cc.code like pchannelcode || '%'
	and lu.code like psizecode || '%'
	and cat.code like pcatcode || '%'
	and brand.code like pbrandcode || '%'
	and ((mm = pmonth and pmonth != 0 )	or 	pmonth = 0)

	group by 
		cc.engname  ,cc.arbname  
		,lu.engname ,lu.arbname 
		,area.engname  ,area.arbname 
		,cat.engname  ,cat.arbname  
		,brand.engname  ,brand.arbname 
		, price 
		,mm

 ;

end;
$$;


ALTER FUNCTION public.in_rpttargetitemsinfosumm(pitemcode character varying, pareacode character varying, pchannelcode character varying, psizecode character varying, pcatcode character varying, pbrandcode character varying, pmonth integer) OWNER TO postgres;

--
-- Name: in_saveinventoryitemtrans(integer); Type: PROCEDURE; Schema: public; Owner: postgres
--

CREATE PROCEDURE public.in_saveinventoryitemtrans(paramtransid integer)
    LANGUAGE plpgsql
    AS $_$
Declare  varChangeQty float;
Declare varIncreaseQty float;
DECLARE varOperationID int;
DECLARE test_cur RECORD;

--RETURNS SETOF varchar AS
--$cursor_test$
	--SELECT COALESCE(Operation_ID,0) Operation_ID FROM in_ItemsTrans WHERE ID = paramTransID into varOperationID ;
BEGIN

FOR test_cur in
	Select 	 II.Item_ID 
		---- I make comment next line because there is more than one record  returned (the resoan from import item uom not put correct baseitemuon_id )

		,ItemIdentifier_ID
		--,(Select id from inv_ItemsIdentifiers baseII	 where baseII.item_id = II.Item_ID and baseII.Itemuom_ID = baseII.baseitemuom_id ) ItemIdentifier_ID

		,H.invLocation_ID,COALESCE( invbinlocation_id,0) BinLocation ,d.baseuom_id  itemUOM_ID --itemUOM_ID 
		, TransDate ChangeDate,Round( D.baseequivalentquantity ,3) Qty
		, H.ID lastitemtrans_ID , D.ID lastitemtransline_id ,False IsOpenBal ,H.fiscalyearperiod_id
	from inv_ItemsTrans H
	Inner join inv_ItemsTransline D On H.ID =  D.ItemTrans_ID
	Inner join inv_ItemsIdentifiers II On II.ID =D.ItemIdentifier_ID
	Where H.ID = paramTransID
	Order By ItemIdentifier_ID,H.invLocation_ID,TransDate

LOOP
	
	varChangeQty = test_cur.Qty;
	varIncreaseQty = test_cur.Qty;

	If not Exists(Select * From inv_Inventory 
				Where
				Item_ID = test_cur.Item_ID 
				And ItemIdentifier_ID = test_cur.ItemIdentifier_ID
				And invLocation_ID = test_cur.invLocation_ID
				And invbinlocation_id = test_cur.BinLocation
				And itemuom_ID = test_cur.itemUOM_ID 
				And ChangeDate=test_cur.ChangeDate
				) then

		If not Exists(Select * From inv_Inventory 
					Where
					Item_ID = test_cur.Item_ID 
					And ItemIdentifier_ID = test_cur.ItemIdentifier_ID
					And invLocation_ID = test_cur.invLocation_ID
					And invbinlocation_id = test_cur.BinLocation
					And itemuom_ID = test_cur.itemUOM_ID )
					Then

					--SELECT RaiseError(cast(test_cur.invLocation_ID as varchar(100)) );

					INSERT INTO inv_Inventory(Item_ID,ItemIdentifier_ID ,invlocation_ID ,invBinLocation_id ,itemuom_ID ,ChangeDate,
							  ChangeQty,qtybalance,perviouschangedate,previousqtybalance,lastitemtrans_ID,lastitemtransline_ID,IsOpenBal,fiscalyearperiod_ID)
					values( test_cur.Item_ID,test_cur.ItemIdentifier_ID,test_cur.invLocation_ID,test_cur.BinLocation,test_cur.itemUOM_ID ,test_cur.ChangeDate
						   ,test_cur.Qty ,test_cur.Qty , NULL, NULL,test_cur.lastitemtrans_ID,test_cur.lastitemtransline_ID,test_cur.IsOpenBal,test_cur.fiscalyearperiod_id) ;
	

		else
					INSERT INTO inv_Inventory(Item_ID,ItemIdentifier_ID ,invlocation_ID ,invBinLocation_id ,itemuom_ID ,ChangeDate,
							  ChangeQty,qtybalance,perviouschangedate,previousqtybalance,lastitemtrans_ID,lastitemtransline_ID,IsOpenBal,fiscalyearperiod_ID)
					Select Item_ID,ItemIdentifier_ID,invLocation_ID,invBinLocation_id,itemUOM_ID ,test_cur.ChangeDate
						   ,varChangeQty ,qtybalance + varChangeQty ,ChangeDate, qtybalance ,test_cur.lastitemtrans_ID,test_cur.lastitemtransline_ID,test_cur.IsOpenBal,test_cur.fiscalyearperiod_id
					From inv_Inventory 
					Where 
						Item_ID = test_cur.Item_ID 
						And ItemIdentifier_ID = test_cur.ItemIdentifier_ID 
						And invLocation_ID = test_cur.invLocation_ID 
						And invBinLocation_id= test_cur.BinLocation 
						And itemUOM_ID  = test_cur.itemUOM_ID  
					Order by inv_Inventory.ChangeDate Desc limit 1;

		end if;
	else
------  Update Inventory
		UPDATE inv_Inventory 
		SET 
			 ChangeQty = ChangeQty 
		   + CASE 
				WHEN 
				Item_ID = test_cur.Item_ID 
				And ItemIdentifier_ID = test_cur.ItemIdentifier_ID
				And invLocation_ID = test_cur.invLocation_ID
				And invBinLocation_id = test_cur.BinLocation
				And itemUOM_ID = test_cur.itemUOM_ID
				And ChangeDate = test_cur.ChangeDate
				THEN varIncreaseQty
				ELSE 0 
			 END
		  ,qtybalance = qtybalance + varIncreaseQty
		  ,previousqtybalance = previousqtybalance 
			+ CASE 
				WHEN 
				Item_ID = test_cur.Item_ID 
				And ItemIdentifier_ID = test_cur.ItemIdentifier_ID
				And invLocation_ID = test_cur.invLocation_ID
				And invBinLocation_id = test_cur.BinLocation
				And itemUOM_ID = test_cur.itemUOM_ID
				And ChangeDate = test_cur.ChangeDate 

				THEN 0 
				ELSE varIncreaseQty 
			 END
			,lastitemtrans_ID = test_cur.lastitemtrans_ID
			,lastitemtransline_ID = test_cur.lastitemtransline_ID
			,IsOpenBal		= test_cur.IsOpenBal	
		WHERE 
		Item_ID = test_cur.Item_ID 
		And ItemIdentifier_ID = test_cur.ItemIdentifier_ID
		And invLocation_ID = test_cur.invLocation_ID
		And invBinLocation_id = test_cur.BinLocation
		And itemUOM_ID = test_cur.itemUOM_ID
		And ChangeDate >= test_cur.ChangeDate;	
	
	end if;

--return next test_cur.customer;

END LOOP;
IF varOperationID <> 0 then
	--EXEC mms_RecalcCost varOperationID
end if;

END;
---$cursor_test$
$_$;


ALTER PROCEDURE public.in_saveinventoryitemtrans(paramtransid integer) OWNER TO postgres;

--
-- Name: raiseerror(text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.raiseerror(text) RETURNS void
    LANGUAGE plpgsql
    AS $_$
 
BEGIN 
   RAISE EXCEPTION '%', $1; 
END; 
 
$_$;


