--
-- Name: rpttargetreportcustsalesmansource(character varying, character varying, character varying, character varying, character varying, character varying, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.rpttargetreportcustsalesmansource(pareacode character varying, pitemcode character varying, pchannelcode character varying, psizecode character varying, pcatcode character varying, pbrandcode character varying, pmonth integer) RETURNS TABLE(t_custengname character varying, t_custarbname character varying, t_tarqty double precision, t_taramount double precision, t_actqty numeric, t_actamount numeric, t_achqtypercent double precision, t_achamountpercent double precision)
    LANGUAGE plpgsql
    AS $$
declare myrec	record;

	BEGIN

CREATE TEMP TABLE temp_custcount AS
	Select Count(*) custcount,accountsize_id sizeid , customerclass_id classid, area_id areaid from ar_customers cc
	Inner Join ar_customersaddresses cad1 ON cad1.customer_id = cc.id
	inner join sy_cities cit1 on cit1.id = cad1.city_id
	inner join sy_lookup lu on lu.id = cc.accountsize_id
	Where cc.allowtarget = true
	group by accountsize_id , customerclass_id , area_id;

CREATE TEMP TABLE temp_actualsales AS

Select  
	Sum(linetotal) TotalActAmount
	,count(o.id) noofinvoice  
	,EXTRACT(month FROM operationdate) Mm 
	,cit.area_id areaid
	,lu.id sizeid
	,ccls.id classid
	,invloc.id invlocid
	,sum(baseequivalentquantity) ActQty
from inv_operations o 
inner join inv_operationsline ol On o.id = ol.operation_id
inner Join inv_operationsTypes ot on ot.id = o.operationtype_id
inner join ar_customers c on c.id = o.customer_id
Inner Join ar_customersaddresses cad ON cad.customer_id = c.id 
Inner Join ar_customersclasses ccls ON ccls.id =  c.customerclass_id 
inner join sy_cities cit on cit.id = cad.city_id	
inner join sy_lookup lu on lu.id = c.accountsize_id
inner join sy_lookup lukind on lu.id = ot.operationkind_id
inner join sy_lookup lustatus on lustatus.id = o.status_id
inner join inv_inventorieslocations invloc on invloc.id = o.invlocation_id
where lu.remarks = 'SALES'
and c.allowtarget = true
and lustatus.keyid = 10004
group by 
	EXTRACT(month FROM operationdate) 
	,cit.area_id 
	,lu.id 
	,ccls.id 
	,invloc.id 
	;

return query 

Select 

			c.custengname,c.custarbname --,sp.name

		,sum(qty/tcustcount.custcount) qty
		,Sum(price * qty /tcustcount.custcount )Amount
		,sum(acts.actqty ) actqty , sum(acts.TotalActAmount) TotalActAmount

 		, sum(  actqty / qty ) * 100    achqtypercent 

 		,sum( TotalActAmount )/ sum( price * qty )* 100 achamountpercent 

	From vw_customersinfo c
--	inner join crm_salesman sp on sp.id = c.salesperson_id
	inner join vw_TargetItemsQtyView v on v.sizeid= c.sizeid and v.classid = c.classid and 	v.areaid = c.areaid
	--from vw_TargetItemsQtyView v
	inner join ar_customersclasses cc on cc.id = v.classid
	inner join sy_lookup lu on lu.id = v.sizeid
	inner join sy_areas area on area.id = v.areaid
	inner join inv_itemscategories cat on cat.id = v.itemcategory_id
	inner join inv_itemsbrands brand on brand.id = v.itembrand_id
	inner Join temp_custcount tcustcount on tcustcount.classid = v.classid and tcustcount.sizeid = v.sizeid and tcustcount.areaid = v.areaid
	left join temp_actualsales acts On acts.classid = v.classid and acts.sizeid = v.sizeid  and acts.Mm = v.mm and acts.areaid = v.areaid 
	LEFT JOIN LATERAL 
	(Select price from  inv_itemspriceslists ipl where  ipl.item_id= v.itemid and ipl.pricelevel_id = cc.pricelevel_id and ipl.itemuom_id =v.itemuomid limit 1) AS firstprc ON true

	where area.code  like pareacode || '%'
	--and itemcode Like pitemcode || '%'
	and cc.code like pchannelcode || '%'
	and lu.code like psizecode || '%'
	and cat.code like pcatcode || '%'
	and brand.code like pbrandcode || '%'

	group by 
-- 		price		
-- 		,
		c.custengname,c.custarbname --,sp.name
;

DROP TABLE IF EXISTS temp_actualsales ;
DROP TABLE IF EXISTS temp_result ;
DROP TABLE IF EXISTS temp_result1 ;
DROP TABLE IF EXISTS temp_custcount ;

end;
$$;


ALTER FUNCTION public.rpttargetreportcustsalesmansource(pareacode character varying, pitemcode character varying, pchannelcode character varying, psizecode character varying, pcatcode character varying, pbrandcode character varying, pmonth integer) OWNER TO postgres;

