CREATE FUNCTION public.rpttargetreportsalesarea(pareacode character varying, pitemcode character varying, pchannelcode character varying, psizecode character varying, pcatcode character varying, pbrandcode character varying, pmonth integer) RETURNS TABLE(t_areaengname character varying, t_areaarbname character varying, t_tarqty double precision, t_taramount double precision, t_actqty numeric, t_actamount numeric, t_achqtypercent double precision, t_achamountpercent double precision)
    LANGUAGE plpgsql
    AS $$
declare myrec	record;

	BEGIN

CREATE TEMP TABLE temp_actualsales AS

Select  
	Sum(linetotal) TotalActAmount
	,count(o.id) noofinvoice  
	,EXTRACT(month FROM operationdate) Mm 
	,cit.area_id areaid
	,lu.id sizeid
	,ccls.id classid
	,invloc.id invlocid
	,sum(baseequivalentquantity) ActQty
	,i.id itemid
from inv_operations o 
inner join inv_operationsline ol On o.id = ol.operation_id
inner Join inv_operationsTypes ot on ot.id = o.operationtype_id
inner join ar_customers c on c.id = o.customer_id
Inner Join ar_customersaddresses cad ON cad.customer_id = c.id 
Inner Join ar_customersclasses ccls ON ccls.id =  c.customerclass_id 
inner join sy_cities cit on cit.id = cad.city_id	
inner join sy_lookup lu on lu.id = c.accountsize_id
inner join sy_lookup lukind on lukind.id = ot.operationkind_id
inner join sy_lookup lustatus on lustatus.id = o.status_id
inner join inv_inventorieslocations invloc on invloc.id = o.invlocation_id
inner join inv_items i on i.id = ol.item_id
where lukind.remarks = 'SALES'
and c.allowtarget = true
and lustatus.keyid = 10004
group by 
	EXTRACT(month FROM operationdate) 
	,cit.area_id 
	,lu.id 
	,ccls.id 
	,invloc.id 
	,i.id
	;

return query 

Select 
		area.engname areaengname ,area.arbname areaarbname 
-- 		,lu.engname sizeengname ,lu.arbname sizearbname 
-- 		,cat.engname catengname ,cat.arbname catarbname 
-- 		,cc.engname classengname ,cc.arbname classarbname 
-- 		,brand.engname brandengname ,brand.arbname brandarbname 

		,sum(qty) qty
		,Sum(price * qty )Amount
		,sum(acts.actqty /baseunitfactor) actqty , sum(acts.TotalActAmount) TotalActAmount

-- 		,v.mm
		, sum( actqty/baseunitfactor) / sum(qty ) * 100    achqtypercent 

		,sum( TotalActAmount )/ sum( price * qty )* 100 achamountpercent 

		
	from vw_TargetItemsQtyView v
	inner join ar_customersclasses cc on cc.id = v.classid
	inner join sy_lookup lu on lu.id = v.sizeid
	inner join sy_areas area on area.id = v.areaid
	inner join inv_itemscategories cat on cat.id = v.itemcategory_id
	inner join inv_itemsbrands brand on brand.id = v.itembrand_id
	left join temp_actualsales acts On acts.classid = v.classid and acts.sizeid = v.sizeid  and acts.Mm = v.mm and acts.areaid = v.areaid and v.itemid = acts.itemid

	
	LEFT JOIN LATERAL 
	(Select price from  inv_itemspriceslists ipl where  ipl.item_id= v.itemid and ipl.pricelevel_id = cc.pricelevel_id and ipl.itemuom_id =v.itemuomid limit 1) AS firstprc ON true

	where area.code  like pareacode || '%'
	--and itemcode Like pitemcode || '%'
	and cc.code like pchannelcode || '%'
	and lu.code like psizecode || '%'
	and cat.code like pcatcode || '%'
	and brand.code like pbrandcode || '%'
	and ((v.mm = pmonth and pmonth != 0 )	or 	pmonth = 0)

	group by 
		area.engname  ,area.arbname 
-- 		,cc.engname  ,cc.arbname  
-- 		,lu.engname ,lu.arbname 
-- 		,cat.engname  ,cat.arbname  
-- 		,brand.engname  ,brand.arbname 
-- 		,price		
		;

DROP TABLE IF EXISTS temp_actualsales ;

end;
$$;


