--
-- Name: sy_generateyearsperiods(integer); Type: PROCEDURE; Schema: public; Owner: postgres
--

CREATE PROCEDURE public.sy_generateyearsperiods(year integer)
    LANGUAGE plpgsql
    AS $$
Declare  
	Cur_BeginDay  int
  ;Cur_EndDay		   int
  ;Cur_BeginMonth	   int
  ;Cur_EndMonth	   int
  ;Cur_LeapBeginDay   int
  ;Cur_LeapEndDay	   int
  ;Cur_LeapBeginMonth  int
  ;Cur_LeapEndMonth   int
  ;Cur_IncrementYear  int
  ;Cur_PeriodType	   int
  ;Cur_PeriodRank	   int;

Declare VarCode		  varchar(20)
	;varFromDate	  varchar(20)
	;varToDate		varchar(20);
	VarName		  varchar(50);
	vdate		varchar(20);
declare
   n int:= 12;
   counter int := 0 ; 

Declare FiscalYearID	  int ;
declare myrec record;
begin

	Insert into sy_FiscalYears (code , arbName , engName)
	Select Cast(Year As varchar(4)) As Code ,Cast(Year As varchar(4)) ArbName , Cast(Year As varchar(4)) As EngName   returning id into FiscalYearID;

	loop 
		exit when counter = n  ;
		counter := counter + 1  ;
		VarCode		 = cast(Year as varchar) || cast(counter as varchar) ;
		vdate = cast(Year as varchar)  || '-' || cast(counter as varchar) || '-01';

		VarName = TO_CHAR(cast(vdate as date), 'Month') AS "Month"	;

		vdate= cast(Year as varchar(10)) || '-' || cast(counter as varchar(1)) || '-' || '01' ;
		varFromDate = cast(Year as varchar(10)) || '-' || cast(counter as varchar(3)) || '-' || '01' ;

		varToDate = ((vdate::date + interval '1 month')::date - interval '1 day')	;	

		RAISE notice '%' ,FiscalYearID ;
		
		Insert into sy_FiscalYearsPeriods (FiscalYear_ID, Code  ,EngName , ArbName ,FromDate ,ToDate,Rank  )	
		Select 	FiscalYearID  , VarCode As Code , VarName As EngName , VarName As ArbName , cast(varFromDate as date), cast(varToDate as date) , Cur_PeriodRank ;
		RAISE notice '%' ,FiscalYearID ;
		
	end loop;

	insert into sy_fiscalyearsperiodsmodules(fiscalyearperiod_ID,module_id, opendate)
	Select  fyp.id,m.id  , current_date from sy_modules m , sy_fiscalyearsperiods fyp 
	where fyp.id  not in (Select fiscalyearperiod_ID from sy_fiscalyearsperiodsmodules);

end;
$$;


ALTER PROCEDURE public.sy_generateyearsperiods(year integer) OWNER TO postgres;

--
-- Name: sy_getfiscalyearperiodid(date, character varying); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.sy_getfiscalyearperiodid(jourdate date, modulecode character varying) RETURNS integer
    LANGUAGE plpgsql
    AS $$
Declare myrec int;

Begin
	if Exists(

			Select FYP.ID  FiscalYearPeriodID
			from sy_FiscalYearsPeriodsModules  FYPM
			Inner join sy_FiscalYearsPeriods FYP on FYPM.FiscalYearPeriod_ID = FYP.ID
			inner join sy_modules m on m.id = FYPM.Module_ID
			Where  Lower(m.code) = lower(ModuleCode)
			And OpenDate is not null And CloseDate Is null  
			And FromDate <= JourDate And ToDate >= JourDate
		
	) then
	Begin
			myrec=(Select FYP.ID  FiscalYearPeriodID  
			from sy_FiscalYearsPeriodsModules  FYPM
			Inner join sy_FiscalYearsPeriods FYP on FYPM.FiscalYearPeriod_ID = FYP.ID
			inner join sy_modules m on m.id = FYPM.Module_ID
			Where  Lower(m.code) = lower(ModuleCode)
			And OpenDate is not null And CloseDate Is null  
			And FromDate <= JourDate And ToDate >= JourDate limit 1 );

	End;
	Else
	Begin
		myrec= 0;
		--Select 0 FiscalYearPeriodID into myrec ;
		
	end;
	end if;
	Return myrec;
	
end;
$$;


ALTER FUNCTION public.sy_getfiscalyearperiodid(jourdate date, modulecode character varying) OWNER TO postgres;

