-- Name: targetdashboardsource(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.targetdashboardsource() RETURNS TABLE(t_areaengname character varying, t_areaarbname character varying, t_sizeengname character varying, t_sizearbname character varying, t_itmcatengname character varying, t_itmcatarbname character varying, t_cclsengname character varying, t_cclsarbname character varying, t_brandengname character varying, t_brandarbname character varying, t_tarqty double precision, t_taramount double precision, t_actqty numeric, t_actamount numeric, t_mm integer, t_classcount bigint, t_sizecount bigint, t_areacount bigint, t_achqtypercent double precision, t_achamountpercent double precision)
    LANGUAGE plpgsql
    AS $$
declare myrec	record;

	BEGIN

create temporary table temp_keyscount as

Select  'class'  counttype,  customerclass_id  , count(id) classCount
from ar_customers c
group by customerclass_id

union all
Select 'size'  counttype,accountsize_id  , count(id) SizeCount
from ar_customers c
group by accountsize_id

union all

Select 'area'  counttype,area_id  , count(c.id) AreaCount
from ar_customers c
Inner Join ar_customersaddresses cad ON cad.customer_id = c.id 
Inner Join ar_customersclasses ccls ON ccls.id =  c.customerclass_id 
inner join sy_cities cit on cit.id = cad.city_id	
group by area_id;

CREATE TEMP TABLE temp_actualsales AS

Select  
	Sum(linetotal) TotalActAmount
	,count(o.id) noofinvoice  
	,EXTRACT(month FROM operationdate) Mm 
	,cit.area_id areaid
	,lu.id sizeid
	,ccls.id classid
	,invloc.id invlocid
	,sum(baseequivalentquantity) ActQty
	,i.id itemid
from inv_operations o 
inner join inv_operationsline ol On o.id = ol.operation_id
inner Join inv_operationsTypes ot on ot.id = o.operationtype_id
inner join ar_customers c on c.id = o.customer_id
Inner Join ar_customersaddresses cad ON cad.customer_id = c.id 
Inner Join ar_customersclasses ccls ON ccls.id =  c.customerclass_id 
inner join sy_cities cit on cit.id = cad.city_id	
inner join sy_lookup lu on lu.id = c.accountsize_id
inner join sy_lookup lukind on lukind.id = ot.operationkind_id
inner join sy_lookup lustatus on lustatus.id = o.status_id
inner join inv_inventorieslocations invloc on invloc.id = o.invlocation_id
inner join inv_items i on i.id = ol.item_id
where lukind.remarks = 'SALES'
and c.allowtarget = true
and lustatus.keyid = 10004
group by 
	EXTRACT(month FROM operationdate) 
	,cit.area_id 
	,lu.id 
	,ccls.id 
	,invloc.id 
	,i.id
	;

create temporary table temp_result as

Select 
		area.engname areaengname ,area.arbname areaarbname 
		,lu.engname sizeengname ,lu.arbname sizearbname 
		,cat.engname catengname ,cat.arbname catarbname 
		,cc.engname classengname ,cc.arbname classarbname 
		,brand.engname brandengname ,brand.arbname brandarbname 

		,sum(qty) qty
		,Sum(price * qty )Amount
		,sum(acts.actqty /baseunitfactor) actqty , sum(acts.TotalActAmount) TotalActAmount

		,v.mm
		,classCount
		,sizeCount
		,areaCount
		, sum( actqty/baseunitfactor) / case when sum(qty ) <> 0 then sum(qty ) * 100 else 1 end     achqtypercent 

		,sum( TotalActAmount )/ case when sum( price * qty ) <> 0 then   sum( price * qty )  * 100 else 1 end achamountpercent 

		
	from vw_TargetItemsQtyView v
	inner join ar_customersclasses cc on cc.id = v.classid
	inner join sy_lookup lu on lu.id = v.sizeid
	inner join sy_areas area on area.id = v.areaid
	inner join inv_itemscategories cat on cat.id = v.itemcategory_id
	inner join inv_itemsbrands brand on brand.id = v.itembrand_id
	left join temp_actualsales acts On acts.classid = v.classid and acts.sizeid = v.sizeid  and acts.Mm = v.mm and acts.areaid = v.areaid and v.itemid = acts.itemid

	LEFT JOIN LATERAL 
	(Select   classCount from temp_keyscount cls where cls.counttype = 'class' AND  customerclass_id = cc.id limit 1) AS keycount ON true
	
	LEFT JOIN LATERAL 
	(Select  classcount sizeCount from temp_keyscount cls where cls.counttype = 'size' AND  customerclass_id = lu.id limit 1) AS keycount1 ON true

	LEFT JOIN LATERAL 
	(Select  classcount areaCount from temp_keyscount cls where cls.counttype = 'area' AND  customerclass_id = area.id limit 1) AS keycount2 ON true

 	 
	
	LEFT JOIN LATERAL 
	(Select price from  inv_itemspriceslists ipl where  ipl.item_id= v.itemid and ipl.pricelevel_id = cc.pricelevel_id and ipl.itemuom_id =v.itemuomid limit 1) AS firstprc ON true

	group by 
		cc.engname  ,cc.arbname  
		,lu.engname ,lu.arbname 
		,area.engname  ,area.arbname 
		,cat.engname  ,cat.arbname  
		,brand.engname  ,brand.arbname 
		,v.mm
		,classCount		
		,sizeCount
		,areaCount
		,price		
		;

return query 

Select 
		 areaengname , areaarbname 
		,sizeengname , sizearbname 
		,catengname , catarbname 
		,classengname , classarbname 
		, brandengname , brandarbname 

		,sum(qty) qty
		,Sum(Amount )Amount
		,sum(actqty) , sum(TotalActAmount) TotalActAmount

		,mm
		,classCount
		,sizeCount
		,areaCount
		, sum(  actqty / case when qty <> 0 then qty else 1 end  ) * 100    achqtypercent 

		,sum( TotalActAmount )/ case when sum( Amount ) <> 0 then sum( Amount )* 100  else 1 end achamountpercent 

		from temp_result
		group by 
				 areaengname , areaarbname 
		,sizeengname , sizearbname 
		,catengname , catarbname 
		,classengname , classarbname 
		, brandengname , brandarbname 
		,mm
		,classCount
		,sizeCount
		,areaCount
		;

DROP TABLE IF EXISTS temp_keyscount;
DROP TABLE IF EXISTS temp_actualsales ;
DROP TABLE IF EXISTS temp_result ;

end;
$$;


