--
-- Name: inv_viewitemsseasonality; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.inv_viewitemsseasonality AS
 SELECT itmsea.item_id,
    itmsea.area_id,
    itmsea.quotapercent,
    itmsea.m1 AS mpercent,
    1 AS mm
   FROM public.inv_itemsseasonality itmsea
UNION ALL
 SELECT itmsea.item_id,
    itmsea.area_id,
    itmsea.quotapercent,
    itmsea.m2 AS mpercent,
    2 AS mm
   FROM public.inv_itemsseasonality itmsea
UNION ALL
 SELECT itmsea.item_id,
    itmsea.area_id,
    itmsea.quotapercent,
    itmsea.m3 AS mpercent,
    3 AS mm
   FROM public.inv_itemsseasonality itmsea
UNION ALL
 SELECT itmsea.item_id,
    itmsea.area_id,
    itmsea.quotapercent,
    itmsea.m4 AS mpercent,
    4 AS mm
   FROM public.inv_itemsseasonality itmsea
UNION ALL
 SELECT itmsea.item_id,
    itmsea.area_id,
    itmsea.quotapercent,
    itmsea.m5 AS mpercent,
    5 AS mm
   FROM public.inv_itemsseasonality itmsea
UNION ALL
 SELECT itmsea.item_id,
    itmsea.area_id,
    itmsea.quotapercent,
    itmsea.m6 AS mpercent,
    6 AS mm
   FROM public.inv_itemsseasonality itmsea
UNION ALL
 SELECT itmsea.item_id,
    itmsea.area_id,
    itmsea.quotapercent,
    itmsea.m7 AS mpercent,
    7 AS mm
   FROM public.inv_itemsseasonality itmsea
UNION ALL
 SELECT itmsea.item_id,
    itmsea.area_id,
    itmsea.quotapercent,
    itmsea.m8 AS mpercent,
    8 AS mm
   FROM public.inv_itemsseasonality itmsea
UNION ALL
 SELECT itmsea.item_id,
    itmsea.area_id,
    itmsea.quotapercent,
    itmsea.m9 AS mpercent,
    9 AS mm
   FROM public.inv_itemsseasonality itmsea
UNION ALL
 SELECT itmsea.item_id,
    itmsea.area_id,
    itmsea.quotapercent,
    itmsea.m10 AS mpercent,
    10 AS mm
   FROM public.inv_itemsseasonality itmsea
UNION ALL
 SELECT itmsea.item_id,
    itmsea.area_id,
    itmsea.quotapercent,
    itmsea.m11 AS mpercent,
    11 AS mm
   FROM public.inv_itemsseasonality itmsea
UNION ALL
 SELECT itmsea.item_id,
    itmsea.area_id,
    itmsea.quotapercent,
    itmsea.m12 AS mpercent,
    12 AS mm
   FROM public.inv_itemsseasonality itmsea;


ALTER TABLE public.inv_viewitemsseasonality OWNER TO postgres;

