--
-- Name: vw_customersinfo; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vw_customersinfo AS
SELECT
    NULL::integer AS sizeid,
    NULL::integer AS sizekeyid,
    NULL::character varying(20) AS sizecode,
    NULL::character varying(100) AS sizeengname,
    NULL::character varying(100) AS sizearbname,
    NULL::integer AS areaid,
    NULL::character varying(20) AS areacode,
    NULL::character varying(20) AS areaengname,
    NULL::character varying(20) AS areaarbname,
    NULL::integer AS custid,
    NULL::character varying(50) AS custcode,
    NULL::character varying(100) AS custengname,
    NULL::character varying(100) AS custarbname,
    NULL::integer AS classid,
    NULL::character varying(50) AS cclscode,
    NULL::character varying(50) AS cclsengname,
    NULL::character varying(50) AS cclsarbname,
    NULL::integer AS pricelevelid,
    NULL::public.ar_customers AS c,
    NULL::bigint AS custcount,
    NULL::integer AS salesperson_id;


ALTER TABLE public.vw_customersinfo OWNER TO postgres;

--
-- Name: vw_targetitemskeys; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vw_targetitemskeys AS
 SELECT lu.id AS sizeid,
    lu.keyid AS sizekeyid,
    lu.code AS sizecode,
    lu.engname AS sizeengname,
    lu.arbname AS sizearbname,
    area.id AS areaid,
    area.code AS areacode,
    area.code AS areaengname,
    area.code AS areaarbname,
    ccls.id AS classid,
    ccls.code AS cclscode,
    ccls.code AS cclsengname,
    ccls.code AS cclsarbname,
    ccls.pricelevel_id AS pricelevelid,
    count(c.id) AS custcount
   FROM (((((public.ar_customers c
     JOIN public.ar_customersaddresses cad ON ((cad.customer_id = c.id)))
     JOIN public.ar_customersclasses ccls ON ((ccls.id = c.customerclass_id)))
     JOIN public.sy_cities cit ON ((cit.id = cad.city_id)))
     JOIN public.sy_lookup lu ON ((lu.id = c.accountsize_id)))
     JOIN public.sy_areas area ON ((area.id = cit.area_id)))
  WHERE (c.allowtarget = true)
  GROUP BY lu.id, lu.keyid, lu.code, lu.engname, lu.arbname, area.id, area.code, ccls.id, ccls.code, ccls.pricelevel_id;


ALTER TABLE public.vw_targetitemskeys OWNER TO postgres;

--
-- Name: vw_targetitemsqtyview; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vw_targetitemsqtyview AS
 SELECT i.id AS itemid,
    tb.itemuom_id AS itemuomid,
    iuom.baseunitfactor,
    itmsea.mm,
    itmsea.area_id AS areaid,
    tbb.channel_id AS classid,
    tb.yearly_qty,
    tbb.contribution,
    itmsea.mpercent,
    itmsea.quotapercent,
    tbb.small,
    tbb.medium,
    tbb.large,
    sizes.sizeid,
    sum((((((tb.yearly_qty)::double precision * ((tbb.contribution)::double precision / (100)::double precision)) * ((itmsea.quotapercent)::double precision / (100)::double precision)) * ((tbb.small)::double precision / (100)::double precision)) * ((itmsea.mpercent)::double precision / (100)::double precision))) AS qty,
    i.code AS itemcode,
    i.engname AS itemengname,
    i.arbname AS itemarbname,
    i.itemcategory_id,
    i.itembrand_id
   FROM (((((public.inv_targetbuildingblocksitems tbb
     JOIN public.inv_targetbuildingblocks tb ON ((tb.id = tbb.targetbuildingblocks_id)))
     JOIN public.inv_items i ON ((i.id = tb.item_id)))
     JOIN public.inv_itemsuom iuom ON ((iuom.id = tb.itemuom_id)))
     JOIN public.inv_viewitemsseasonality itmsea ON ((itmsea.item_id = i.id)))
     LEFT JOIN LATERAL ( SELECT sy_lookup.id AS sizeid
           FROM public.sy_lookup
          WHERE (sy_lookup.keyid = 2102)
         LIMIT 1) sizes ON (true))
  GROUP BY i.id, tb.itemuom_id, iuom.baseunitfactor, itmsea.area_id, tbb.channel_id, itmsea.mm, i.code, tb.yearly_qty, tbb.contribution, itmsea.mpercent, itmsea.quotapercent, tbb.small, tbb.medium, tbb.large, sizes.sizeid, i.engname, i.arbname, i.itemcategory_id, i.itembrand_id
UNION ALL
 SELECT i.id AS itemid,
    tb.itemuom_id AS itemuomid,
    iuom.baseunitfactor,
    itmsea.mm,
    itmsea.area_id AS areaid,
    tbb.channel_id AS classid,
    tb.yearly_qty,
    tbb.contribution,
    itmsea.mpercent,
    itmsea.quotapercent,
    tbb.small,
    tbb.medium,
    tbb.large,
    sizes.sizeid,
    sum((((((tb.yearly_qty)::double precision * ((tbb.contribution)::double precision / (100)::double precision)) * ((itmsea.quotapercent)::double precision / (100)::double precision)) * ((tbb.medium)::double precision / (100)::double precision)) * ((itmsea.mpercent)::double precision / (100)::double precision))) AS qty,
    i.code AS itemcode,
    i.engname AS itemengname,
    i.arbname AS itemarbname,
    i.itemcategory_id,
    i.itembrand_id
   FROM (((((public.inv_targetbuildingblocksitems tbb
     JOIN public.inv_targetbuildingblocks tb ON ((tb.id = tbb.targetbuildingblocks_id)))
     JOIN public.inv_items i ON ((i.id = tb.item_id)))
     JOIN public.inv_itemsuom iuom ON ((iuom.id = tb.itemuom_id)))
     JOIN public.inv_viewitemsseasonality itmsea ON ((itmsea.item_id = i.id)))
     LEFT JOIN LATERAL ( SELECT sy_lookup.id AS sizeid
           FROM public.sy_lookup
          WHERE (sy_lookup.keyid = 2103)
         LIMIT 1) sizes ON (true))
  GROUP BY i.id, tb.itemuom_id, iuom.baseunitfactor, itmsea.area_id, tbb.channel_id, itmsea.mm, i.code, tb.yearly_qty, tbb.contribution, itmsea.mpercent, itmsea.quotapercent, tbb.small, tbb.medium, tbb.large, sizes.sizeid, i.engname, i.arbname, i.itemcategory_id, i.itembrand_id
UNION ALL
 SELECT i.id AS itemid,
    tb.itemuom_id AS itemuomid,
    iuom.baseunitfactor,
    itmsea.mm,
    itmsea.area_id AS areaid,
    tbb.channel_id AS classid,
    tb.yearly_qty,
    tbb.contribution,
    itmsea.mpercent,
    itmsea.quotapercent,
    tbb.small,
    tbb.medium,
    tbb.large,
    sizes.sizeid,
    sum((((((tb.yearly_qty)::double precision * ((tbb.contribution)::double precision / (100)::double precision)) * ((itmsea.quotapercent)::double precision / (100)::double precision)) * ((tbb.large)::double precision / (100)::double precision)) * ((itmsea.mpercent)::double precision / (100)::double precision))) AS qty,
    i.code AS itemcode,
    i.engname AS itemengname,
    i.arbname AS itemarbname,
    i.itemcategory_id,
    i.itembrand_id
   FROM (((((public.inv_targetbuildingblocksitems tbb
     JOIN public.inv_targetbuildingblocks tb ON ((tb.id = tbb.targetbuildingblocks_id)))
     JOIN public.inv_items i ON ((i.id = tb.item_id)))
     JOIN public.inv_itemsuom iuom ON ((iuom.id = tb.itemuom_id)))
     JOIN public.inv_viewitemsseasonality itmsea ON ((itmsea.item_id = i.id)))
     LEFT JOIN LATERAL ( SELECT sy_lookup.id AS sizeid
           FROM public.sy_lookup
          WHERE (sy_lookup.keyid = 2104)
         LIMIT 1) sizes ON (true))
  GROUP BY i.id, tb.itemuom_id, iuom.baseunitfactor, itmsea.area_id, tbb.channel_id, itmsea.mm, i.code, tb.yearly_qty, tbb.contribution, itmsea.mpercent, itmsea.quotapercent, tbb.small, tbb.medium, tbb.large, sizes.sizeid, i.engname, i.arbname, i.itemcategory_id, i.itembrand_id;


ALTER TABLE public.vw_targetitemsqtyview OWNER TO postgres;

