--
-- Name: vw_customersinfo _RETURN; Type: RULE; Schema: public; Owner: postgres
--

CREATE OR REPLACE VIEW public.vw_customersinfo AS
 SELECT lu.id AS sizeid,
    lu.keyid AS sizekeyid,
    lu.code AS sizecode,
    lu.engname AS sizeengname,
    lu.arbname AS sizearbname,
    area.id AS areaid,
    area.code AS areacode,
    area.code AS areaengname,
    area.code AS areaarbname,
    c.id AS custid,
    c.code AS custcode,
    c.engname AS custengname,
    c.arbname AS custarbname,
    ccls.id AS classid,
    ccls.code AS cclscode,
    ccls.code AS cclsengname,
    ccls.code AS cclsarbname,
    ccls.pricelevel_id AS pricelevelid,
    c.*::public.ar_customers AS c,
    count(c.id) AS custcount,
    c.salesperson_id
   FROM (((((public.ar_customers c
     JOIN public.ar_customersaddresses cad ON ((cad.customer_id = c.id)))
     JOIN public.ar_customersclasses ccls ON ((ccls.id = c.customerclass_id)))
     JOIN public.sy_cities cit ON ((cit.id = cad.city_id)))
     JOIN public.sy_lookup lu ON ((lu.id = c.accountsize_id)))
     JOIN public.sy_areas area ON ((area.id = cit.area_id)))
  WHERE (c.allowtarget = true)
  GROUP BY lu.id, lu.keyid, lu.code, lu.engname, lu.arbname, area.id, area.code, ccls.id, ccls.code, ccls.pricelevel_id, c.id, c.code, c.engname, c.arbname, c.salesperson_id;


